-- Poems batch 53
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('de260931-f7aa-4f9d-adb8-78cfef3061a5','寄酬高輦推官','齊己','唐','唐诗','tang','','[]','道自閑機長，詩從靜境生。',48,'全唐诗/poet.tang.46000.json','["道自閑機長，詩從靜境生。", "不知春豔盡，但覺雅風清。", "竹膩題幽碧，蕉乾裂脆聲。", "何當九霄客，重疊記無名。"]'),
('f2866b5a-4e07-44e2-87b7-bf9b78cbbd03','逢詩僧','齊己','唐','唐诗','tang','','[]','禪玄無可並，詩妙有何評。',48,'全唐诗/poet.tang.46000.json','["禪玄無可並，詩妙有何評。", "五七字中苦，百千年後清。", "難求方至理，不朽始爲名。", "珍重重相見，忘機話此情。"]'),
('161240b4-f608-4f6f-8815-a25ccfc5d8d3','話道','齊己','唐','唐诗','tang','','[]','大道多大笑，寂寥何以論。',48,'全唐诗/poet.tang.46000.json','["大道多大笑，寂寥何以論。", "霜楓翻落葉，水鳥啄閑門。", "服藥還傷性，求珠亦損魂。", "無端鑿混沌，一死不還源。"]'),
('270578b5-9787-4551-acd8-48459a209b6e','謝歐陽侍郎寄示新集','齊己','唐','唐诗','tang','','[]','宮錦三十段，金梭新織來。',48,'全唐诗/poet.tang.46000.json','["宮錦三十段，金梭新織來。", "殷勤謝君子，迢遞寄寒灰。", "鸑鷟對鼓舞，神仙雙裴回。", "誰當巧裁製，披去升瑤臺。"]'),
('b23c08ea-3ba7-41b7-95a5-bd2e4af5a6da','西墅新居','齊己','唐','唐诗','tang','','[]','漸漸見苔青，疎疎遍地生。',48,'全唐诗/poet.tang.46000.json','["漸漸見苔青，疎疎遍地生。", "閑穿藤屐起，亂踏石階行。", "野鳥啼幽樹，名僧笑此情。", "殘陽竹陰裏，老圃打門聲。"]'),
('c0c7c036-8922-4dc0-8fdb-2aa6126dd21f','酬孫魴','齊己','唐','唐诗','tang','','[]','幽人還愛雲，才子已從軍。',48,'全唐诗/poet.tang.46000.json','["幽人還愛雲，才子已從軍。", "可信鴛鴻侶，更思麋鹿羣。", "新題雖有寄，舊論竟難聞。", "知己今如此，編聯悉欲焚。"]'),
('d265deac-e6b3-4a30-b737-ab7baf51545a','掃地','齊己','唐','唐诗','tang','','[]','日日掃復灑，不容纖物侵。',48,'全唐诗/poet.tang.46000.json','["日日掃復灑，不容纖物侵。", "敢望來客口，道似主人心。", "蟻過光中少，苔依潤處深。", "門前亦如此，一徑入疎林。"]'),
('530d9f84-6b32-4f15-a952-f91aa57a051f','書匡山隱者壁','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','紅霞青壁底，石室薜蘿垂。',48,'全唐诗/poet.tang.46000.json','["紅霞青壁底，石室薜蘿垂。", "應有迷仙者，曾逢採藥時。", "桃花饒兩頰，松葉淺長髭。", "直是來城市，何人識得伊。"]'),
('b749368c-dab2-4163-9542-93673456a69d','送乾康禪師入山過夏','齊己','唐','唐诗','tang','','[]','由來喧滑境，難駐寂寥蹤。',48,'全唐诗/poet.tang.46000.json','["由來喧滑境，難駐寂寥蹤。", "逼夏搖孤錫，離城入亂峯。", "雲門應近寺，石路或穿松。", "知在棲禪外，題詩寄北宗。"]'),
('9326b06d-a918-491e-8b3a-e7080b3a5e10','野鴨','齊己','唐','唐诗','tang','','[]','野鴨殊家鴨，離羣忽遠飛。',48,'全唐诗/poet.tang.46000.json','["野鴨殊家鴨，離羣忽遠飛。", "長生緣甚瘦，近死爲傷肥。", "江海游空闊，池塘啄細微。", "紅蘭白蘋渚，春暖刷毛衣。"]'),
('153b30b7-5328-4623-b529-aaa8b7ab3cfa','傷秋','齊己','唐','唐诗','tang','','[]','旦暮餘生在，肌膚十分無。',48,'全唐诗/poet.tang.46000.json','["旦暮餘生在，肌膚十分無。", "眠寒半榻朽，立月一株枯。", "夢已隨雙樹，詩猶却萬夫。", "名山未歸得，可惜死江湖。"]'),
('e5208479-98cb-42b1-b828-a4d6db85c333','懷東湖寺','齊己','唐','唐诗','tang','','[]','鐵柱東湖岸，寺高人亦閑。',48,'全唐诗/poet.tang.46000.json','["鐵柱東湖岸，寺高人亦閑。", "往年曾每日，來此看西山。", "竹徑青苔合，茶軒白鳥還。", "而今在天末，欲去已衰顏。"]'),
('724b3749-b445-4990-a5da-8adc515beee5','寄峴山願公三首 一','齊己','唐','唐诗','tang','','[]','形影更誰親，應懷漆道人。',48,'全唐诗/poet.tang.46000.json','["形影更誰親，應懷漆道人。", "片言酬鑿齒，半偈伏姚秦。", "榛莽池經燒，蒿萊寺過春。", "心期重西去，一共弔遺塵。"]'),
('77ac0ebf-37b4-4625-a2d1-8cbba8bc5dff','寄峴山願公三首 二','齊己','唐','唐诗','tang','','[]','相思恨相遠，至理那時何。',48,'全唐诗/poet.tang.46000.json','["相思恨相遠，至理那時何。", "道笑忘言甚，詩嫌背俗多。", "青苔閑閣閉，白日斷人過。", "獨上西樓望，荆門千萬坡。"]'),
('0d0e3f32-de7a-4ae3-a0e9-5023dde274d0','寄峴山願公三首 三','齊己','唐','唐诗','tang','','[]','彼此無消息，所思江漢遙。',48,'全唐诗/poet.tang.46000.json','["彼此無消息，所思江漢遙。", "轉聞多患難，甚說遠相招。", "老至何悲歎，生知便寂寥。", "終期踏松影，攜手虎溪橋。"]'),
('82a41183-1339-4859-809f-27f71b1dac50','清夜作','齊己','唐','唐诗','tang','','[]','不惜白日短，乍容清夜長。',48,'全唐诗/poet.tang.46000.json','["不惜白日短，乍容清夜長。", "坐聞風露滴，吟覺骨毛涼。", "興寢無諸病，空閑有一牀。", "天明振衣起，苔砌落花香。"]'),
('bbb45e7c-cac2-49ae-b076-613ea662d1e1','贈白處士','齊己','唐','唐诗','tang','','[]','莘野居何定，浮生知是誰。',50,'全唐诗/poet.tang.46000.json','["莘野居何定，浮生知是誰。", "衣衫同[野]叟，指趣似禪師。", "白髮應無也，丹砂久服之。", "仍聞創行計，春暖向峨嵋。"]'),
('1716432f-5f0f-44f6-a78a-f1de0cfede4a','崔秀才宿話','齊己','唐','唐诗','tang','','[]','事轉聞多事，心休話苦心。',48,'全唐诗/poet.tang.46000.json','["事轉聞多事，心休話苦心。", "相留明月寺，共憶白雲岑。", "蘚壁殘蟲韻，霜軒倒竹陰。", "開門又言別，誰竟慰塵襟。"]'),
('98268253-d4c4-486a-84fa-901435b22d92','懷天台華頂僧','齊己','唐','唐诗','tang','','[]','華頂危臨海，丹霞裏石橋。',48,'全唐诗/poet.tang.46000.json','["華頂危臨海，丹霞裏石橋。", "曾從國清寺，上看月明潮。", "好鳥親香火，狂泉噴泬寥。", "欲歸師智者，頭白路迢迢。"]'),
('2d6b176d-c181-4c0d-aa6f-78bf7c4ac843','送人赴官','齊己','唐','唐诗','tang','','[]','年少作初官，還如行路難。',48,'全唐诗/poet.tang.46000.json','["年少作初官，還如行路難。", "兵荒經邑里，風俗久凋殘。", "照硯花光淡，漂書柳絮乾。", "聊應充侍膳，薄俸繼朝餐。"]'),
('70a7ea31-5ea5-4161-92b0-ab92e4856371','水鶴','齊己','唐','唐诗','tang','','[]','鴛鴦與鸂鶒，相狎豈慙君。',50,'全唐诗/poet.tang.46000.json','["鴛鴦與鸂鶒，相狎豈慙君。", "比雪還勝雪，同羣亦出羣。", "靜巢孤島月，寒夢九臯雲。", "歸路分明[過]，飛鳴即可聞。"]'),
('d1b1d440-8312-40c3-9a01-4d2bcf619b62','湘中感懷','齊己','唐','唐诗','tang','','[]','漁翁那會我，傲兀葦邊行。',48,'全唐诗/poet.tang.46000.json','["漁翁那會我，傲兀葦邊行。", "亂世難逸跡，乘流擬濯纓。", "江花紅細碎，沙鳥白分明。", "向夕題詩處，春風斑竹聲。"]'),
('9d02f226-cb75-46f4-be46-77408672fb22','九日逢虛中虛受','齊己','唐','唐诗','tang','','[]','楚后萍臺下，相逢九日時。',48,'全唐诗/poet.tang.46000.json','["楚后萍臺下，相逢九日時。", "干戈人事地，荒廢菊花籬。", "我已多衰病，君猶盡黑髭。", "皇天安罪得，解語便吟詩。"]'),
('02cf9a3d-544c-4d1e-b135-e2e9fa42046d','贈李明府','齊己','唐','唐诗','tang','','[]','名家宰名邑，將謂屈鋒鋩。',48,'全唐诗/poet.tang.46000.json','["名家宰名邑，將謂屈鋒鋩。", "直是難蘇俗，能消不下堂。", "冰痕生硯水，柳影透琴牀。", "何必稱瀟灑，獨爲詩酒狂。"]'),
('8a2fae7d-feaa-4012-a1a7-02be3ce443b7','暮春久雨作','齊己','唐','唐诗','tang','','[]','積雨向春陰，冥冥獨院深。',48,'全唐诗/poet.tang.46000.json','["積雨向春陰，冥冥獨院深。", "已無花落地，空有竹藏禽。", "簷溜聲何暴，隣僧影亦沈。", "誰知力耕者，桑麥最關心。"]'),
('cbd575ef-45c1-48a8-8a50-0b1c7f3b3fad','渚宮莫問詩一十五首 一','齊己','唐','唐诗','tang','','[]','莫問疎人事，王侯已任伊。',48,'全唐诗/poet.tang.46000.json','["莫問疎人事，王侯已任伊。", "不妨隨野性，還似在山時。", "靜入無聲樂，狂拋正律詩。", "自爲仍自愛，清淨裏尋思。"]'),
('79369fb4-5b90-487b-9201-560489445857','渚宮莫問詩一十五首 二','齊己','唐','唐诗','tang','','[]','莫問伊嵇嬾，流年已付他。',48,'全唐诗/poet.tang.46000.json','["莫問伊嵇嬾，流年已付他。", "話通時事少，詩着野題多。", "夢外春桃李，心中舊薜蘿。", "浮生此不悟，剃髮竟如何。"]'),
('f07f4d36-2258-491d-a742-5a10e39b60fa','渚宮莫問詩一十五首 三','齊己','唐','唐诗','tang','','[]','莫問休行脚，南方已徧尋。',48,'全唐诗/poet.tang.46000.json','["莫問休行脚，南方已徧尋。", "了應須自了，心不是他心。", "赤水珠何覓，寒山偈莫吟。", "誰同論此理，杜口少知音。"]'),
('351a7ea7-a637-4ab1-9fde-5a0357637284','渚宮莫問詩一十五首 四','齊己','唐','唐诗','tang','','[]','莫問孱愚格，天應只與閑。',48,'全唐诗/poet.tang.46000.json','["莫問孱愚格，天應只與閑。", "合居長樹下，那稱衆人間。", "跡絕爲真隱，機忘是大還。", "終當學支遁，買取箇青山。"]'),
('884486ca-3578-4989-a855-15db06a7d1af','渚宮莫問詩一十五首 五','齊己','唐','唐诗','tang','','[]','莫問無求意，浮雲喻可知。',48,'全唐诗/poet.tang.46000.json','["莫問無求意，浮雲喻可知。", "滿盈如不戒，倚伏更何疑。", "樂矣賢顏子，窮乎聖仲尼。", "已過知命歲，休把運行推。"]'),
('ad8ebf52-1763-4a4a-80f7-387ba6e880c6','渚宮莫問詩一十五首 六','齊己','唐','唐诗','tang','','[]','莫問閑行趣，春風野水涯。',48,'全唐诗/poet.tang.46000.json','["莫問閑行趣，春風野水涯。", "千門無謝女，兩岸有楊花。", "好鶴曾爲客，真龍或作蛇。", "躊躕自迴首，日脚背樓斜。"]'),
('defe26ac-1f0e-4f1f-9d19-dd159551c565','渚宮莫問詩一十五首 七','齊己','唐','唐诗','tang','','[]','莫問真消息，中心只自知。',48,'全唐诗/poet.tang.46000.json','["莫問真消息，中心只自知。", "清風含笑詠，明月混希夷。", "壞衲涼天擁，玄文靜夜披。", "善哉溫伯子，言望至公知。"]'),
('364eedb9-6400-48c8-9fb2-d790c0c5dd5e','渚宮莫問詩一十五首 八','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','莫問休持鉢，從貧乞已疎。',48,'全唐诗/poet.tang.46000.json','["莫問休持鉢，從貧乞已疎。", "侯門叨月俸，齋食剩年儲。", "簪履三千外，形骸六十餘。", "舊峯呵練若，松徑接匡廬。"]'),
('d216a40c-8f66-42a2-acae-365af2704cbd','渚宮莫問詩一十五首 九','齊己','唐','唐诗','tang','','[]','莫問依劉跡，金臺又度秋。',48,'全唐诗/poet.tang.46000.json','["莫問依劉跡，金臺又度秋。", "威儀非上客，譚笑愧諸侯。", "禮許無拘檢，詩推異輩流。", "東林未歸得，搖落楚江頭。"]'),
('a5f3bc27-1526-4a1e-9cf4-5639794f0f11','渚宮莫問詩一十五首 十','齊己','唐','唐诗','tang','','[]','莫問無機性，甘名百鈍人。',48,'全唐诗/poet.tang.46000.json','["莫問無機性，甘名百鈍人。", "一牀鋪冷落，長日臥精神。", "分已疎知舊，詩還得意新。", "多才碧雲客，時或此相親。"]'),
('dbb7b498-06c0-479b-9377-917d8aacb206','渚宮莫問詩一十五首 十一','齊己','唐','唐诗','tang','','[]','莫問關門意，從來寡往還。',48,'全唐诗/poet.tang.46000.json','["莫問關門意，從來寡往還。", "道應歸淡泊，身合在空閑。", "四面苔圍綠，孤窗雨灑斑。", "夢尋何處去，秋色水邊山。"]'),
('bcc31b61-df29-4361-98cc-5471b70a4df8','渚宮莫問詩一十五首 十二','齊己','唐','唐诗','tang','','[]','莫問□□□，□□逐性情。',48,'全唐诗/poet.tang.46000.json','["莫問□□□，□□逐性情。", "人間高此道，禪外剩他名。", "夏□松邊坐，秋光水畔行。", "更無時忌諱，容易得題成。"]'),
('513215d9-080a-4f3a-bf74-d58c7638f252','渚宮莫問詩一十五首 十三','齊己','唐','唐诗','tang','','[]','莫問多山興，晴樓獨凭時。',48,'全唐诗/poet.tang.46000.json','["莫問多山興，晴樓獨凭時。", "六年滄海寺，一別白蓮池。", "句早逢名匠，禪曾見祖師。", "冥搜與真性，清外認揚眉。"]'),
('97044e4a-594d-4075-85f3-d40daaa8dd97','渚宮莫問詩一十五首 十四','齊己','唐','唐诗','tang','','[]','莫問衰殘質，流光速可悲。',48,'全唐诗/poet.tang.46000.json','["莫問衰殘質，流光速可悲。", "寸心修未了，長命欲何爲。", "坐臥身多倦，經行骨漸疲。", "分明說此苦，珍重竺乾師。"]'),
('478fe904-bb32-4cba-b050-aa6bbf9f5169','渚宮莫問詩一十五首 十五','齊己','唐','唐诗','tang','','[]','莫問野騰騰，勞形已不能。',48,'全唐诗/poet.tang.46000.json','["莫問野騰騰，勞形已不能。", "慇懃無上士，珍重有名僧。", "坐覺心心默，行思步步冰。", "終歸石房裏，一點夜深燈。"]'),
('34810d96-2252-4ef6-908b-f70f3bd61fd0','荆州新秋病起雜題一十五首 病起見王化','齊己','唐','唐诗','tang','','[]','病起見王化，融融古帝鄉。',48,'全唐诗/poet.tang.46000.json','["病起見王化，融融古帝鄉。", "曉煙凝氣紫，晚色作雲黃。", "四野歌豐稔，千門唱樂康。", "老身仍未死，猶詠好風光。"]'),
('12b31106-ef69-45b3-a015-a3035723bba5','荆州新秋病起雜題一十五首 病起見圖畫','齊己','唐','唐诗','tang','','[]','病起見圖畫，雲門興似饒。',48,'全唐诗/poet.tang.46000.json','["病起見圖畫，雲門興似饒。", "衲衣椶笠重，嵩岳華山遙。", "命在齋猶赴，刀閒髮盡凋。", "秋光漸輕健，欲去倚江橋。"]'),
('eaf5c02b-4774-4671-aa6c-1f074d236802','荆州新秋病起雜題一十五首 病起見苔錢','齊己','唐','唐诗','tang','','[]','病起見苔錢，規模遍地圓。',48,'全唐诗/poet.tang.46000.json','["病起見苔錢，規模遍地圓。", "兒童掃不破，子母自相連。", "潤屋何曾有，緣牆謾可憐。", "虛教作銅臭，空使外人傳。"]'),
('d2593a48-ace3-4479-801e-764674a85a49','荆州新秋病起雜題一十五首 病起見庭竹','齊己','唐','唐诗','tang','','[]','病起見庭竹，君應悲我情。',48,'全唐诗/poet.tang.46000.json','["病起見庭竹，君應悲我情。", "何妨甚消瘦，却稱苦修行。", "每謝侵牀影，時迴傍枕聲。", "秋來漸平復，吟遶骨毛輕。"]'),
('2f7035b2-3976-4cfc-ad82-007a27a2d2c1','荆州新秋病起雜題一十五首 病起見生涯','齊己','唐','唐诗','tang','','[]','病起見生涯，資緣覺甚奢。',48,'全唐诗/poet.tang.46000.json','["病起見生涯，資緣覺甚奢。", "方袍嫌垢弊，律服變光華。", "頗愧同諸俗，何嘗異出家。", "三衣如兩翼，珍重汝寒鴉。"]'),
('ee69bded-a1e8-4cbf-8e90-1d6b386359af','荆州新秋病起雜題一十五首 病起見秋扇','齊己','唐','唐诗','tang','','[]','病起見秋扇，風前悟感傷。',48,'全唐诗/poet.tang.46000.json','["病起見秋扇，風前悟感傷。", "念予當咽絕，得爾致清涼。", "沙鷺如搖影，汀蓮似綻香。", "不同婕妤詠，託意怨君王。"]'),
('0b6856c7-6a47-4ac6-a015-e5384f4094df','荆州新秋病起雜題一十五首 病起見衰葉','齊己','唐','唐诗','tang','','[]','病起見衰葉，飄然似我身。',48,'全唐诗/poet.tang.46000.json','["病起見衰葉，飄然似我身。", "偶乘風有韻，初落地無塵。", "縱得紅霑露，爭如綠帶春。", "因傷此懷抱，聊寄一篇新。"]'),
('02afe8f4-f6c5-4bf1-a20a-68a07e65c022','荆州新秋病起雜題一十五首 病起見庭栢','齊己','唐','唐诗','tang','','[]','病起見庭栢，青青我不任。',48,'全唐诗/poet.tang.46000.json','["病起見庭栢，青青我不任。", "力扶乾瘦骨，勉對歲寒心。", "韻謝疎篁合，根容片石侵。", "衰殘想長壽，時倚就閑吟。"]'),
('ea3e6403-e22f-47aa-93ef-8b9929c134d5','荆州新秋病起雜題一十五首 病起見庭蓮','齊己','唐','唐诗','tang','','[]','病起見庭蓮，風荷已颯然。',48,'全唐诗/poet.tang.46000.json','["病起見庭蓮，風荷已颯然。", "開時聞馥郁，枕上正纏綿。", "本在滄江闊，移來碧沼圓。", "却思香社裏，葉葉漏聲連。"]'),
('7d282653-f873-49a3-91e9-46f2f73abdb9','荆州新秋病起雜題一十五首 病起見庭菊','齊己','唐','唐诗','tang','','[]','病起見庭菊，幾勞栽種工。',48,'全唐诗/poet.tang.46000.json','["病起見庭菊，幾勞栽種工。", "可能經臥疾，相倚自成叢。", "翠萼低含露，金英盡亞風。", "那知予愛爾，不在酒杯中。"]'),
('6bbb6efa-94f3-40db-b461-6791ccad2279','荆州新秋病起雜題一十五首 病起見庭石','齊己','唐','唐诗','tang','','[]','病起見庭石，豈知經夏眠。',48,'全唐诗/poet.tang.46000.json','["病起見庭石，豈知經夏眠。", "不能資藥價，空自作苔錢。", "翠憶藍光底，青思瀑影邊。", "巖僧應笑我，細碎種階前。"]'),
('470fa0fa-3a55-4bc0-814d-7067ceae0fb8','荆州新秋病起雜題一十五首 病起見庭莎','齊己','唐','唐诗','tang','','[]','病起見庭莎，綠階傍竹多。',48,'全唐诗/poet.tang.46000.json','["病起見庭莎，綠階傍竹多。", "遶行猶未得，靜聽復如何。", "蟋蟀幽中響，蟪蛄深處歌。", "不緣田地窄，剩種任婆娑。"]'),
('36add9ff-b52f-4191-a038-be2c16ccdc6e','荆州新秋病起雜題一十五首 病起見苔色','齊己','唐','唐诗','tang','','[]','病起見苔色，凝然陣未枯。',48,'全唐诗/poet.tang.46000.json','["病起見苔色，凝然陣未枯。", "淺深圍柱礎，詰曲遶廊廡。", "碧翠文相間，青黃勢自鋪。", "爲錢虛玷染，畢竟不如無。"]'),
('46d85d40-5315-44c8-b0f6-33afd118bf9c','荆州新秋病起雜題一十五首 病起見秋月','齊己','唐','唐诗','tang','','[]','病起見秋月，正當三五時。',48,'全唐诗/poet.tang.46000.json','["病起見秋月，正當三五時。", "清光應鑒我，幽思更同誰。", "惜坐身猶倦，牽吟氣尚羸。", "明年七十六，約此健相期。"]'),
('7e140d77-9824-4361-a7e1-8b332e939143','荆州新秋病起雜題一十五首 病起見閑雲','齊己','唐','唐诗','tang','','[]','病起見閑雲，空中聚又分。',48,'全唐诗/poet.tang.46000.json','["病起見閑雲，空中聚又分。", "滯留堪笑我，舒卷不如君。", "觸石終無跡，從風或有聞。", "仙山足鸞鳳，歸去自同羣。"]'),
('882f7430-bfcf-4e7f-a585-f8b11f5537aa','夜坐聞雪寄所知','齊己','唐','唐诗','tang','','[]','初宵飛霰急，竹樹灑乾輕。',48,'全唐诗/poet.tang.46000.json','["初宵飛霰急，竹樹灑乾輕。", "不是知音者，難教愛此聲。", "漸凌孤燭白，偏激苦心清。", "堪笑同文友，忘眠坐到明。"]'),
('5fda31cb-fd30-477b-a4a5-8237bab9f5a2','懷洞庭','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','憶過巴陵歲，無人問去留。',48,'全唐诗/poet.tang.46000.json','["憶過巴陵歲，無人問去留。", "中宵滿湖月，獨自在僧樓。", "漁父真閑唱，靈均是謾愁。", "今來欲長往，誰借木蘭舟。"]'),
('98fdb4ac-1359-4ede-b573-5d9bba2080df','欲遊龍山鹿苑有作','齊己','唐','唐诗','tang','','[]','龍山門不遠，鹿苑路非遙。',48,'全唐诗/poet.tang.46000.json','["龍山門不遠，鹿苑路非遙。", "合逐閑身去，何須待客招。", "年華殘兩鬢，筋骨倦長宵。", "聞說峯前寺，新修白石橋。"]'),
('51a93ef5-81f4-4a27-be27-8be261022261','再逢晝公','齊己','唐','唐诗','tang','','[]','竟陵西別後，徧地起刀兵。',48,'全唐诗/poet.tang.46000.json','["竟陵西別後，徧地起刀兵。", "彼此無緣着，雲山有處行。", "久吟難敵句，終忍不求名。", "年鬢俱如雪，相看眼且明。"]'),
('32badc31-3d02-46de-896b-9087d105da9c','送人遊武陵湘中','齊己','唐','唐诗','tang','','[]','爲子歌行樂，西南入武陵。',48,'全唐诗/poet.tang.46000.json','["爲子歌行樂，西南入武陵。", "風煙無戰士，賓榻有吟僧。", "山遶軍城疊，江臨寺閣層。", "遍尋幽勝了，湘水泛清澄。"]'),
('3de1c6fc-2432-46f4-b110-81770248bc50','酬九經者','齊己','唐','唐诗','tang','','["\u9ec4\u6cb3"]','九經三史學，窮妙又窮微。',48,'全唐诗/poet.tang.46000.json','["九經三史學，窮妙又窮微。", "長白山初出，青雲路欲飛。", "江僧酬雪句，沙鶴識麻衣。", "家在黃河北，南來偶未歸。"]'),
('5945190a-363d-4c3a-a443-891ba8501cee','寄贈集灘二公','齊己','唐','唐诗','tang','','[]','聞有難名境，因君住更名。',48,'全唐诗/poet.tang.46000.json','["聞有難名境，因君住更名。", "軒窗中夜色，風月遶灘聲。", "客好過無厭，禽幽畫不成。", "終期一尋去，聊且寄吟情。"]'),
('23e8fe38-6052-44ee-9407-c8541e0aa31a','夏日作','齊己','唐','唐诗','tang','','[]','燕雀語相和，風池滿芰荷。',48,'全唐诗/poet.tang.46000.json','["燕雀語相和，風池滿芰荷。", "可驚成事晚，殊喜得閑多。", "竹衆涼欺水，苔繁綠勝莎。", "無慙孤聖代，賦詠有詩歌。"]'),
('00ec915a-7260-43dd-ad4b-5b42631ade45','行路難','齊己','唐','唐诗','tang','','[]','下浸與高盤，不爲行路難。',48,'全唐诗/poet.tang.46000.json','["下浸與高盤，不爲行路難。", "是非真險惡，翻覆作峯巒。", "漆媿同時黑，朱慙巧處丹。", "令人畏相識，欲畫白雲看。"]'),
('307af128-8709-41c2-b7a0-57130271570f','送玉泉道者迴山寺','齊己','唐','唐诗','tang','','[]','却憶西峯頂，經行絕愛憎。',48,'全唐诗/poet.tang.46000.json','["却憶西峯頂，經行絕愛憎。", "別來心念念，歸去雪層層。", "石塢尋春笋，苔龕續夜燈。", "應悲塵土裏，追逐利名僧。"]'),
('7c6e5441-5e97-43c9-b214-8aa62f3a669e','謝王拾遺見訪兼寄篇什','齊己','唐','唐诗','tang','','[]','竹裏安禪處，生涯一印灰。',48,'全唐诗/poet.tang.46000.json','["竹裏安禪處，生涯一印灰。", "經年乞食過，昨日諫臣來。", "愧把黃梅偈，曾酬白雪才。", "因令識鳥跡，重疊在蒼苔。"]'),
('00a313cd-bf1b-44cd-8173-a61058525404','題張氏池亭','齊己','唐','唐诗','tang','','[]','樹石叢叢別，詩家趣向幽。',48,'全唐诗/poet.tang.46000.json','["樹石叢叢別，詩家趣向幽。", "有時閑客散，始覺細泉流。", "蝶到琴棋畔，花過島嶼頭。", "月明紅藕上，應見白龜遊。"]'),
('f96f1c17-fa9a-4cac-b203-97ebb0e465b4','送人南遊','齊己','唐','唐诗','tang','','[]','且聽吟贈遠，君此去蒙州。',50,'全唐诗/poet.tang.46000.json','["且聽吟贈遠，君此去蒙州。", "瘴國頻聞說，邊鴻亦不遊。", "[蠻]花藏孔雀，野石亂犀牛。", "到彼誰相慰，知音有郡侯。"]'),
('2b708007-3148-42a6-a9ff-4a991d487183','題明公房','齊己','唐','唐诗','tang','','[]','寺北聞湘浪，窗南見嶽雲。',48,'全唐诗/poet.tang.46000.json','["寺北聞湘浪，窗南見嶽雲。", "自然高日用，何要出人羣。", "瓦滴殘松雨，香爐匝印文。", "近年精易道，疑者曉紛紛。"]'),
('f2a024be-2085-4af0-afd4-41bd0310314a','寄顧處士','齊己','唐','唐诗','tang','','[]','半年離別夢，來往即湖邊。',48,'全唐诗/poet.tang.46000.json','["半年離別夢，來往即湖邊。", "兩幅關山雪，尋常在眼前。", "項容藏古翠，張藻卷寒煙。", "藍淀圖花鳥，時人不惜錢。"]'),
('e3188be4-268f-4b36-aec4-8a11ba78b584','貽徐生','齊己','唐','唐诗','tang','','[]','可能東海子，清苦在貧居。',48,'全唐诗/poet.tang.46000.json','["可能東海子，清苦在貧居。", "掃地無閑客，堆窗有古書。", "少年猶若此，向老合何如。", "去歲頻相訪，今來見亦疎。"]'),
('b37b3b4c-4f84-4fb2-934c-bf94c5d35929','謝虛中上人晚秋見寄','齊己','唐','唐诗','tang','','[]','楚外同文在，荆門得信時。',48,'全唐诗/poet.tang.46000.json','["楚外同文在，荆門得信時。", "幾重相別意，一首晚秋詩。", "日暮山沈雨，蓮殘水滿池。", "登樓試南望，爲子動歸思。"]'),
('3323ae6a-232d-45ad-9be9-887fda861cd9','寄東林言之禪子','齊己','唐','唐诗','tang','','[]','聞思相送後，幽院閉苔錢。',48,'全唐诗/poet.tang.46000.json','["聞思相送後，幽院閉苔錢。", "使我吟還廢，聞君病未痊。", "聽秋唯困坐，怕客但佯眠。", "可惜東窗月，無寥過一年。"]'),
('0365bb66-4fc5-418c-874c-8eec2bb1731b','寒節日寄鄉友','齊己','唐','唐诗','tang','','[]','歲歲逢寒食，寥寥古寺家。',48,'全唐诗/poet.tang.46000.json','["歲歲逢寒食，寥寥古寺家。", "踏青思故里，垂白看楊花。", "原野稀疎雨，江天冷澹霞。", "滄浪與湘水，歸恨共無涯。"]'),
('c6595eac-e121-4906-b4f8-b66ead3ac6a9','聞西蟾從弟卜巖居嶽西有寄','齊己','唐','唐诗','tang','','[]','瀑布見高低，巖開巖壁西。',48,'全唐诗/poet.tang.46000.json','["瀑布見高低，巖開巖壁西。", "碧雲多舊作，紅葉幾新題。", "滴瀝中疎磬，嵌空半倚梯。", "仍聞樵子徑，□不到前溪。"]'),
('601f4010-2087-40f0-86c7-6e8329248115','寄懷西蟾師弟','齊己','唐','唐诗','tang','','[]','萬里八九月，一身西北風。',48,'全唐诗/poet.tang.46000.json','["萬里八九月，一身西北風。", "自從相示後，長記在吟中。", "見說南遊遠，堪懷我姓同。", "江邊忽得信，迴到岳門東。"]'),
('c9351812-15dc-48ff-8fd0-0d248f01dac4','撲滿子','齊己','唐','唐诗','tang','','[]','祗愛滿我腹，爭如滿害身。',24,'全唐诗/poet.tang.46000.json','["祗愛滿我腹，爭如滿害身。", "到頭須撲破，却散與他人。"]'),
('22f74441-68c6-4125-b938-90b3fe9bacfa','寄西川惠光大師曇域','齊己','唐','唐诗','tang','','[]','禪月有名子，相知面未曾。',48,'全唐诗/poet.tang.46000.json','["禪月有名子，相知面未曾。", "筆精垂壁溜，詩澀滴杉冰。", "蜀國從棲泊，蕪城幾廢興。", "憶歸應寄夢，東北過金陵。"]'),
('42c871d7-b40c-476f-8b9d-20cf75258855','憶別匡山寄彭澤乾晝上人','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','憶別匡山日，無端是遠遊。',48,'全唐诗/poet.tang.46000.json','["憶別匡山日，無端是遠遊。", "却迴看五老，飜悔上孤舟。", "蹭蹬三千里，蹉跎二十秋。", "近來空寄夢，時到虎溪頭。"]'),
('f623a51e-4768-4c26-8d7d-7530d622df3c','又寄彭澤晝公','齊己','唐','唐诗','tang','','[]','聞君彭澤住，結搆近陶公。',48,'全唐诗/poet.tang.46000.json','["聞君彭澤住，結搆近陶公。", "種菊心相似，嘗茶味不同。", "湖光秋枕上，嶽翠夏窗中。", "八月東林去，吟香菡萏風。"]'),
('fc224112-c305-4c52-a17d-383b339e67fb','因覽支使孫中丞看可準大師詩序有寄','齊己','唐','唐诗','tang','','[]','一千篇裏選，三百首菁英。',48,'全唐诗/poet.tang.46000.json','["一千篇裏選，三百首菁英。", "玉尺新量出，金刀舊剪成。", "錦江增古翠，仙掌減元精。", "自此爲風格，留傳諸後生。"]'),
('32f53149-5549-46e8-9017-cd3b61412b40','新秋病中枕上聞蟬','齊己','唐','唐诗','tang','','[]','枕上稍醒醒，忽聞蟬一聲。',48,'全唐诗/poet.tang.46000.json','["枕上稍醒醒，忽聞蟬一聲。", "此時知不死，昨日即前生。", "更欲臨窗聽，猶難策杖行。", "尋應同蛻殼，重飲露華清。"]'),
('7e353afe-506b-4331-a1be-e5de4ba27607','寄雲蓋山先禪師','齊己','唐','唐诗','tang','','[]','曾尋湘水東，古翠積秋濃。',48,'全唐诗/poet.tang.46000.json','["曾尋湘水東，古翠積秋濃。", "長老禪棲處，半天雲蓋峯。", "閑牀饒得石，雜樹少於松。", "近有誰堪語，瀏陽妙指蹤。"]'),
('56b1ff2a-937a-45a0-89e1-7484fce8b835','落葉','齊己','唐','唐诗','tang','','[]','落多秋亦晚，窗外見諸鄰。',48,'全唐诗/poet.tang.46000.json','["落多秋亦晚，窗外見諸鄰。", "世上誰驚盡，林間獨掃頻。", "蕭騷微月夜，重疊早霜晨。", "昨日繁陰在，鶯聲樹樹春。"]'),
('c8f10ccd-9ba3-4a51-8be0-c5686d3f51b1','次耒陽作','齊己','唐','唐诗','tang','','[]','遶岳復沿湘，衡陽又耒陽。',48,'全唐诗/poet.tang.46000.json','["遶岳復沿湘，衡陽又耒陽。", "不堪思北客，從此入南荒。", "旦夕多猨狖，淹留少雪霜。", "因經杜公墓，惆悵學文章。"]'),
('1b8763bb-cddb-4993-ad1e-47112403a9b6','舟中晚望祝融峯','齊己','唐','唐诗','tang','','[]','天際卓寒青，舟中望晚晴。',48,'全唐诗/poet.tang.46000.json','["天際卓寒青，舟中望晚晴。", "十年關夢寐，此日向崢嶸。", "巨石凌空黑，飛泉照夜明。", "終當躡孤頂，坐看白雲生。"]'),
('93936db3-3a85-4975-a978-b95c0b9adffc','弔杜工部墳','齊己','唐','唐诗','tang','','[]','鵬翅蹋於斯，明君知不知。',50,'全唐诗/poet.tang.46000.json','["鵬翅蹋於斯，明君知不知。", "[域]中詩價大，荒外土墳卑。", "瘴雨無時滴，蠻風有穴吹。", "唯應李太白，魂魄往來疲。"]'),
('b18f0ea2-40a6-4df2-a1a0-2a7a9c7d44f0','嶽中寄殷處士','齊己','唐','唐诗','tang','','[]','出嶽與入嶽，前題繼後題。',48,'全唐诗/poet.tang.46000.json','["出嶽與入嶽，前題繼後題。", "遍尋僧壁上，多在雁峯西。", "近說遊江寺，將誰話石梯。", "相思立高巘，山下草萋萋。"]'),
('4450ed44-2cba-4677-84b5-0636cf6759cf','送幽禪師','齊己','唐','唐诗','tang','','[]','霜繁野葉飛，長老卷行衣。',48,'全唐诗/poet.tang.46000.json','["霜繁野葉飛，長老卷行衣。", "浮世不知處，白雲相待歸。", "磬和天籟響，禪動嶽神威。", "莫便言長往，勞生待發機。"]'),
('2ef0396a-9b74-441d-b12d-ef44d8fd2b90','觀燒','齊己','唐','唐诗','tang','','[]','獵獵寒蕪引，承風勢不還。',48,'全唐诗/poet.tang.46000.json','["獵獵寒蕪引，承風勢不還。", "放來應有主，焚去到何山。", "焰入空濛裏，煙飛蒼莽間。", "石中有良玉，惆悵但傷顏。"]'),
('2824799b-be82-42e0-98c8-4d11bc4f0398','詠茶十二韻','齊己','唐','唐诗','tang','','[]','百草讓爲靈，功先百草成。',144,'全唐诗/poet.tang.46000.json','["百草讓爲靈，功先百草成。", "甘傳天下口，貴占火前名。", "出處春無雁，收時谷有鶯。", "封題從澤國，貢獻入秦京。", "齅覺精新極，嘗知骨自輕。", "研通天柱響，摘遶蜀山明。", "賦客秋吟起，禪師晝臥驚。", "角開香滿室，爐動綠凝鐺。", "晚憶涼泉對，閑思異果平。", "松黃乾旋泛，雲母滑隨傾。", "頗貴高人寄，尤宜別匱盛。", "曾尋修事法，妙盡陸先生。"]'),
('10cd1f03-0b8c-4aa3-a50b-d9803271fe2f','寄陽岐西峯僧','齊己','唐','唐诗','tang','','[]','西峯殘照東，瀑布灑冥鴻。',48,'全唐诗/poet.tang.46000.json','["西峯殘照東，瀑布灑冥鴻。", "閑憶高牕外，秋晴萬里空。", "藤陰藏石磴，衣毳落杉風。", "日有誰來覓，層層鳥道中。"]'),
('9da2719c-6faa-48e8-83d1-cbcbe6634027','迴雁峯','齊己','唐','唐诗','tang','','[]','瘴雨過孱顏，危邊有徑盤。',36,'全唐诗/poet.tang.46000.json','["瘴雨過孱顏，危邊有徑盤。", "壯堪扶壽嶽，靈合置仙壇。", "影北鴻聲亂，青南客道難。"]'),
('142f8709-117e-4a0e-94d3-afa5b7bb2589','贈詢公上人','齊己','唐','唐诗','tang','','[]','威儀何貴重，一室貯水清。',48,'全唐诗/poet.tang.46000.json','["威儀何貴重，一室貯水清。", "終日松杉徑，自多蟲蟻行。", "像前孤立影，鐘外數珠聲。", "知悟修來事，今爲第幾生。"]'),
('73615dae-d26a-4c08-99a8-a6533e8af2d5','秋興','齊己','唐','唐诗','tang','','[]','所見背時情，閑行亦獨行。',48,'全唐诗/poet.tang.46000.json','["所見背時情，閑行亦獨行。", "晚涼思水石，危閣望崢嶸。", "雨外殘雲片，風中亂葉聲。", "舊山吟友在，相憶夢應清。"]'),
('72cfc47c-43e6-4129-b5c4-5cbebfba920c','古寺老松','齊己','唐','唐诗','tang','','[]','百歲禪師說，先師指此松。',48,'全唐诗/poet.tang.46000.json','["百歲禪師說，先師指此松。", "小年行道遶，早見偃枝重。", "月檻移孤影，秋亭卓一峯。", "終當因夜電，拏攫從雲龍。"]'),
('b7aa491a-afaf-4ba5-ab62-c466fe0dd096','題無余處士書齋','齊己','唐','唐诗','tang','','[]','閑地從莎蘚，誰人愛此心。',48,'全唐诗/poet.tang.46000.json','["閑地從莎蘚，誰人愛此心。", "琴棋懷客遠，風雪閉門深。", "枕外江灘響，窗西樹石陰。", "他年衡嶽寺，爲我一相尋。"]'),
('9fc45fca-f3d8-448e-95e8-033cb9b3dcd0','歲暮江寺住','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','山依枯槁容，何處見年終？',48,'全唐诗/poet.tang.46000.json','["山依枯槁容，何處見年終？", "風雪軍城外，蒹葭古寺中。", "孤村誰認磬，極浦夜鳴鴻。", "坐憶匡廬隱，泉聲滴半空。"]'),
('f754fb00-1b8c-41cb-b098-9fa1c9fade4a','新燕','齊己','唐','唐诗','tang','','[]','棲託近佳人，應憐巧語新。',48,'全唐诗/poet.tang.46000.json','["棲託近佳人，應憐巧語新。", "風光華屋暖，弦管牡丹晨。", "遠采江泥膩，雙飛麥雨勻。", "差池自有便，敢觸杏梁塵。"]'),
('85d0e845-f7ae-43da-9278-eef010bfa700','喻吟','齊己','唐','唐诗','tang','','[]','日用是何專，吟疲即坐禪。',48,'全唐诗/poet.tang.46000.json','["日用是何專，吟疲即坐禪。", "此生還可喜，餘事不相便。", "頭白無邪裏，魂清有象先。", "江花與芳草，莫染我情田。"]'),
('335e53a1-a2b1-4976-bff8-adda5fd43ea4','過湘江唐弘書齋','齊己','唐','唐诗','tang','','[]','四鄰無俗迹，終日大開門。',48,'全唐诗/poet.tang.46000.json','["四鄰無俗迹，終日大開門。", "水晚來邊雁，林秋下楚猨。", "一家隨難在，雙眼向書昏。", "沈近騷人廟，吟應見古魂。"]'),
('9184b407-bfa9-4307-af79-cb8439ebf014','讀賈島集','齊己','唐','唐诗','tang','','[]','遺篇三百首，首首是遺冤。',48,'全唐诗/poet.tang.46000.json','["遺篇三百首，首首是遺冤。", "知到千年外，更逢何者論。", "離秦空得罪，入蜀但聽猨。", "還似長沙祖，唯餘賦鵩言。"]'),
('148eb136-e973-4785-810c-9f25f9ec2af0','寄山中諸友','齊己','唐','唐诗','tang','','[]','自歸城裏寺，長憶宿山門。',48,'全唐诗/poet.tang.46000.json','["自歸城裏寺，長憶宿山門。", "終夜冥心客，諸峯呌月猨。", "嵐光生眼力，泉滴爽吟魂。", "只待遊方遍，還來埽樹根。"]'),
('97d985cd-b7dd-4911-8f29-e126f163cbfd','懷終南僧','齊己','唐','唐诗','tang','','[]','擾擾一京塵，何門是了因。',48,'全唐诗/poet.tang.46000.json','["擾擾一京塵，何門是了因。", "萬重千疊嶂，一去不來人。", "鳥道春殘雪，蘿龕晝定身。", "寥寥石窗外，天籟動衣巾。"]'),
('a8f6c869-6a72-44bb-b5b4-ba39eefd8815','送二友生歸宜陽','齊己','唐','唐诗','tang','','[]','二生俱我友，清苦輩流稀。',48,'全唐诗/poet.tang.46000.json','["二生俱我友，清苦輩流稀。", "舊國居相近，孤帆秋共歸。", "殘陽沙鳥亂，疎雨島楓飛。", "幾宿多山處，猨啼燭影微。"]'),
('50ef47d6-a89f-4b9d-a332-5d35664df760','懷從弟','齊己','唐','唐诗','tang','','[]','孤窗燭影微，何事阻吟思。',48,'全唐诗/poet.tang.46000.json','["孤窗燭影微，何事阻吟思。", "兄弟斷消息，山川長路岐。", "日沈栖鶴塢，霜著呌猨枝。", "可想爲懷抱，多愁多難時。"]'),
('2c5c5ec4-7aa7-41e4-a90a-64ea41fbeb6f','岳陽道中作','齊己','唐','唐诗','tang','','[]','客思尋常動，未如今斷魂。',48,'全唐诗/poet.tang.46000.json','["客思尋常動，未如今斷魂。", "路岐經亂後，風雪少人村。", "大澤鳴寒雁，千峯啼晝猨。", "爭教此時白，不上鬢鬚根。"]'),
('dc9c3333-5275-46c5-9ce4-9c557efe9465','赴鄭谷郎中招遊龍興觀讀題詩[板]謁七真儀像因有十八韻','齊己','唐','唐诗','tang','','[]','何處陪遊勝，龍興古觀時。',216,'全唐诗/poet.tang.46000.json','["何處陪遊勝，龍興古觀時。", "詩懸大雅作，殿禮七真儀。", "遠繼周南美，彌旌拱北思。", "雄方垂朴略，後輩仰箴規。", "對坐茵花暖，偕行蘚陣隳。", "僧絛初學結，朝服久慵披。", "到處琴碁傍，登樓筆硯隨。", "論禪忘視聽，譚老極希夷。", "照日江光遠，遮軒檜影欹。", "觸鞋松子響，窺立鶴雛癡。", "始貴茶巡爽，終憐酒散遲。", "放懷還把杖，憇石或搘頤。", "眺遠凝清眄，吟高動白髭。", "風鵬心不小，蒿雀志徒卑。", "顧我專無作，於身忘有爲。", "叨因五字解，每忝重言期。", "捨此應休也，何人更賞之。", "淹留仙境晚，迴騎雪風吹。"]'),
('139de24b-1661-41cd-a20f-20d59c670d38','書李秀才壁','齊己','唐','唐诗','tang','','[]','干戈阻上日，南國寄貧居。',50,'全唐诗/poet.tang.46000.json','["干戈阻上日，南國寄貧居。", "舊里荒應盡，新年病未除。", "窗風連島樹，門逕接隣蔬。", "我有閑來約，相看雪滿[株]。"]'),
('277a4ee9-8d7f-41de-9399-6c52833aa58a','聞尚顏下世','齊己','唐','唐诗','tang','','[]','嶽僧傳的信，聞在麓山亡。',48,'全唐诗/poet.tang.46000.json','["嶽僧傳的信，聞在麓山亡。", "郡有爲詩客，誰來一影堂。", "夢休尋灞滻，跡已絕瀟湘。", "遠憶同吟石，新秋檜栢涼。"]'),
('5d362c18-fcfe-4036-a697-1f73701e453c','薔薇','齊己','唐','唐诗','tang','','[]','根本似玫瑰，繁英刾外開。',48,'全唐诗/poet.tang.46000.json','["根本似玫瑰，繁英刾外開。", "香高藂有架，紅落地多苔。", "去住閑人看，晴明遠蝶來。", "牡丹先幾日，銷歇向塵埃。"]'),
('b5f033de-71c5-4f37-8b6f-24a1384d2c64','送隆公上人','齊己','唐','唐诗','tang','','[]','獨攜譚柄去，千里指人寰。',48,'全唐诗/poet.tang.46000.json','["獨攜譚柄去，千里指人寰。", "未斷生徒望，難教白日閑。", "空江橫落照，大府向西山。", "好騁陳那孔，誰云劫石頑。"]'),
('576ddeac-7aa5-4fce-a92c-94b92f7c835c','宿簡寂觀','齊己','唐','唐诗','tang','','[]','萬壑雲霞影，千年松檜聲。',48,'全唐诗/poet.tang.46000.json','["萬壑雲霞影，千年松檜聲。", "如何教下士，容易信長生。", "月共虛無白，香和沆𤅈清。", "閑尋古廊畫，記得列仙名。"]'),
('dc04c087-e9d7-4996-ab1a-2e67ee8c4fbc','遇元上人','齊己','唐','唐诗','tang','','[]','七澤過名山，相逢黃落殘。',48,'全唐诗/poet.tang.46000.json','["七澤過名山，相逢黃落殘。", "杉松開寺晚，泉月話心寒。", "祖遍諸方禮，經曾幾處看。", "應懷出家院，紫閣近長安。"]'),
('b9d32a46-de5f-41ba-a261-437611f80d0d','早梅','齊己','唐','唐诗','tang','','["\u548f\u7269", "\u6885\u82b1", "\u8a00\u5fd7", "\u548f\u7269\u8bd7"]','萬木凍欲折，孤根暖獨迴。',48,'全唐诗/poet.tang.46000.json','["萬木凍欲折，孤根暖獨迴。", "前村深雪裏，昨夜一枝開。", "風遰幽香去，禽窺素豔來。", "明年如應律，先發映春臺。"]'),
('ad519176-a940-4622-b846-11a18a6c1f7c','聽泉','齊己','唐','唐诗','tang','','[]','落石幾萬仞，冷聲飄遠空。',48,'全唐诗/poet.tang.46000.json','["落石幾萬仞，冷聲飄遠空。", "高秋初雨後，半夜亂山中。", "只有照壁月，更無吹葉風。", "幾曾廬岳聽，到曉與僧同。"]'),
('9776b3c1-a67f-4d20-bd37-45097beb0378','送孫逸人歸廬山','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','獨自擔琴鶴，還歸瀑布東。',48,'全唐诗/poet.tang.46000.json','["獨自擔琴鶴，還歸瀑布東。", "逍遙非俗趣，楊柳謾春風。", "草遶村程綠，花盤石磴紅。", "他時許相覓，五老亂雲中。"]'),
('e0ceaa89-9df4-4566-9a26-c049ce1d6eb0','聽李尊師彈琴','齊己','唐','唐诗','tang','','[]','仙子弄瑤琴，仙山松月深。',48,'全唐诗/poet.tang.46000.json','["仙子弄瑤琴，仙山松月深。", "此聲含太古，誰聽到無心。", "灑石霜千片，歕崖泉萬尋。", "何人傳指法，攜向海中岑。"]'),
('4cdce8c2-e3ac-4971-a1b6-0a1ceef8335b','寄武陵微上人','齊己','唐','唐诗','tang','','[]','善卷臺邊寺，松筠遶祖堂。',48,'全唐诗/poet.tang.46000.json','["善卷臺邊寺，松筠遶祖堂。", "秋聲度風雨，曉色遍滄浪。", "白石同誰坐，清吟過我狂。", "近聞爲古律，雅道更重光。"]'),
('b9e5266f-e328-43fc-9b27-e0a25012ce58','匡山寓居棲公','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','外物盡已外，閑遊且自由。',48,'全唐诗/poet.tang.46000.json','["外物盡已外，閑遊且自由。", "好山逢過夏，無事住經秋。", "樹影殘陽寺，茶香古石樓。", "何時定休講，歸漱虎溪流。"]'),
('1140aed1-c7d0-433e-8c2d-b4cf74b30d81','湘西道林寺陶太尉井','齊己','唐','唐诗','tang','','[]','太尉遺孤井，寒澄七百年。',48,'全唐诗/poet.tang.46000.json','["太尉遺孤井，寒澄七百年。", "未聞陵谷變，終與姓名傳。", "影浸無風樹，光含有月天。", "林僧曉來此，滿汲灑金田。"]'),
('54bb81d9-24c6-4720-bb37-4bb81e8bb40d','寄松江陸龜蒙處士','齊己','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','萬卷功何用，徒稱處士休。',48,'全唐诗/poet.tang.46000.json','["萬卷功何用，徒稱處士休。", "閑欹太湖石，醉聽洞庭秋。", "道在誰開口，詩成自點頭。", "中間欲相訪，尋便阻戈矛。"]'),
('a12b8e11-1ceb-4656-a7b9-9e07046a0f99','閉門','齊己','唐','唐诗','tang','','[]','外事休關念，灰心獨閉門。',48,'全唐诗/poet.tang.46000.json','["外事休關念，灰心獨閉門。", "無人來問我，白日又黃昏。", "燈集飛蛾影，窗銷迸雪痕。", "中心自明了，一句祖師言。"]'),
('adc36a10-c127-4a7c-89aa-249c8c02c171','看水','齊己','唐','唐诗','tang','','[]','范蠡東浮闊，靈均北泛長。',48,'全唐诗/poet.tang.46000.json','["范蠡東浮闊，靈均北泛長。", "誰知遠煙浪，別有好思量。", "故國門前急，天涯照裏忙。", "難收上樓興，渺漫正斜陽。"]'),
('47b6cc86-2094-426b-9e9b-f21bc50f66f7','寄棲白上人','齊己','唐','唐诗','tang','','[]','萬國爭名地，吾師獨此閑。',48,'全唐诗/poet.tang.46000.json','["萬國爭名地，吾師獨此閑。", "題詩招上相，看雪下南山。", "內殿承恩久，中條進表還。", "常因秋貢客，少得掩禪關。"]'),
('9882b26c-af56-44b6-b5ab-8630d8b26c4d','自題','齊己','唐','唐诗','tang','','[]','禪外求詩妙，年來鬢已秋。',48,'全唐诗/poet.tang.46000.json','["禪外求詩妙，年來鬢已秋。", "未嘗將一字，容易謁諸侯。", "挂夢山皆遠，題名石盡幽。", "敢言梁太子，傍采碧雲流。"]'),
('ea8aa096-9bdf-4d8f-bbb4-95eb8acd0586','孫支使來借詩集因有謝','齊己','唐','唐诗','tang','','[]','冥搜從少小，隨分得淳元。',48,'全唐诗/poet.tang.46000.json','["冥搜從少小，隨分得淳元。", "聞說吟僧口，多傳過蜀門。", "相尋江島上，共看夏雲根。", "坐落遲遲日，新題互把論。"]'),
('4e7876be-c640-4cb1-89ac-6fa8640a3587','夏日言懷','齊己','唐','唐诗','tang','','[]','苦被流年迫，衰羸老病情。',48,'全唐诗/poet.tang.46000.json','["苦被流年迫，衰羸老病情。", "得歸青嶂死，便共白雲生。", "樹枿燒爐響，崖稜躡屐聲。", "此心人信否，魂夢自分明。"]'),
('029d9706-a709-4a05-b283-e592e593d964','早秋寄友生','齊己','唐','唐诗','tang','','[]','雨多殘暑歇，蟬急暮風清。',48,'全唐诗/poet.tang.46000.json','["雨多殘暑歇，蟬急暮風清。", "誰有閑心去，江邊看水行。", "河遙紅蓼簇，野闊白煙平。", "試折秋蓮葉，題詩寄竺卿。"]'),
('b6fa3173-7ecd-434f-8ac9-194c44625a04','送王秀才往松滋夏課','齊己','唐','唐诗','tang','','[]','松滋聞古縣，明府是詩家。',50,'全唐诗/poet.tang.46000.json','["松滋聞古縣，明府是詩家。", "靜理餘無事，[攲]眠盡落花。", "江光搖夕照，柳影帶殘霞。", "君去應相與，乘船泛月華。"]'),
('a7462858-2a79-4f27-91b7-d163407fde03','喜{巩/言}公自武陵至','齊己','唐','唐诗','tang','','[]','已盡滄浪興，還思相楚行。',48,'全唐诗/poet.tang.46000.json','["已盡滄浪興，還思相楚行。", "鬢全無舊黑，詩別有新清。", "暫憇臨寒水，時來扣靜荆。", "囊中有靈藥，終不獻公卿。"]'),
('6cee7519-f5f6-49d7-b973-e371d47fcfe1','假山','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','匡廬久別離，積翠杳天涯。',218,'全唐诗/poet.tang.46000.json','["匡廬久別離，積翠杳天涯。", "靜室曾圖峭，幽亭復創奇。", "典衣酬土價，擇日運工時。", "信手成重疊，隨心作蔽虧。", "根盤驚院窄，頂聳訝簷卑。", "鎮地那言重，當軒未厭危。", "巨靈何忍擘，秦政肯輕移。", "晚覺莎煙觸，寒聞竹籟吹。", "藍灰澄古色，泥水合凝滋。", "引看僧來數，牽吟客散遲。", "九華渾髣髴，五老頗參差。", "蛛網藤蘿挂，春霖瀑布垂。", "加添雙石笋，映帶小蓮池。", "舊說雷居士，曾聞遠大師。", "紅霞中結社，白壁上題詩。", "顧此誠徒爾，勞心是妄爲。", "經營慙培塿，賞翫愧童兒。", "會入千峯去，[閑]蹤任屬誰。"]'),
('a53b111a-c5a2-4f7e-8304-662e7d18451e','謝西川可準上人遠寄詩集','齊己','唐','唐诗','tang','','[]','匡社經行外，沃洲禪宴餘。',48,'全唐诗/poet.tang.46000.json','["匡社經行外，沃洲禪宴餘。", "吾師還繼此，後輩復何如。", "江上傳風雅，靜中時卷舒。", "堪隨樂天集，共伴白芙蕖。"]'),
('49e7f63d-6571-4ae8-bdba-45e325d04945','秋空','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','已覺秋空極，更堪寥泬青。',48,'全唐诗/poet.tang.46000.json','["已覺秋空極，更堪寥泬青。", "只應容好月，爭合有妖星。", "耿耿高河截，翛翛一雁經。", "曾於洞庭宿，上下徹心靈。"]'),
('382a3b64-6374-455b-a715-9d577c482db9','與聶尊師話道','齊己','唐','唐诗','tang','','[]','伯陽遺妙旨，杳杳與冥冥。',48,'全唐诗/poet.tang.46000.json','["伯陽遺妙旨，杳杳與冥冥。", "說即非難說，行還不易行。", "藥中迷九轉，心外覓長生。", "畢竟荒原上，一盤蒿隴平。"]'),
('3e29ac01-f34f-4c12-9e77-73e6ce9b9e41','送相里秀才自京至却迴','齊己','唐','唐诗','tang','','[]','夷門詩客至，楚寺閉蕭騷。',48,'全唐诗/poet.tang.46000.json','["夷門詩客至，楚寺閉蕭騷。", "老病語言澀，少年風韻高。", "難於尋閬島，險甚涉雲濤。", "珍重西歸去，無忘役思勞。"]'),
('b287f163-b33d-4e59-992f-0e13d164075e','謝人寄南榴卓子','齊己','唐','唐诗','tang','','[]','幸附全材長，良工斸器殊。',48,'全唐诗/poet.tang.46000.json','["幸附全材長，良工斸器殊。", "千林文栢有，一尺錦榴無。", "品格宜仙果，精光稱玉壺。", "憐君遠相寄，多愧野蔬麤。"]'),
('c5445ef9-62b4-4f4f-9462-1bd1eba27b5e','寄舊居隣友','齊己','唐','唐诗','tang','','[]','別後知何趣，搜奇少客同。',48,'全唐诗/poet.tang.46000.json','["別後知何趣，搜奇少客同。", "幾層山影下，萬樹雪聲中。", "晚鼎烹茶綠，晨廚爨粟紅。", "何時攜卷出，世代有名公。"]'),
('1ce1a692-e2b1-459b-b6b3-7d05a3c3e5c8','送朱秀才歸閩','齊己','唐','唐诗','tang','','[]','荆門來幾日，欲往又囊空。',48,'全唐诗/poet.tang.46000.json','["荆門來幾日，欲往又囊空。", "遠客歸南越，單衣背北風。", "近鄉微有雪，到海漸無鴻。", "努力成詩業，無謀謁至公。"]'),
('529f8a00-8427-4bb2-b44a-423e30a60555','龍潭作','齊己','唐','唐诗','tang','','[]','乍臨毛髮豎，雙壁夾湍流。',48,'全唐诗/poet.tang.46000.json','["乍臨毛髮豎，雙壁夾湍流。", "白日鳥影過，青苔龍氣浮。", "蔽空雲出石，應禱雨翻湫。", "四面耕桑者，先聞賀有秋。"]'),
('c1381762-eaca-4d76-a975-f2f1bc452257','依韻酬謝尊師見贈二首 一','齊己','唐','唐诗','tang','','[]','南國搜奇久，偏傷杜甫墳。',48,'全唐诗/poet.tang.46000.json','["南國搜奇久，偏傷杜甫墳。", "重來經漢浦，又去入嵩雲。", "舊別人稀見，新朝事漸聞。", "莫將高尚跡，閑處傲明君。"]'),
('b2f368df-6460-4a8a-a50e-067120f6a62e','依韻酬謝尊師見贈二首 二','齊己','唐','唐诗','tang','','[]','嶽頂休高臥，荆門訪掩扉。',48,'全唐诗/poet.tang.46000.json','["嶽頂休高臥，荆門訪掩扉。", "新詩遺我別，舊約與誰歸。", "賢路曾無滯，良時肯自違。", "明年窺日窟，仙桂露霏微。"]'),
('6f8322ff-7c32-4fe4-91fe-9435aecf8c68','送冰禪再往湖中','齊己','唐','唐诗','tang','','[]','行心寧肯住，南去與誰羣。',48,'全唐诗/poet.tang.46000.json','["行心寧肯住，南去與誰羣。", "碧落高空處，清秋一片雲。", "穿林瓶影滅，背雨錫聲分。", "應笑遊方久，龍鍾楚水濆。"]'),
('187f7b35-5b29-45bc-bafe-bc52158d0e7e','喜表公往楚王城','齊己','唐','唐诗','tang','','[]','已聞人捨地，結構舊基平。',48,'全唐诗/poet.tang.46000.json','["已聞人捨地，結構舊基平。", "一面湖光白，鄰家竹影清。", "應難尋輦道，空說是王城。", "誰信興亡跡，今來有磬聲。"]'),
('b0a827f4-c831-495e-8d03-403e6adecf57','春雪初晴喜友生至','齊己','唐','唐诗','tang','','[]','數日不見日，飄飄勢忽開。',48,'全唐诗/poet.tang.46000.json','["數日不見日，飄飄勢忽開。", "雖無忙事出，還有故人來。", "已盡南簷滴，仍殘北牖堆。", "明朝望平遠，相約在春臺。"]'),
('ce741969-818b-4249-9595-72962b75aac4','殘春連雨中偶作懷故人','齊己','唐','唐诗','tang','','[]','南鄰阻杖藜，屐齒遶牀泥。',48,'全唐诗/poet.tang.46000.json','["南鄰阻杖藜，屐齒遶牀泥。", "漠漠門長掩，遲遲日又西。", "不知何興味，更有好詩題。", "還憶東林否，行苔傍虎溪。"]'),
('e2604ea6-5676-4a2a-b1b0-cfe1e8c70e7c','送崔判官赴歸倅','齊己','唐','唐诗','tang','','[]','白首從顏巷，青袍去佐官。',48,'全唐诗/poet.tang.46000.json','["白首從顏巷，青袍去佐官。", "只應微俸祿，聊補舊飢寒。", "地說丘墟甚，民聞旱歉殘。", "春風吹綺席，賓主醉相歡。"]'),
('c9e8cbd1-1f7b-4021-bf12-747e5207fd84','寒食日懷寄友人','齊己','唐','唐诗','tang','','[]','萬井追寒食，閑扉獨不開。',48,'全唐诗/poet.tang.46000.json','["萬井追寒食，閑扉獨不開。", "梨花應折盡，柳絮自飛來。", "夢覺懷仙島，吟行遶砌苔。", "浮生已悟了，時節任相催。"]'),
('c68a41ae-a46f-4772-9be4-2520fc9af597','懷巴陵舊遊','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭雲夢秋，空碧共悠悠。',48,'全唐诗/poet.tang.46000.json','["洞庭雲夢秋，空碧共悠悠。", "孟子狂題後，何人更倚樓。", "日西來遠棹，風外見平流。", "終欲重尋去，僧窗古岸頭。"]'),
('11219b1a-a88a-4404-a9a2-3e17ea6f9f41','招乾晝上人宿話','齊己','唐','唐诗','tang','','[]','連夜因風雪，相留在寂寥。',48,'全唐诗/poet.tang.46000.json','["連夜因風雪，相留在寂寥。", "禪心誰指示，詩卷自焚燒。", "語默鄰寒漏，窗扉向早朝。", "天台若長往，還渡海門潮。"]'),
('dccb3b25-1628-4de0-9ca8-82a7b36c6b03','荆門秋日寄友人','齊己','唐','唐诗','tang','','[]','青溪知不遠，白首要難歸。',48,'全唐诗/poet.tang.46000.json','["青溪知不遠，白首要難歸。", "空想煙雲裏，春風鸞鶴飛。", "誰論傳法偈，自補坐禪衣。", "未謝侯門去，尋常即掩扉。"]'),
('f04fc4c7-cefc-4ed3-8f84-b993dd9a557e','哭鄭谷郎中','齊己','唐','唐诗','tang','','[]','朝衣閑典盡，酒病覺難醫。',48,'全唐诗/poet.tang.46000.json','["朝衣閑典盡，酒病覺難醫。", "下世無遺恨，傳家有大詩。", "新墳青嶂疊，寒食白雲垂。", "長憶招吟夜，前年風雪時。"]'),
('fc80325a-99e4-4054-a9dc-bd9ad4243cfc','題東林十八賢真堂','齊己','唐','唐诗','tang','','[]','白藕花前舊影堂，劉雷風骨畫龍章。',64,'全唐诗/poet.tang.46000.json','["白藕花前舊影堂，劉雷風骨畫龍章。", "共輕天子諸侯貴，同愛吾師一法長。", "陶令醉多招不得，謝公心亂入無方。", "何人到此思高躅，嵐點苔痕滿粉牆。"]'),
('78c3aadb-7b08-4345-990e-57401f8d564b','題南岳般若寺','齊己','唐','唐诗','tang','','[]','諸峯翠少中峯翠，五寺名高此寺名。',64,'全唐诗/poet.tang.46000.json','["諸峯翠少中峯翠，五寺名高此寺名。", "石路險盤嵐靄滑，僧窗高倚泬寥明。", "凌空殿閣由天設，遍地杉松是自生。", "更有上方難上處，紫苔紅蘚遶崢嶸。"]'),
('3161e003-06a1-4c10-b9cc-fa4f4cdc6fcf','寄廬岳僧','齊己','唐','唐诗','tang','','[]','一聞飛錫別區中，深入西南瀑布峯。',64,'全唐诗/poet.tang.46000.json','["一聞飛錫別區中，深入西南瀑布峯。", "天際雪埋千片石，洞門冰折幾株松。", "煙霞明媚棲心地，苔蘚縈紆出世蹤。", "莫問江邊舊居寺，火燒兵劫斷秋鐘。"]'),
('9c764e5a-afbc-41ad-b82d-2858301564c5','遊谷山寺','齊己','唐','唐诗','tang','','[]','城裏尋常見碧稜，水邊朝暮送歸僧。',64,'全唐诗/poet.tang.46000.json','["城裏尋常見碧稜，水邊朝暮送歸僧。", "數峯雲脚垂平地，一徑松聲徹上層。", "寒澗不生浮世物，陰崖猶積去年冰。", "此身有底難拋事，時復攜筇信步登。"]'),
('6c7e3855-313c-491c-9d69-d4ed7dacf80d','楚寺寒夜作','齊己','唐','唐诗','tang','','[]','寒爐局促坐成勞，暗淡燈光照二毛。',64,'全唐诗/poet.tang.46000.json','["寒爐局促坐成勞，暗淡燈光照二毛。", "水寺閑來僧寂寂，雪風吹去雁嗷嗷。", "江山積疊歸程遠，魂夢穿沿過處高。", "畢竟忘言是吾道，袈裟不稱揖蕭曹。"]'),
('60d33344-d3cc-497c-b5c0-f59ee8e6b9f4','送泰禪師歸南岳','齊己','唐','唐诗','tang','','[]','石龕閑鏁白猨邊，歸去程途半在船。',64,'全唐诗/poet.tang.46000.json','["石龕閑鏁白猨邊，歸去程途半在船。", "林簇曉霜離水寺，路穿新燒入山泉。", "已尋嵐壁臨空盡，却看星辰向地懸。", "有興寄題紅葉上，不妨收拾別爲編。"]'),
('479e0432-a820-4788-a579-0f4448c1a3e6','山中寄凝密大師兄弟','齊己','唐','唐诗','tang','','[]','一爐薪盡室空然，萬象何妨在眼前。',64,'全唐诗/poet.tang.46000.json','["一爐薪盡室空然，萬象何妨在眼前。", "時有興來還覓句，已無心去即安禪。", "山門影落秋風樹，水國光凝夕照天。", "借問荀家兄弟內，八龍頭角讓誰先。"]'),
('53c6cfa7-ac39-401b-ad07-2a7c3606f75b','海棠花','齊己','唐','唐诗','tang','','[]','繁於桃李盛於梅，寒食旬前社後開。',64,'全唐诗/poet.tang.46000.json','["繁於桃李盛於梅，寒食旬前社後開。", "半月暄和留豔態，兩時風雨免傷摧。", "人憐格異詩重賦，蝶戀香多夜更來。", "猶得殘紅向春暮，牡丹相繼發池臺。"]'),
('08fef0e4-f09b-4bf2-be68-016c0f8bff2f','題贈湘西龍安寺利禪師','齊己','唐','唐诗','tang','','[]','頭白已無行脚念，自開荒寺住煙蘿。',64,'全唐诗/poet.tang.46000.json','["頭白已無行脚念，自開荒寺住煙蘿。", "門前路到瀟湘盡，石上雲歸岳麓多。", "南祖衣盂曾禮謁，東林泉月舊經過。", "閑來松外看城郭，一片紅塵隔逝波。"]'),
('c48bfcc5-f3b2-4451-8ee8-af4531a5026b','寄文浩百法','齊己','唐','唐诗','tang','','[]','當時六祖在黃梅，五百人中眼獨開。',64,'全唐诗/poet.tang.46000.json','["當時六祖在黃梅，五百人中眼獨開。", "入室偈聞傳絕唱，昇堂客謾恃多才。", "鐵牛無用成真角，石女能生是聖胎。", "聞說欲拋經論去，莫教惆悵却空迴。"]'),
('6e958390-3dd2-4373-ab95-99622c7481a6','謝人寄新詩集','齊己','唐','唐诗','tang','','[]','所聞新事即戈矛，欲去終疑是暗投。',64,'全唐诗/poet.tang.46000.json','["所聞新事即戈矛，欲去終疑是暗投。", "遠客寄言還有在，此門將謂總無休。", "千篇著述誠難得，一字知音不易求。", "時入思量向何處，月圓孤凭水邊樓。"]'),
('6423f9d6-9d28-4564-bb87-b32d57f06a78','謝元願上人遠寄檀溪集','齊己','唐','唐诗','tang','','[]','白首蕭條居漢浦，清吟編集號檀溪。',64,'全唐诗/poet.tang.46000.json','["白首蕭條居漢浦，清吟編集號檀溪。", "有人收拾應如玉，無主知音只似泥。", "入理半同黃葉句，遣懷多擬碧雲題。", "猶能爲我相思在，千里封來夢澤西。"]'),
('80f879b3-0b18-43af-94ca-c774e89e9480','寄道林寺諸友','齊己','唐','唐诗','tang','','[]','吟興終依異境長，舊遊時入靜思量。',64,'全唐诗/poet.tang.46000.json','["吟興終依異境長，舊遊時入靜思量。", "江聲裏過東西寺，樹影中行上下方。", "春色濕僧巾屨膩，松花沾鶴骨毛香。", "老來何計重歸去，千里重湖浪渺茫。"]'),
('ac535cf7-3d3c-4a8b-88cc-10860986b0a6','贈智滿三藏','齊己','唐','唐诗','tang','','[]','灌頂清涼一滴通，大毗盧藏遍虛空。',64,'全唐诗/poet.tang.46000.json','["灌頂清涼一滴通，大毗盧藏遍虛空。", "欲飛薝蔔花無盡，須待陀羅尼有功。", "金杵力摧魔界黑，水精光透夜燈紅。", "可堪東獻明天子，命服新酬贊國風。"]'),
('70b0dd8f-3815-40ea-9d7b-0e0c1b22d8a1','謝王先輩湘中迴惠示卷軸','齊己','唐','唐诗','tang','','[]','少小即懷風雅情，獨能遺象琢淳精。',64,'全唐诗/poet.tang.46000.json','["少小即懷風雅情，獨能遺象琢淳精。", "不教霜雪侵玄鬢，便向雲霄換好名。", "攜去湘江聞鼓瑟，袖來緱嶺伴吹笙。", "多君百首貽衰颯，留把吟行訪竺卿。"]'),
('3cf7c137-d5b8-48e1-812e-0ea9b056ac71','荆渚寄懷西蜀無染大師兄','齊己','唐','唐诗','tang','','[]','大潙心付白崖前，寶月分輝照蜀天。',64,'全唐诗/poet.tang.46000.json','["大潙心付白崖前，寶月分輝照蜀天。", "聖主降情延北內，諸侯稽首問南禪。", "清秋不動驪龍海，紅日無私罔象川。", "欲聽吾宗舊山說，地邊身老楚江邊。"]'),
('94cb5b04-e3f9-4cb2-849e-8b7657796deb','謝武陵徐巡官遠寄五七字詩集','齊己','唐','唐诗','tang','','[]','五字才將七字爭，爲君聊敢試懸衡。',64,'全唐诗/poet.tang.46000.json','["五字才將七字爭，爲君聊敢試懸衡。", "鼎湖菡萏搖金影，蓬島鸞皇舞翠聲。", "還是靈龜巢得穩，要須仙子駕方行。", "兩邊珍重遙相惠，何夕燈前盡此情。"]'),
('a91bf2b0-6ba5-4c88-8433-ff456d70a128','重宿舊房與愚上人靜話','齊己','唐','唐诗','tang','','[]','曾此棲心過十冬，今來瀟灑屬生公。',64,'全唐诗/poet.tang.46000.json','["曾此棲心過十冬，今來瀟灑屬生公。", "檀欒舊植青添翠，菡萏新栽白換紅。", "北面城臨燈影合，西隣壁近講聲通。", "不知門下趨筵士，何似當時石解空。"]'),
('69ccd68e-76b6-4472-a228-7fac8116d0a0','謝南平王賜山雞','齊己','唐','唐诗','tang','','[]','五色文章類彩鸞，楚人羅得半摧殘。',64,'全唐诗/poet.tang.46000.json','["五色文章類彩鸞，楚人羅得半摧殘。", "金籠莫恨傷冠幘，玉粒頒慙剪羽翰。", "孤立影危丹檻裏，雙棲伴在白雲端。", "上台愛育通幽細，却放溪山去不難。"]'),
('e45df110-8ab8-4e43-b5bb-d8ef0ac82b63','荆門病中雨後書懷寄幕中知己','齊己','唐','唐诗','tang','','[]','病根翻作憶山勞，一雨聊堪浣鬱陶。',64,'全唐诗/poet.tang.46000.json','["病根翻作憶山勞，一雨聊堪浣鬱陶。", "心白未能忘水月，眼青獨得見秋毫。", "蟬聲晚簇枝枝急，雲影晴分片片高。", "還憶赤松兄弟否，別來應見鶴衣毛。"]'),
('759ee047-917a-4a49-affd-383fee929dd2','宿江寺','齊己','唐','唐诗','tang','','[]','島僧留宿慰衰顏，舊住何妨老未還。',64,'全唐诗/poet.tang.46000.json','["島僧留宿慰衰顏，舊住何妨老未還。", "身共錫聲離鳥外，跡同雲影過人間。", "曾無夢入朝天路，憶有詩題隔海山。", "珍重來晨渡江去，九華青裏扣松關。"]'),
('698fd1d7-bd94-4db8-a131-fca4bd77ef7b','謝貫微上人寄示古風今體四軸','齊己','唐','唐诗','tang','','[]','四軸騷詞書八行，捧吟肌骨遍清涼。',64,'全唐诗/poet.tang.46000.json','["四軸騷詞書八行，捧吟肌骨遍清涼。", "謾求龍樹能醫眼，休問圖澄學洗腸。", "今體盡搜初剖判，古風淳鑿未玄黃。", "不知誰肯降文陣，闇點旌旗敵子房。"]'),
('ef913822-6acf-4bb9-993c-4ebcdf3ce131','荆州貫休大師舊房','齊己','唐','唐诗','tang','','[]','疎篁抽笋柳垂陰，舊是休公種境吟。',64,'全唐诗/poet.tang.46000.json','["疎篁抽笋柳垂陰，舊是休公種境吟。", "入貢文儒來請益，出官卿相駐過尋。", "右軍書畫神傳髓，康樂文章夢授心。", "銷得青城千嶂下，白蓮標塔帝恩深。"]'),
('cdb5e910-b2dd-472d-a292-3fd991281be0','寄谷山長老','齊己','唐','唐诗','tang','','[]','遊遍名山祖遍尋，却來塵世渾光陰。',64,'全唐诗/poet.tang.46000.json','["遊遍名山祖遍尋，却來塵世渾光陰。", "肯將的的吾師意，擬付茫茫弟子心。", "豈有虛空遮道眼，不妨文字問知音。", "滄浪萬頃三更月，天上何如水底深。"]'),
('03f9784e-5572-4bd5-a336-edd81a34b189','寄黃暉處士','齊己','唐','唐诗','tang','','[]','蒙氏藝傳黃氏子，獨聞相繼得名高。',64,'全唐诗/poet.tang.46000.json','["蒙氏藝傳黃氏子，獨聞相繼得名高。", "鋒鋩妙奪金雞距，纖利精分玉兔毫。", "濡染只應親賦詠，風流不稱近方刀。", "何妨寄我臨池興，忍使江淹役夢勞。"]'),
('f52e91b4-136a-419b-929c-3a768939524b','荆門勉懷寄道林寺諸友','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','榮枯得失理昭然，誰斅離騷更問天。',64,'全唐诗/poet.tang.46000.json','["榮枯得失理昭然，誰斅離騷更問天。", "生下便知真夢幻，老來何必歎流年。", "清風不變詩應在，明月無蹤道可傳。", "珍重匡廬沃洲主，拂衣拋却好林泉。"]'),
('1fa14626-2576-4120-be7f-9b7a44b71295','荅崔校書','齊己','唐','唐诗','tang','','[]','雪色衫衣絕點塵，明知富貴是浮雲。',64,'全唐诗/poet.tang.46000.json','["雪色衫衣絕點塵，明知富貴是浮雲。", "不隨喧滑迷真性，何用潺湲洗汚聞。", "北闕會拋紅駊騀，東林社憶白氛氳。", "清吟有興頻相示，欲得多慙蠹蝕文。"]'),
('8a7c74d4-ccf3-44ea-8c23-5caadc174805','乞櫻桃','齊己','唐','唐诗','tang','','[]','去年曾賦此花詩，幾聽南園爛熟時。',64,'全唐诗/poet.tang.46000.json','["去年曾賦此花詩，幾聽南園爛熟時。", "嚼破紅香堪換骨，摘殘丹顆欲燒枝。", "流鶯偷啄心應醉，行客潛窺眼亦癡。", "聞說張筵就珠樹，任從攀折半離披。"]'),
('8e3fd930-32f2-4055-a97a-f45045d26e40','寄南雅上人','齊己','唐','唐诗','tang','','[]','曾得音書慰暮年，相思多故信難傳。',64,'全唐诗/poet.tang.46000.json','["曾得音書慰暮年，相思多故信難傳。", "清吟何處題紅葉，舊社空懷墮白蓮。", "山水本同真趣向，侯門剛有薄因緣。", "他時不得君招隱，會逐南歸楚客船。"]'),
('e0d3b21d-07c4-468c-856b-650d7f34d1d7','寄歐陽侍郎','齊己','唐','唐诗','tang','','[]','又聞繁總在嘉州，職重身閑倚寺樓。',64,'全唐诗/poet.tang.46000.json','["又聞繁總在嘉州，職重身閑倚寺樓。", "大象影和山面落，兩江聲合郡前流。", "棋輕國手知難敵，詩是天才肯易酬。", "畢竟男兒自高達，從來心不是悠悠。"]'),
('9421ca75-ec29-4853-b00d-e3a7fe24e0a8','與崔校書靜話言懷','齊己','唐','唐诗','tang','','[]','同年生在咸通裏，事佛爲儒趣盡高。',64,'全唐诗/poet.tang.46000.json','["同年生在咸通裏，事佛爲儒趣盡高。", "我性已甘披祖衲，君心猶待脫藍袍。", "霜髭曉幾臨銅鏡，雪鬢寒疎落剃刀。", "出世朝天俱未得，不妨還往有風騷。"]'),
('64ebd3bb-0b7f-402a-8ab4-ea31cb490079','謝人惠拄杖','齊己','唐','唐诗','tang','','[]','邛州靈境產修篁，九節材應表九陽。',64,'全唐诗/poet.tang.46000.json','["邛州靈境產修篁，九節材應表九陽。", "造化已能分尺度，保持爭合與尋常。", "幽林剪破清秋影，高手攜來綠玉光。", "深謝魯儒憐潦倒，欲教撐拄遶禪牀。"]'),
('2c4422f1-a943-453f-92ab-f5e9b10371a2','謝秦府推官寄丹臺集','齊己','唐','唐诗','tang','','[]','秦王手筆序丹臺，不錯褒揚最上才。',64,'全唐诗/poet.tang.46000.json','["秦王手筆序丹臺，不錯褒揚最上才。", "鳳闕幾傳爲匠碩，龍門曾用振風雷。", "錢郎未竭精華去，元白終存作者來。", "兩軸蚌胎驪頷耀，枉臨禪室伴寒灰。"]'),
('d0cd71b5-447f-47c1-b7fd-c1897b40a355','題畫鷺鷥兼簡孫郎中','齊己','唐','唐诗','tang','','[]','曾向滄江看不真，却因圖畫見精神。',64,'全唐诗/poet.tang.46000.json','["曾向滄江看不真，却因圖畫見精神。", "何妨金粉資高格，不用丹青點此身。", "蒲葉岸長堪映帶，荻花叢晚好相親。", "思量畫得勝籠得，野性由來不戀人。"]'),
('6d4eabee-0c78-4b7a-b0e8-d72fc2ce4568','賀行軍太傅得白氏東林集','齊己','唐','唐诗','tang','','[]','樂天歌詠有遺編，留在東林伴白蓮。',64,'全唐诗/poet.tang.46000.json','["樂天歌詠有遺編，留在東林伴白蓮。", "百尺典墳隨喪亂，一家風雅獨完全。", "常聞荆渚通侯論，果遂吳都使者傳。", "仰賀斯文歸朗鑒，永資聲政入薰弦。"]'),
('cde282bf-0fc9-4137-b86d-2ea05b7e800c','韶陽微公','齊己','唐','唐诗','tang','','[]','曲江晴影石千株，吾子思歸夢斷初。',64,'全唐诗/poet.tang.46000.json','["曲江晴影石千株，吾子思歸夢斷初。", "有信北來山疊疊，無言南去雨疎疎。", "祖師門接園林路，丞相家同井邑居。", "閑野老身留得否，相招多是秀才書。"]'),
('99059bde-ecf3-413e-820c-586952a4ef99','將之匡岳過尋陽','齊己','唐','唐诗','tang','','[]','帆過尋陽晚霽開，西風北雁似相催。',64,'全唐诗/poet.tang.46000.json','["帆過尋陽晚霽開，西風北雁似相催。", "大都浪後青堆沒，五老雲中翠疊來。", "此路便堪歸水石，何門更合向塵埃。", "遠公林下蓮池畔，箇箇高人盡有才。"]'),
('c7c6ae30-66f8-49c1-ba5c-03b62bf81c12','寄湘幕王重書記','齊己','唐','唐诗','tang','','[]','拋擲浟江舊釣磯，日參籌畫廢吟詩。',64,'全唐诗/poet.tang.46000.json','["拋擲浟江舊釣磯，日參籌畫廢吟詩。", "可能有事關心後，得似無人識面時。", "官好近聞加茜服，藥靈曾說換霜髭。", "高才直氣平生志，除却徒知即不知。"]'),
('d5cc543d-11aa-4deb-aa8d-5e17b2f72a0b','宿沈彬進士書院','齊己','唐','唐诗','tang','','[]','相期只爲話篇章，踏雪曾來宿此房。',64,'全唐诗/poet.tang.46000.json','["相期只爲話篇章，踏雪曾來宿此房。", "喧滑盡消城漏滴，窗扉初掩岳茶香。", "舊山春暖生薇蕨，大國塵昏懼殺傷。", "應有太平時節在，寒宵未臥共思量。"]'),
('6df5256e-78af-4c54-9395-007ad3463acf','靜院','齊己','唐','唐诗','tang','','[]','花院相重點破苔，誰心肯此話心灰。',64,'全唐诗/poet.tang.46000.json','["花院相重點破苔，誰心肯此話心灰。", "好風時傍疎篁起，幽鳥晚從何處來？", "筆硯興狂師沈謝，香燈魂斷憶宗雷。", "浮生已問空王了，箭急光陰一任催。"]'),
('a89b1879-338a-4912-a6c6-5e21bac3f4d2','送白處士遊峨嵋','齊己','唐','唐诗','tang','','[]','閑身誰道是羈遊，西指峨嵋碧頂頭。',64,'全唐诗/poet.tang.46000.json','["閑身誰道是羈遊，西指峨嵋碧頂頭。", "琴鶴幾程隨客棹，風霜何處宿龍湫。", "尋僧石磴臨天井，斸藥秋崖倒瀑流。", "莫爲寰瀛多事在，客星相逐不迴休。"]'),
('13e741a2-9c9e-4594-8238-e390d182754c','寄顧蟾處士','齊己','唐','唐诗','tang','','[]','久聞爲客過蒼梧，休說攜家歸鏡湖。',66,'全唐诗/poet.tang.46000.json','["久聞爲客過蒼梧，休說攜家歸鏡湖。", "山水顛狂應盡在，[鬢]毛凋落免貧無。", "和僧搶入雲中峭，帶鶴驅成澗底孤。", "春醉醒來有餘興，因人乞與武陵圖。"]'),
('cc40b164-5d54-419a-acdd-60141cad70a5','懷金陵知舊','齊己','唐','唐诗','tang','','[]','海門相別住荆門，六度秋光兩鬢根。',64,'全唐诗/poet.tang.46000.json','["海門相別住荆門，六度秋光兩鬢根。", "萬象倒心難蓋口，一生無事可傷魂。", "石頭城外青山疊，北固窗前白浪翻。", "盡是共游題版處，有誰惆悵拂苔痕。"]'),
('907749c8-6b53-4587-a4c2-d0ef699e13c8','喜得自牧上人書','齊己','唐','唐诗','tang','','[]','吳都使者泛驚濤，靈一傳書慰毳袍。',64,'全唐诗/poet.tang.46000.json','["吳都使者泛驚濤，靈一傳書慰毳袍。", "別興偶隨雲水遠，知音本自國風高。", "身依閑淡中銷日，髮向清涼處落刀。", "聞著括囊新集了，擬教誰與序離騷。"]'),
('6f2263b7-4acf-4fc8-9c8b-0b64421f5ce0','驚秋','齊己','唐','唐诗','tang','','[]','曉窗驚覺向秋風，萬里心凝淡蕩中。',64,'全唐诗/poet.tang.46000.json','["曉窗驚覺向秋風，萬里心凝淡蕩中。", "池影碎飜紅菡萏，井聲乾落綠梧桐。", "破除閑事渾歸道，銷耗勞生旋逐空。", "妖殺九原狐兔意，豈知丘隴是英雄。"]'),
('408fa9f3-969b-4ced-872d-3c67988c8b9a','聞沈彬赴吳都請辟','齊己','唐','唐诗','tang','','[]','長訝高眠得穩無，果隨徵辟起江湖。',64,'全唐诗/poet.tang.46000.json','["長訝高眠得穩無，果隨徵辟起江湖。", "鴛鴦已列罇罍貴，鷗鶴休懷釣渚孤。", "白日不妨扶漢祚，清才何讓賦吳都。", "可能更憶相尋夜，雪滿諸峯火一爐。"]'),
('8664f8c0-15c3-46f6-a291-12d426efd682','寄江夏仁公','齊己','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','寺閣高連黃鶴樓，簷前檻底大江流。',64,'全唐诗/poet.tang.46000.json','["寺閣高連黃鶴樓，簷前檻底大江流。", "幾因秋霽澄空外，獨爲詩情到上頭。", "白日有餘閑送客，紫衣何啻貴封侯。", "別來多少新吟也，不寄南宗老比丘。"]'),
('9f478fc9-82f5-46bb-a7c2-32c312f2109a','中春林下偶作','齊己','唐','唐诗','tang','','[]','淨境無人可共攜，閑眠未起日光低。',64,'全唐诗/poet.tang.46000.json','["淨境無人可共攜，閑眠未起日光低。", "浮生莫把還丹續，萬事須將至理齊。", "花在月明蝴蝶夢，雨餘山綠杜鵑啼。", "何能向外求攀折，巖桂枝條拂石梯。"]'),
('b1aacbaa-27b9-40c5-8ed4-5708c9b778f7','送劉秀才歸桑水寧覲','齊己','唐','唐诗','tang','','["\u9ec4\u6cb3"]','歸和初喜戢戈矛，乍捧鄉書感去留。',64,'全唐诗/poet.tang.46000.json','["歸和初喜戢戈矛，乍捧鄉書感去留。", "雁序分飛離漢口，鴒原騫翥在鼇頭。", "家鄰紫塞仍千里，路過黃河更幾州。", "應到高堂問安後，却攜文入帝京遊。"]'),
('4f76a711-3d6a-45d4-9385-07bdda535ba5','寄曹松','齊己','唐','唐诗','tang','','[]','舊制新題削復刊，工夫過甚琢琅玕。',64,'全唐诗/poet.tang.46000.json','["舊制新題削復刊，工夫過甚琢琅玕。", "藥中求見黃芽易，詩裏思聞白雪難。", "扣寂頗同心在定，鑿空何止髮衝冠。", "夜來月苦懷高論，數樹霜邊獨傍欄。"]'),
('b6720361-8068-43b2-b768-5be3081a5b31','酬蜀國歐陽學士','齊己','唐','唐诗','tang','','[]','因緣劉表駐經行，又聽西風墮葉聲。',64,'全唐诗/poet.tang.46000.json','["因緣劉表駐經行，又聽西風墮葉聲。", "鶴髮不堪言此世，峨嵋空約在他生。", "已從禪祖參真性，敢向詩家認好名。", "深愧故人憐潦倒，每傳仙語下南荆。"]'),
('0de2b0b9-eec7-4310-b4ee-f9e65aaa0926','寄荆幕孫郎中','齊己','唐','唐诗','tang','','[]','珠履風流憶富春，三千鵷鷺讓精神。',64,'全唐诗/poet.tang.46000.json','["珠履風流憶富春，三千鵷鷺讓精神。", "詩工鑿破清求妙，道論研通白見真。", "四座共推操檄健，一家誰信買書貧。", "別來鄉國魂應斷，劒閣東西盡戰塵。"]'),
('5da58fe6-8dd7-404b-9039-b97f4c1de736','謝王詹事垂訪','齊己','唐','唐诗','tang','','[]','鳥外孤峯未得歸，人間觸類是無機。',64,'全唐诗/poet.tang.46000.json','["鳥外孤峯未得歸，人間觸類是無機。", "方悲鹿軫棲江寺，忽訝軺車降竹扉。", "王澤乍聞譚渙汗，國風那得話玄微。", "應驚老病炎天裏，枯骨肩橫一衲衣。"]'),
('90ba8d2f-0cd0-4b92-a735-9b95b652a47b','題南平後園牡丹','齊己','唐','唐诗','tang','','[]','暖披煙豔照西園，翠幄朱欄護列仙。',64,'全唐诗/poet.tang.46000.json','["暖披煙豔照西園，翠幄朱欄護列仙。", "玉帳笙歌留盡日，瑤臺伴侶待歸天。", "香多覺受風光剩，紅重知含雨露偏。", "上客分明記開處，明年開更勝今年。"]'),
('5b149cbb-8afb-4733-8c81-3b2ddec93ee7','和李書記','齊己','唐','唐诗','tang','','[]','繁極全分青帝功，開時獨占上春風。',64,'全唐诗/poet.tang.46000.json','["繁極全分青帝功，開時獨占上春風。", "吳姬舞雪非真豔，漢后題詩是怨紅。", "遠蜨戀香拋別苑，野鶯銜得出深宮。", "君看萬態當筵處，羞殺薔薇點碎叢。"]'),
('90cd671b-e7d6-44da-98dd-98b545733145','謝孫郎中寄示','齊己','唐','唐诗','tang','','[]','一念禪餘味國風，早因持論偶名公。',64,'全唐诗/poet.tang.46000.json','["一念禪餘味國風，早因持論偶名公。", "久傷琴喪人亡後，忽有雲和雪唱同。", "繩琢靜聞罤象外，是非閑見寂寥中。", "時來日往緣真趣，不覺秋江度塞鴻。"]'),
('bf679d8e-9c66-443b-ba26-8483114622d4','愛吟','齊己','唐','唐诗','tang','','[]','正堪凝思掩禪扃，又被詩魔惱竺卿。',64,'全唐诗/poet.tang.46000.json','["正堪凝思掩禪扃，又被詩魔惱竺卿。", "偶凭窗扉從落照，不眠風雪到殘更。", "皎然未必迷前習，支遁寧非悟後生。", "傳寫會逢精鑒者，也應知是詠閑情。"]'),
('2bbc37d7-649f-4ab0-bb44-d629736310ab','寄懷東林寺匡白監寺','齊己','唐','唐诗','tang','','[]','南岳別來無約後，東林歸住有前緣。',64,'全唐诗/poet.tang.46000.json','["南岳別來無約後，東林歸住有前緣。", "閑搜好句題紅葉，靜斂霜眉對白蓮。", "雁塔影分疎檜月，虎溪聲合幾峯泉。", "修心若似伊耶舍，傳記須添十九賢。"]'),
('b21f9b40-9614-4147-88e6-1feb24e56553','謝人惠十色花牋幷棋子','齊己','唐','唐诗','tang','','[]','陵州棋子浣花牋，深愧攜來自錦州。',64,'全唐诗/poet.tang.46000.json','["陵州棋子浣花牋，深愧攜來自錦州。", "海蚌琢成星落落，吳綾隱出雁翩翩。", "留防桂苑題詩客，惜寄桃源敵手仙。", "捧受不堪思出處，七千餘里劒門前。"]'),
('521f5114-a3ab-4cad-97ca-0ec76f4237a3','夏日寓居寄友人','齊己','唐','唐诗','tang','','[]','北遊兵阻復南還，因寄荆州病掩關。',64,'全唐诗/poet.tang.46000.json','["北遊兵阻復南還，因寄荆州病掩關。", "日月坐銷江上寺，清涼魂斷剡中山。", "披緇影跡堪藏拙，出世身心合向閑。", "多謝扶風大君子，相思時到寂寥間。"]'),
('4d9b4c79-fb34-46de-b9a6-4a5abed3e38a','中秋十四日夜對月上南平主人','齊己','唐','唐诗','tang','','[]','今宵前夕皆堪翫，何必圓時始竭才。',64,'全唐诗/poet.tang.46000.json','["今宵前夕皆堪翫，何必圓時始竭才。", "空說輪中有天子，不知何處是樓臺？", "終憂明夜雲遮却，且埽閑居坐看來。", "玉兔銀蟾似多意，乍臨棠樹影裴回。"]'),
('fa36ef5d-e5f9-40d9-85fb-d73e935d5bec','謝人惠十才子圖','齊己','唐','唐诗','tang','','[]','丹青妙寫十才人，玉峭冰稜姑射神。',64,'全唐诗/poet.tang.46000.json','["丹青妙寫十才人，玉峭冰稜姑射神。", "醉舞離披真鸑鷟，狂吟崩倒瑞麒麟。", "飜騰造化山曾竭，採掇珠璣海幾貧。", "猶得知音與圖畫，草堂閑挂似相親。"]'),
('bcadd6e1-05cf-4e4d-981f-a26d44e49960','荆門病中寄懷鄉人歐陽侍郎彬','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','誰會荆州一老夫，夢勞神役憶匡廬。',64,'全唐诗/poet.tang.46000.json','["誰會荆州一老夫，夢勞神役憶匡廬。", "碧雲雁影紛紛去，黃葉蟾聲漸漸無。", "口淡莫分餐氣味，身羸但覺病肌膚。", "可憐饌玉燒蘭者，肯慰寒偎雪夜爐。"]'),
('44cfe45d-a987-435f-b01e-deeef3e7f9ce','送譚三藏入京','齊己','唐','唐诗','tang','','[]','阿闍梨與佛身同，灌頂難施利濟功。',64,'全唐诗/poet.tang.46000.json','["阿闍梨與佛身同，灌頂難施利濟功。", "持咒力須資運祚，度人心要似虛空。", "東周路踏紅塵裏，北極門瞻紫氣中。", "好進焚文霑帝澤，却歸天策繼真風。"]'),
('1810abca-6fb3-4d0e-be59-160a9dd73336','寄酬秦府高推官輦','齊己','唐','唐诗','tang','','[]','天台衡嶽舊曾尋，閑憶留題白石林。',64,'全唐诗/poet.tang.46000.json','["天台衡嶽舊曾尋，閑憶留題白石林。", "歲月已殘衰颯鬢，風騷猶壯寂寥心。", "緱山碧樹遮藏密，丹穴紅霞掩暎深。", "爭得相逢一攜手，拂衣同去聽玄音。"]'),
('c168defd-466e-442c-b561-10058e26cd1d','敘懷寄高推官','齊己','唐','唐诗','tang','','[]','搜新編舊與誰評，自向無聲認有聲。',64,'全唐诗/poet.tang.46000.json','["搜新編舊與誰評，自向無聲認有聲。", "已覺愛來多廢道，可堪傳去更沽名。", "風松韻裏忘形坐，霜月光中共影行。", "還勝御溝寒夜水，狂吟衝尹甚傷情。"]'),
('951d6b65-df55-4929-b4d9-e04d019257e1','送朱侍御自洛陽歸閬州寧覲','齊己','唐','唐诗','tang','','[]','尋常西望故園時，幾處魂隨落照飛。',64,'全唐诗/poet.tang.46000.json','["尋常西望故園時，幾處魂隨落照飛。", "客路舊縈秦甸出，鄉程今遶漢陽歸。", "已過巫峽沈青靄，忽認峨嵋在翠微。", "從此倚門休望斷，交親喜換老萊衣。"]'),
('ba046639-36e2-4c14-a065-3fd108868e7a','貽惠暹上人','齊己','唐','唐诗','tang','','[]','經論功餘更業詩，又於難裏縱天機。',64,'全唐诗/poet.tang.46000.json','["經論功餘更業詩，又於難裏縱天機。", "吳朝客見投文去，楚國僧迎著紫歸。", "已得聲名先振俗，不妨風雪更探微。", "金陵高憶恩門在，終挂雲帆重一飛。"]'),
('582d1357-8688-4ca3-b140-7d20b9ced881','酬西蜀廣濟大師見寄','齊己','唐','唐诗','tang','','[]','猶得吾師繼頌聲，百篇相愛寄南荆。',64,'全唐诗/poet.tang.46000.json','["猶得吾師繼頌聲，百篇相愛寄南荆。", "卷開錦水霞光爛，吟入峨嵋雪氣清。", "楚外已甘推絕唱，蜀中誰敢共懸衡。", "應憐無可同無本，終向風騷作弟兄。"]'),
('7f26f8f0-41fd-4768-9f0e-d60d22c3cffb','江寺春殘寄幕中知己二首 一','齊己','唐','唐诗','tang','','[]','誰遣西來負岳雲，自由歸去竟何因。',64,'全唐诗/poet.tang.46000.json','["誰遣西來負岳雲，自由歸去竟何因。", "山龕薜荔應殘雪，江寺玫瑰又度春。", "早歲便師無學士，臨年却作有爲人。", "何妨夜醮時相憶，伴醉佯狂笑老身。"]'),
('99401bfe-0dd5-4d61-b9fc-b2dc666ad753','江寺春殘寄幕中知己二首 二','齊己','唐','唐诗','tang','','[]','社蓮慚與幕蓮同，岳寺蕭條儉府雄。',64,'全唐诗/poet.tang.46000.json','["社蓮慚與幕蓮同，岳寺蕭條儉府雄。", "冷淡獨開香火裏，殷妍行列綺羅中。", "秋加玉露何傷白，夜醉金缸不那紅。", "閑憶遺民此心地，一般無染喻真空。"]'),
('806fc8b2-fb8f-4d66-be20-faab4c1100db','寄玉泉實仁上人','齊己','唐','唐诗','tang','','[]','往歲曾尋聖跡時，樹邊三遶禮吾師。',64,'全唐诗/poet.tang.46000.json','["往歲曾尋聖跡時，樹邊三遶禮吾師。", "敢望護法將軍記，且喜焚香弟子知。", "後會未期心的的，前峯欲下步遲遲。", "今來老劣難行甚，空寂無緣但寄詩。"]'),
('4979a8e7-75d5-4633-99a3-6f38efdc40fa','荆渚感懷寄僧達禪弟三首 一','齊己','唐','唐诗','tang','','[]','電擊流年七十三，齒衰氣沮竟何堪。',64,'全唐诗/poet.tang.46000.json','["電擊流年七十三，齒衰氣沮竟何堪。", "誰云有句傳天下，自愧無心寄嶺南。", "曉漱氣嫌通市井，晚烹香憶落雲潭。", "鄰峯道者應彈指，蘚剝藤纏舊石龕。"]'),
('7ad8764d-4748-4f5d-90e3-0784e322f023','荆渚感懷寄僧達禪弟三首 二','齊己','唐','唐诗','tang','','[]','十五年前會虎溪，白蓮齋後便來西。',64,'全唐诗/poet.tang.46000.json','["十五年前會虎溪，白蓮齋後便來西。", "干戈時變信雖絕，吳楚路長魂不迷。", "黃葉喻曾同我悟，碧雲情近與誰攜。", "春殘相憶荆江岸，一隻杜鵑頭上啼。"]'),
('8e8f9d86-5cb7-437a-b9a7-265a786a46eb','荆渚感懷寄僧達禪弟三首 三','齊己','唐','唐诗','tang','','[]','鶴嶺僧來細話君，依前高尚跡難羣。',64,'全唐诗/poet.tang.46000.json','["鶴嶺僧來細話君，依前高尚跡難羣。", "自拋南岳三生石，長傍西山數片雲。", "丹訪葛洪無舊竈，詩尋靈觀有遺文。", "莫將離別爲相隔，心似虛空幾處分。"]'),
('400a774f-d199-449b-9279-798e6ed92337','寄孫魴秀才','齊己','唐','唐诗','tang','','[]','郡樓東面寺牆西，顏子生涯竹屋低。',64,'全唐诗/poet.tang.46000.json','["郡樓東面寺牆西，顏子生涯竹屋低。", "書案飛颺風落絮，地苔狼藉燕銜泥。", "吟窗晚凭春篁密，行徑斜穿夏菜齊。", "別後相思頻夢到，二年同此賦閑題。"]'),
('c2f93c9b-9745-4b23-8bda-1517094ab72b','送李評事往宜春','齊己','唐','唐诗','tang','','[]','蘭舟西去是通津，名郡賢侯下禮頻。',64,'全唐诗/poet.tang.46000.json','["蘭舟西去是通津，名郡賢侯下禮頻。", "山遍寺樓看仰岫，臺連城閣上宜春。", "鴻心夜過鄉心亂，雪韻朝飛句韻新。", "別有官榮身外趣，月江松徑訪禪人。"]'),
('5e9ce2f2-8bfa-462f-8920-4ab9ad7f89a8','中春感興','齊己','唐','唐诗','tang','','[]','春風日日雨時時，寒力潛從暖勢衰。',64,'全唐诗/poet.tang.46000.json','["春風日日雨時時，寒力潛從暖勢衰。", "一氣不言含有象，萬靈何處謝無私。", "詩通物理行堪掇，道合天機坐可窺。", "應是正人持造化，盡驅幽細入罏鎚。"]'),
('7b4e4d7f-0398-4e4e-859b-618fa08481cb','早鶯','齊己','唐','唐诗','tang','','[]','何處經年閟好音，暖風催出囀喬林。',64,'全唐诗/poet.tang.46000.json','["何處經年閟好音，暖風催出囀喬林。", "羽毛新刷陶潛菊，喉舌初調叔夜琴。", "藏雨並棲紅杏密，避人雙入綠楊深。", "曉來枝上千般語，應共桃花說舊心。"]'),
('e9a255c6-6562-489b-9bd2-6f30457faed9','酬尚顏上人','齊己','唐','唐诗','tang','','[]','紫綬蒼髭百歲侵，綠苔芳草遶堦深。',64,'全唐诗/poet.tang.46000.json','["紫綬蒼髭百歲侵，綠苔芳草遶堦深。", "不妨好鳥喧高臥，切忌閑人聒正吟。", "魯鼎寂寥休辨口，劫灰銷變莫宣心。", "還憐我有冥搜癖，時把新詩過竹尋。"]'),
('bd976e08-8954-4be2-9dea-e00bedbf29b7','寄倪署郎中','齊己','唐','唐诗','tang','','[]','風雨冥冥春闇移，紅殘綠滿海棠枝。',64,'全唐诗/poet.tang.46000.json','["風雨冥冥春闇移，紅殘綠滿海棠枝。", "帝鄉久別江鄉住，椿笋何如櫻笋時。", "海內擅名君作賦，林間外學我爲詩。", "近聞南國升南省，應笑無機老病師。"]'),
('5c695097-e927-4739-81f5-d5364d905608','題鄭郎中谷仰山居','齊己','唐','唐诗','tang','','[]','簷壁層層映水天，半乘岡壠半民田。',64,'全唐诗/poet.tang.46000.json','["簷壁層層映水天，半乘岡壠半民田。", "王維愛甚難拋畫，支遁憐多不惜錢。", "巨石盡含金玉氣，亂峯深鎖棟梁煙。", "秦爭漢奪虛勞力，却是巢由得穩眠。"]'),
('43840e11-48c5-411c-ac5e-b0ee437e3c21','湘中寓居春日感懷','齊己','唐','唐诗','tang','','[]','江禽野獸兩堪傷，避射驚彈各自忙。',64,'全唐诗/poet.tang.46000.json','["江禽野獸兩堪傷，避射驚彈各自忙。", "頭角任多無獬豸，羽毛雖衆讓鴛鴦。", "落苔紅小櫻桃熟，侵井青纖燕麥長。", "吟把離騷憶前事，汨羅春浪撼殘陽。"]'),
('80b06d39-4ae9-4450-a21d-3c14001091dd','瀟湘','齊己','唐','唐诗','tang','','[]','寒清健碧遠相含，珠媚根源在極南。',64,'全唐诗/poet.tang.46000.json','["寒清健碧遠相含，珠媚根源在極南。", "流古遰今空作島，逗山衝壁自爲潭。", "遷來賈誼愁無限，謫過靈均恨不堪。", "畢竟輸他老漁叟，綠蓑青竹釣濃藍。"]'),
('860aeae7-09cc-4d42-b8be-ecef133560d3','寄友生','齊己','唐','唐诗','tang','','[]','風騷情味近如何，門底寒流屋裏莎。',64,'全唐诗/poet.tang.46000.json','["風騷情味近如何，門底寒流屋裏莎。", "曾摘園蔬留我宿，共吟江月看鴻過。", "時危苦恨無收拾，道妙深誇有琢磨。", "涼夜欹眠應得夢，平生心肺似君多。"]'),
('9394cbf8-1ee7-4817-958b-97ad57239d6a','酬荅退上人','齊己','唐','唐诗','tang','','[]','鬚鬢三分白二分，一生蹤跡出人羣。',64,'全唐诗/poet.tang.46000.json','["鬚鬢三分白二分，一生蹤跡出人羣。", "嵩丘夢憶諸峰雪，衡岳禪依五寺雲。", "青衲幾臨高瀑濯，苦吟曾許斷猿聞。", "荒村殘臘相逢夜，月滿鴻多楚水濆。"]'),
('6cf026d9-3101-406e-965b-c9f3862712e0','山中春懷','齊己','唐','唐诗','tang','','[]','心魂役役不曾歸，萬象相牽向極微。',64,'全唐诗/poet.tang.46000.json','["心魂役役不曾歸，萬象相牽向極微。", "所得或憂逢郢刃，凡言皆欲奪天機。", "遊深晚谷香充鼻，坐苦春松粉滿衣。", "何物不爲狼籍境，桃花和雨更霏霏。"]'),
('19e855e5-4949-43d9-bcbd-7247f31e73a3','寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','上國誰傳消息過，醉眠醒坐對嵯峨。',64,'全唐诗/poet.tang.46000.json','["上國誰傳消息過，醉眠醒坐對嵯峨。", "身離道士衣裳少，筆荅禪師句偈多。", "南岸郡鐘涼度枕，西齋竹露冷霑莎。", "還應笑我降心外，惹得詩魔助佛魔。"]'),
('a312852c-7859-4f22-bafe-ff04554d45ba','寄萍鄉唐稟正字','齊己','唐','唐诗','tang','','[]','新書聲價滿皇都，高臥林中更起無。',64,'全唐诗/poet.tang.46000.json','["新書聲價滿皇都，高臥林中更起無。", "春興酒香薰肺腑，夜吟雲氣濕髭鬚。", "同登水閣僧皆別，共上漁船鶴亦孤。", "長憶前年送行處，洞門殘日照菖蒲。"]'),
('8e247f7c-b878-4168-96ea-d364fd243edf','秋夕書懷','齊己','唐','唐诗','tang','','[]','涼多夜永擁山袍，片石閑欹不覺勞。',64,'全唐诗/poet.tang.46000.json','["涼多夜永擁山袍，片石閑欹不覺勞。", "蟋蟀遶牀無夢寐，梧桐滿地有蕭騷。", "平生樂道心常切，五字逢人價合高。", "破落西窗向殘月，露聲如雨滴蓬蒿。"]'),
('a0206127-03ce-48da-943d-3bffc19062ce','亂後經西山寺','齊己','唐','唐诗','tang','','[]','松燒寺破是刀兵，谷變陵遷事可驚。',64,'全唐诗/poet.tang.46000.json','["松燒寺破是刀兵，谷變陵遷事可驚。", "雲裏乍逢新住主，石邊重認舊題名。", "閑臨菡萏荒池坐，亂踏鴛鴦破瓦行。", "欲伴高僧重結社，此身無計捨前程。"]'),
('e997d2b3-1b23-438e-8b44-be0ac1858921','題梁賢巽公房','齊己','唐','唐诗','tang','','[]','吳王廟側有高房，簾影南軒日正長。',64,'全唐诗/poet.tang.46000.json','["吳王廟側有高房，簾影南軒日正長。", "吹苑野風桃葉碧，壓畦春露菜花黃。", "懸燈向後惟冥默，凭案前頭即渺茫。", "知有虎溪歸夢切，寺門松折社僧亡。"]'),
('805df3c2-f7b3-4bfe-a0d4-ded719d46c26','塘上閑作','齊己','唐','唐诗','tang','','[]','閑行閑坐藉莎煙，此興堪思二古賢。',64,'全唐诗/poet.tang.46000.json','["閑行閑坐藉莎煙，此興堪思二古賢。", "陶靖節居彭澤畔，賀知章在鏡池邊。", "鴛鴦著對能飛繡，菡萏成羣不語仙。", "形影騰騰夕陽裏，數峰危翠滴漁船。"]'),
('0901d774-7d42-4120-86ea-de20528ed4de','江上望遠山寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','危碧層層映水天，半垂岡隴下民田。',64,'全唐诗/poet.tang.46000.json','["危碧層層映水天，半垂岡隴下民田。", "王維愛甚難拋畫，支遁高多不惜錢。", "巨石盡含金玉氣，亂峰閑鎖棟梁煙。", "秦爭漢奪空勞力，却是巢由得穩眠。"]'),
('e8155a25-b507-4e55-92ac-506392a73bce','送人自蜀迴南遊','齊己','唐','唐诗','tang','','[]','錦水東浮情尚鬱，湘波南泛思何長。',64,'全唐诗/poet.tang.46000.json','["錦水東浮情尚鬱，湘波南泛思何長。", "蜀魂巴狖悲殘夜，越鳥燕鴻叫夕陽。", "煙月幾般爲客路，林泉四絕是吾鄉。", "尋幽必有僧相指，宋杜題詩近舊房。"]'),
('b4bc6da1-63ce-4931-84ba-8f6f8072fa3d','寄无願上人','齊己','唐','唐诗','tang','','[]','六十八去七十歲，與師年鬢不爭多。',66,'全唐诗/poet.tang.46000.json','["六十八去七十歲，與師年鬢不爭多。", "誰言生死無消處，還有修行那得何。", "開士安能窮好惡，故人堪憶舊經過。", "會歸原上焚身後，一陣灰飛也[任他]。"]'),
('f40f92df-1a70-465c-b207-fcf98cadc0e3','懷瀟湘即事寄友人','齊己','唐','唐诗','tang','','[]','浸野淫空澹蕩和，十年鄰住聽漁歌。',64,'全唐诗/poet.tang.46000.json','["浸野淫空澹蕩和，十年鄰住聽漁歌。", "城臨遠櫂浮煙泊，寺近閑人泛月過。", "岸引綠蕪春雨細，汀連斑竹晚風多。", "可憐千古懷沙處，還有魚龍弄白波。"]'),
('5918924b-3b3b-4a58-a8b4-d2a106f59290','謝橘洲人寄橘','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭栽種似瀟湘，綠遶人家帶夕陽。',64,'全唐诗/poet.tang.46000.json','["洞庭栽種似瀟湘，綠遶人家帶夕陽。", "霜裛露蒸千樹熟，浪圍風撼一洲香。", "洪崖遣後名何遠，陸績懷來事更長。", "藏貯待供賓客好，石榴宜稱映舟光。"]'),
('f5128fc6-ddea-4359-be1f-134f9ed9151d','自貽','齊己','唐','唐诗','tang','','[]','心中身外更何猜，坐石看雲養聖胎。',64,'全唐诗/poet.tang.46000.json','["心中身外更何猜，坐石看雲養聖胎。", "名在好詩誰逐去，跡依閑處自歸來。", "時添瀑布新缾水，旋換旃檀舊印灰。", "晴出寺門驚往事，古松千尺半蒼苔。"]'),
('ab60a4e1-93e8-453e-9055-f5a9abe51740','寄益上人','齊己','唐','唐诗','tang','','[]','長想尋君道路遙，亂山霜後火新燒。',64,'全唐诗/poet.tang.46000.json','["長想尋君道路遙，亂山霜後火新燒。", "近聞移住鄰衡岳，幾度題詩上石橋。", "古木傳聲連峭壁，一燈懸影過中宵。", "風騷味薄誰相愛，攲枕常多夢鮑昭。"]'),
('8d5a9149-b703-4f7d-8467-a2f1b61e2ccc','行次宜春寄湘西諸友','齊己','唐','唐诗','tang','','[]','幸無名利路相迷，雙履尋山上柏梯。',66,'全唐诗/poet.tang.46000.json','["幸無名利路相迷，雙履尋山上柏梯。", "衣鉢祖辭梅嶺外，香燈社別橘洲西。", "雲中石壁青[侵]漢，樹下苔錢綠遶溪。", "我愛遠遊君愛住，此心他約與誰攜。"]'),
('c49308e2-1a42-4536-8c4a-30189e7a85ec','送略禪者歸南岳','齊己','唐','唐诗','tang','','[]','林下鐘殘又拂衣，錫聲還獨向南飛。',66,'全唐诗/poet.tang.46000.json','["林下鐘殘又拂衣，錫聲還獨向南飛。", "千峰[冷]截冥鴻處，一徑險通禪客歸。", "青石上行苔片片，古杉邊宿雨霏霏。", "勞生有願應回首，忍著無心與物違。"]'),
('ff9b89c8-455b-445a-b3e3-792d1276e899','詠懷寄知己','齊己','唐','唐诗','tang','','[]','已得浮生到老閑，且將新句擬玄關。',64,'全唐诗/poet.tang.46000.json','["已得浮生到老閑，且將新句擬玄關。", "自知清興來無盡，誰道淳風去不還。", "三百正聲傳世後，五千真理在人間。", "此心終待相逢說，時復登樓看暮山。"]'),
('1a72a217-0b56-475e-85b5-3c2dab844dde','寄吳拾遺','齊己','唐','唐诗','tang','','[]','新竹將誰搉重輕，皎然評裏見權衡。',64,'全唐诗/poet.tang.46000.json','["新竹將誰搉重輕，皎然評裏見權衡。", "非無苦到難搜處，合有清垂不朽名。", "疎雨晚衝蓮葉響，亂蟬涼抱檜梢鳴。", "野橋閑背殘陽立，翻憶蘇卿送子卿。"]'),
('1c4f9662-7fe7-4c15-9ce6-c1a39528e475','春晴感興','齊己','唐','唐诗','tang','','[]','連旬陰翳曉來晴，水滿圓塘照日明。',64,'全唐诗/poet.tang.46000.json','["連旬陰翳曉來晴，水滿圓塘照日明。", "岸草短長邊過客，江花紅白裏啼鶯。", "野無征戰時堪望，山有樓臺煖好行。", "桑柘依依禾黍綠，可憐歸去是張衡。"]'),
('89b6b63f-7899-416d-9c27-e2f8e0848bb8','謝道友拄杖','齊己','唐','唐诗','tang','','[]','翦自南巖瀑布邊，寒光七尺乳珠連。',64,'全唐诗/poet.tang.46000.json','["翦自南巖瀑布邊，寒光七尺乳珠連。", "持來未入塵埃路，乞與應憐老病年。", "欹影夜歸青石澗，卓痕秋過綠苔錢。", "他時攜上嵩峰頂，把倚長松看洛川。"]'),
('9e806ac8-3084-46ee-8530-630623ad4d0c','東林寄別修睦上人','齊己','唐','唐诗','tang','','[]','行心乞得見秋風，雙履難留去住蹤。',64,'全唐诗/poet.tang.46000.json','["行心乞得見秋風，雙履難留去住蹤。", "紅葉正多離社客，白雲無限向嵩峰。", "囊中自欠詩千首，身外誰知事幾重。", "此別不能爲後約，年華相似逼衰容。"]'),
('50cd4ba1-47b5-476b-9b7c-1b3bba01cad6','夏日原西避暑寄吟友','齊己','唐','唐诗','tang','','[]','熱煙疎竹古原西，日日乘涼此杖藜。',64,'全唐诗/poet.tang.46000.json','["熱煙疎竹古原西，日日乘涼此杖藜。", "閑處雨聲隨霹靂，旱田人望隔虹霓。", "蟬依獨樹乾吟苦，鳥憶平川渴過齊。", "別有相招好泉石，瑞花瑤草盡堪攜。"]'),
('78c0e5b9-fe24-41b2-9e32-b5664a0d12e2','懷匡阜','齊己','唐','唐诗','tang','','[]','荆州連歲滯遊方，拄杖塵封六尺光。',64,'全唐诗/poet.tang.46000.json','["荆州連歲滯遊方，拄杖塵封六尺光。", "洗面有香思石溜，冥心無撓憶山牀。", "閑機但媿時機速，靜論須慙世論長。", "昨夜分明夢歸去，薜蘿幽逕遶禪房。"]'),
('b46a564e-934c-4423-9127-c214763a059c','靜坐','齊己','唐','唐诗','tang','','[]','繩牀欹坐任崩頹，雙眼醒醒閉復開。',64,'全唐诗/poet.tang.46000.json','["繩牀欹坐任崩頹，雙眼醒醒閉復開。", "日月更無閑裏過，風騷時有靜中來。", "天真自得生難捨，世幻誰驚死不迴。", "何處堪投此蹤跡，水邊晴去上高臺。"]'),
('422fca69-2b55-4658-a4ef-6bd53f89d2d1','寄湘中諸友','齊己','唐','唐诗','tang','','[]','碧雲諸友盡黃眸，石點花飛更說無。',64,'全唐诗/poet.tang.46000.json','["碧雲諸友盡黃眸，石點花飛更說無。", "嵐翠濕衣松接院，芙蓉薰面寺臨湖。", "沃洲高臥心何僻，匡社長禪興亦孤。", "爭似楚王文物國，金鑣紫綬讓前途。"]'),
('7a78089b-83ca-4aef-ba3f-db272023bc30','荅无願上人書','齊己','唐','唐诗','tang','','[]','鄭生驅蹇峴山迴，傳得安公好信來。',64,'全唐诗/poet.tang.46000.json','["鄭生驅蹇峴山迴，傳得安公好信來。", "千里阻修俱老骨，八行重疊慰寒灰。", "春殘桃李猶開戶，雪滿松杉始上臺。", "必有南遊山水興，漢江平穩好浮杯。"]'),
('00752ffe-f56c-4cb1-9370-0488dd1736e0','送胤公歸闕','齊己','唐','唐诗','tang','','[]','西朝歸去見高情，應戀香燈近聖明。',64,'全唐诗/poet.tang.46000.json','["西朝歸去見高情，應戀香燈近聖明。", "關令莫疑非馬辯，道安還跨赤驢行。", "充齋野店蔬無味，灑笠平原雪有聲。", "忍惜文章便閑得，看他趨競取時名。"]'),
('9c0f6275-b20c-4e76-9a42-76124ee2be99','感時','齊己','唐','唐诗','tang','','[]','忽忽枕前蝴蝶夢，悠悠覺後利名塵。',64,'全唐诗/poet.tang.46000.json','["忽忽枕前蝴蝶夢，悠悠覺後利名塵。", "無窮今日明朝事，有限生來死去人。", "終與狐狸爲窟穴，謾師龜鶴養精神。", "可憐顏子能消息，虛室坐忘心最真。"]'),
('fc0442bb-141a-4a4d-b9db-c6f43e689ae6','湖上逸人','齊己','唐','唐诗','tang','','[]','澹蕩光中翡翠飛，田田初出柳絲絲。',64,'全唐诗/poet.tang.46000.json','["澹蕩光中翡翠飛，田田初出柳絲絲。", "吟沿綠島時逢鶴，醉泛清波或見龜。", "七澤釣師應識我，中原逐鹿不知誰。", "秋風水寺僧相近，一徑蘆花到竹籬。"]'),
('2f478b21-d349-4d73-b9f1-1b95f0c00dca','懷巴陵','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','垂白堪思大亂前，薄遊曾駐洞庭邊。',64,'全唐诗/poet.tang.46000.json','["垂白堪思大亂前，薄遊曾駐洞庭邊。", "尋僧古寺沿沙岸，倚杖殘陽落水天。", "蘭蘂蔫菸騷客廟，煙波晴闊釣師船。", "此時欲買君山住，嬾就商人乞箇錢。"]'),
('d0897db5-c1ed-4ddd-b043-1e508d81712e','渚宮謝楊秀才自嵩山相訪','齊己','唐','唐诗','tang','','[]','嵩峰有客遠相尋，塵滿麻衣袖苦吟。',64,'全唐诗/poet.tang.46000.json','["嵩峰有客遠相尋，塵滿麻衣袖苦吟。", "花盡草長方閉戶，道孤身老正傷心。", "紅堆落日雲千仞，碧撼涼風竹一林。", "惆悵雅聲消歇去，喜君聊此暫披襟。"]'),
('28c497eb-4a9e-46ad-9420-d1cd8e72a57e','荆門寄沈彬','齊己','唐','唐诗','tang','','[]','罷趨明聖嬾從知，鶴氅褵褷遂性披。',64,'全唐诗/poet.tang.46000.json','["罷趨明聖嬾從知，鶴氅褵褷遂性披。", "道有靜君堪托迹，詩無賢子擬傳誰。", "松聲白日邊行止，日影紅霞裏夢思。", "珍重兩篇千里達，去年江上雪飛時。"]'),
('1c7179df-f20d-4bfe-ae79-218891f3dd0b','讀陰符經','齊己','唐','唐诗','tang','','[]','遶窗風竹骨輕安，閑借陰符仰臥看。',64,'全唐诗/poet.tang.46000.json','["遶窗風竹骨輕安，閑借陰符仰臥看。", "絕利一源真有謂，空勞萬卷是無端。", "清虛可保昇雲易，嗜慾終知入聖難。", "三要洞開何用閉，高臺時去凭欄干。"]'),
('0cec80ce-9fd4-4421-a6d2-15b9a4f6a102','寄吳國知舊','齊己','唐','唐诗','tang','','[]','淮甸當年憶旅遊，衲衣椶笠外何求。',64,'全唐诗/poet.tang.46000.json','["淮甸當年憶旅遊，衲衣椶笠外何求。", "城中古巷尋詩客，橋上殘陽背酒樓。", "晴色水雲天合影，晚聲名利市爭頭。", "可憐王化融融裏，惆悵無僧似惠休。"]'),
('3c29e843-3fe1-4dd8-b105-ab9db3d94806','移居','齊己','唐','唐诗','tang','','[]','上台言任養疎愚，乞與西城水滿湖。',64,'全唐诗/poet.tang.46000.json','["上台言任養疎愚，乞與西城水滿湖。", "吹榻好風終日有，趂涼閑客片時無。", "檀欒翠擁清蟬在，菡萏紅殘白鳥孤。", "欲問存思搜抉妙，幾聯詩許敵三都。"]'),
('57185aa8-e155-45d7-8869-e5c9c758202d','喜彬上人見訪','齊己','唐','唐诗','tang','','[]','高吟欲繼沃州師，千里相尋問課虛。',64,'全唐诗/poet.tang.46000.json','["高吟欲繼沃州師，千里相尋問課虛。", "殘臘江山行盡處，滿衣風雪到閑居。", "攜來律韻清何甚，趣入幽微旨不疎。", "莫惜天機細搥琢，他時終可擬芙蕖。"]'),
('c200b097-3c92-4d31-bc8f-0f6e9ba5b4d6','荆州新秋寺居寫懷詩五首上南平王 一','齊己','唐','唐诗','tang','','[]','竹如翡翠侵簾影，苔學琉璃布地紋。',64,'全唐诗/poet.tang.46000.json','["竹如翡翠侵簾影，苔學琉璃布地紋。", "高臥更無如此樂，遠遊何必愛他雲。", "閑聽謝朓吟爲政，靜看蕭何坐致君。", "只恐老身衰朽速，他年不得頌鴻勳。"]'),
('0634b87b-4642-4eb5-b515-d20343955284','荆州新秋寺居寫懷詩五首上南平王 二','齊己','唐','唐诗','tang','','[]','井梧黃落暮蟬清，久駐金臺但暗驚。',64,'全唐诗/poet.tang.46000.json','["井梧黃落暮蟬清，久駐金臺但暗驚。", "事佛未憐諸弟子，談空爭動上公卿。", "合歸鳥外藏幽跡，敢向人前認好名。", "滿印白檀燈一醆，可能酬謝得聰明。"]'),
('cea97cf1-bab7-4002-b648-ce7b36e5eaba','荆州新秋寺居寫懷詩五首上南平王 三','齊己','唐','唐诗','tang','','[]','金湯裏面境何求，寶殿東邊院最幽。',64,'全唐诗/poet.tang.46000.json','["金湯裏面境何求，寶殿東邊院最幽。", "栽種已添新竹影，畫圖兼列遠山秋。", "形容豈合親公子，章句爭堪狎士流。", "虛負岷峨老僧約，年年雪水下汀洲。"]'),
('8ebaa588-df7d-43c9-9473-34a544be9b7c','荆州新秋寺居寫懷詩五首上南平王 四','齊己','唐','唐诗','tang','','[]','漢江西岸蜀江東，六稔安禪教化中。',64,'全唐诗/poet.tang.46000.json','["漢江西岸蜀江東，六稔安禪教化中。", "託跡幸將王粲別，歸心寧與子山同。", "尊罍豈識曹參酒，賓客還親宋玉風。", "又見去年三五夕，一輪寒魄破煙空。"]'),
('02671a74-c809-4b0d-bda5-9c0c13a0cbc7','荆州新秋寺居寫懷詩五首上南平王 五','齊己','唐','唐诗','tang','','[]','石龕閑鎖舊居峰，何事膺門歲月重。',64,'全唐诗/poet.tang.46000.json','["石龕閑鎖舊居峰，何事膺門歲月重。", "五七詩中叨見遇，三千客外許疎慵。", "迎涼蟋蟀喧閑思，積雨莓苔沒屐蹤。", "會待英雄啓金口，却教擔錫入雲松。"]'),
('9ee9828b-0fac-4fad-8102-580d2f6b32ce','送李秀才歸湘中','齊己','唐','唐诗','tang','','[]','詞客攜文訪病夫，因吟送別憶湘湖。',64,'全唐诗/poet.tang.46000.json','["詞客攜文訪病夫，因吟送別憶湘湖。", "寒消浦溆催鴻鴈，暖入溪山養鷓鴣。", "僧向月中尋岳麓，雲從城上去蒼梧。", "君歸爲問峰前寺，舊住僧房鎖在無。"]'),
('06bc7707-ca57-457a-a9d9-4ae5e76d1e27','寄吳國西供奉','齊己','唐','唐诗','tang','','[]','別來相憶夢多迷，君住東朝我楚西。',64,'全唐诗/poet.tang.46000.json','["別來相憶夢多迷，君住東朝我楚西。", "瑤闕合陪龍象位，春山休記鷓鴣啼。", "承恩位與千官別，應制才將十子齊。", "幾笑遠公慵送客，慇懃只到寺前溪。"]'),
('c9426817-cbbc-4a85-b69e-8cb396095c43','謝人惠端溪硯','齊己','唐','唐诗','tang','','[]','端人鑿斷碧溪潯，善價爭教惜萬金。',64,'全唐诗/poet.tang.46000.json','["端人鑿斷碧溪潯，善價爭教惜萬金。", "礱琢已曾經敏手，研磨終見透堅心。", "安排得主難移動，含貯隨時任淺深。", "保重更求裝鈿匣，閑將濡染寄知音。"]'),
('ed98061e-db22-4793-80dc-2f01955f9e9a','送吳先輩赴京','齊己','唐','唐诗','tang','','[]','煙霄已遂明經第，江漢重來問苦吟。',64,'全唐诗/poet.tang.46000.json','["煙霄已遂明經第，江漢重來問苦吟。", "託興偶憑風月遠，忘機終在寂寥深。", "千篇未聽常徒口，一字須防作者心。", "此日與君聊話別，老身難約更相尋。"]'),
('3ceeb434-dc8e-4b20-ae8b-6a151e4f762e','和西蜀可準大師遠寄之什','齊己','唐','唐诗','tang','','[]','莫知何路去追攀，空想人間出世間。',64,'全唐诗/poet.tang.46000.json','["莫知何路去追攀，空想人間出世間。", "杜口已同居士室，傳心休問祖師山。", "禪中不住方爲定，說處無生始是閑。", "珍重希音遠相寄，亂峰西望疊孱顏。"]'),
('aa96314f-39bf-4ecc-8319-cf8aa39fceb7','荆門暮冬與節公話別','齊己','唐','唐诗','tang','','[]','漳河湘岸柳關頭，離別相逢四十秋。',64,'全唐诗/poet.tang.46000.json','["漳河湘岸柳關頭，離別相逢四十秋。", "我憶黃梅夢南國，君懷明主去東周。", "幾程霜雪經殘臘，何處封疆過舊遊。", "好及春風承帝澤，莫忘衰朽臥林丘。"]'),
('c9e99678-f359-4705-a24e-76d33876b05c','賀孫支使郎中遷居','齊己','唐','唐诗','tang','','[]','別認公侯禮上才，築金何啻舊燕臺。',64,'全唐诗/poet.tang.46000.json','["別認公侯禮上才，築金何啻舊燕臺。", "地連東閣橫頭買，門對西園正面開。", "不隔紅塵趨棨戟，只拖珠履赴尊罍。", "應逢明月清霜夜，閑領笙歌宴此來。"]'),
('0942ddd7-e853-4d06-90a9-d4b6d7d0a753','庭際新移松竹','齊己','唐','唐诗','tang','','[]','三莖瘦竹兩株松，瑟瑟翛翛韻且同。',64,'全唐诗/poet.tang.46000.json','["三莖瘦竹兩株松，瑟瑟翛翛韻且同。", "抱節乍離新澗雪，盤根遠別舊林風。", "歲寒相倚無塵地，蔭影分明有月中。", "更待陽和信催促，碧梢青杪看凌空。"]'),
('a5437149-3579-42fe-b4ef-7073774c942b','荆門寄題禪月大師影堂','齊己','唐','唐诗','tang','','[]','澤國聞師泥日後，蜀王全禮葬餘灰。',64,'全唐诗/poet.tang.46000.json','["澤國聞師泥日後，蜀王全禮葬餘灰。", "白蓮塔向清泉鎖，禪月堂臨錦水開。", "西岳千篇傳古律，南宗一句印靈臺。", "不堪隻履還西去，葱嶺如今無使迴。"]'),
('e28aa6b6-1d1e-4c32-84c5-01a7ce57690e','賀雪','齊己','唐','唐诗','tang','','[]','上清凝結下乾坤，爲瑞爲祥表致君。',64,'全唐诗/poet.tang.46000.json','["上清凝結下乾坤，爲瑞爲祥表致君。", "日月影從光外過，山河形向靜中分。", "歌揚郢路誰同聽，聲灑梁園客共聞。", "堪想畫堂簾卷次，輕隨舞袖正紛紛。"]'),
('47b20531-9fb9-43cf-a7c4-35ca1cfa60e2','荆州寄貫微上人','齊己','唐','唐诗','tang','','[]','舊齋休憶對松關，各在王侯顧遇間。',64,'全唐诗/poet.tang.46000.json','["舊齋休憶對松關，各在王侯顧遇間。", "命服已霑天渥澤，衲衣猶擁祖斕斑。", "相思莫救燒心火，留滯難移壓腦山。", "得失兩途俱不是，笑他高臥碧孱顏。"]'),
('8481a319-3e97-417e-b80c-80ef3c3be2d6','送休師歸長沙寧覲','齊己','唐','唐诗','tang','','[]','高堂親老本師存，多難長懸兩處魂。',64,'全唐诗/poet.tang.46000.json','["高堂親老本師存，多難長懸兩處魂。", "已說戰塵消漢口，便隨征櫂別荆門。", "晴吟野闊無耕地，晚宿灣深有釣村。", "他日更思衰老否，七年相伴琢詩言。"]'),
('09b794d3-9891-42ce-963a-6956af4a4974','江上夏日','齊己','唐','唐诗','tang','','[]','無處清陰似剡溪，火雲奇崛倚空齊。',64,'全唐诗/poet.tang.46000.json','["無處清陰似剡溪，火雲奇崛倚空齊。", "千山冷疊湖光外，一扇涼搖楚色西。", "碧樹影疎風易斷，綠蕪平遠日難低。", "故園舊寺臨湘水，斑竹煙深越鳥啼。"]'),
('0be9ef35-add8-4d77-b340-74a6c1434f42','渚宮春日因懷有作','齊己','唐','唐诗','tang','','[]','舊業樹連湘樹遠，家山雲與嶽雲平。',64,'全唐诗/poet.tang.46000.json','["舊業樹連湘樹遠，家山雲與嶽雲平。", "僧來已說無耕釣，鴈去那知有弟兄。", "客思莫牽蝴蝶夢，鄉心自憶鷓鴣聲。", "沙頭南望堪腸斷，誰把歸舟載我行。"]'),
('ee1819e9-bcc9-4e19-91eb-a7459e2d9ab6','松化爲石','齊己','唐','唐诗','tang','','[]','盤根幾聳翠崖前，却偃凌雲化至堅。',64,'全唐诗/poet.tang.46000.json','["盤根幾聳翠崖前，却偃凌雲化至堅。", "乍結精華齊永劫，不隨凋變已千年。", "逢賢必用鐫辭立，遇聖終將刻印傳。", "肯似荆山鑿餘者，蘚封頑滯臥嵐煙。"]'),
('9359c006-efa4-4fe7-b5d3-8fca624a8ae1','寄澧陽吳使君','齊己','唐','唐诗','tang','','[]','南客西來話使君，涔陽風雨變行春。',64,'全唐诗/poet.tang.46000.json','["南客西來話使君，涔陽風雨變行春。", "四鄰耕釣趨仁政，千里煙花壓路塵。", "去獸未勝除狡吏，還珠爭似復逋民。", "紅蘭浦暖攜才子，爛醉連題賦白蘋。"]'),
('aedb4818-0a73-498a-bc4c-2f2819f92180','湘江送客','齊己','唐','唐诗','tang','','[]','湘江秋色湛如冰，楚客離懷暮不勝。',64,'全唐诗/poet.tang.46000.json','["湘江秋色湛如冰，楚客離懷暮不勝。", "千里碧雲聞塞鴈，幾程青草見巴陵。", "寒濤響疊晨征樐，岸葦叢明夜泊燈。", "鸚鵡洲邊若回首，爲思前事一捫膺。"]'),
('6bc4c6a4-b467-4081-a690-5506b0e4ef86','暮遊岳麓寺','齊己','唐','唐诗','tang','','[]','寺樓高出碧崖稜，城裏誰知在上層。',64,'全唐诗/poet.tang.46000.json','["寺樓高出碧崖稜，城裏誰知在上層。", "初雪灑來喬木暝，遠禽飛過大江澄。", "閑消不睡憐長夜，靜照無言謝一燈。", "迴首何邊是空地，四村桑麥遍丘陵。"]'),
('786007f1-0304-4231-92c6-205172c3c6e9','林下留別道友','齊己','唐','唐诗','tang','','[]','住亦無依去是閑，何心終戀此林間。',64,'全唐诗/poet.tang.46000.json','["住亦無依去是閑，何心終戀此林間。", "片雲孤鶴東西路，四海九州多少山。", "靜坐趁涼移樹影，興隨題處著苔斑。", "秋來洗浣行衣了，還爾鄰僧舊竹關。"]'),
('2989cae6-17f2-4307-b616-d08e8645325c','道林寺居寄岳麓禪師二首 一','齊己','唐','唐诗','tang','','[]','門前石路徹中峰，樹影泉聲在半空。',64,'全唐诗/poet.tang.46000.json','["門前石路徹中峰，樹影泉聲在半空。", "尋去未應勞上下，往來殊已倦西東。", "髭根盡白孤雲並，心跡全忘片月同。", "長憶高窗夏天裏，古松青檜午時風。"]'),
('f85ba725-3ce0-4d6c-be80-8870ff1300f1','道林寺居寄岳麓禪師二首 二','齊己','唐','唐诗','tang','','[]','山袍不稱下紅塵，各是閑居島外身。',64,'全唐诗/poet.tang.46000.json','["山袍不稱下紅塵，各是閑居島外身。", "兩處煙霞門寂寂，一般苔蘚石磷磷。", "禪關悟後寧疑物，詩格玄來不傍人。", "月照經行更誰見，露華松粉點衣巾。"]'),
('cb5a8a7b-3a52-49f5-9668-d1b23be22207','亂後江西過孫魴舊居因寄','齊己','唐','唐诗','tang','','[]','舊遊重到倍悲涼，吟憶同人倚寺牆。',64,'全唐诗/poet.tang.46000.json','["舊遊重到倍悲涼，吟憶同人倚寺牆。", "何處暮蟬喧逆旅，此中山鳥噪垂楊。", "寰區有主權兵器，風月無人掌桂香。", "欲寄此心空北望，塞鴻天末失歸行。"]'),
('c185b257-7c7a-4910-a29c-368417fb5345','宜春江上寄仰山長老二首 一','齊己','唐','唐诗','tang','','[]','水隔孤城城隔山，水邊時望憶師閑。',64,'全唐诗/poet.tang.46000.json','["水隔孤城城隔山，水邊時望憶師閑。", "清泉白日中峰上，落日半空栖鳥還。", "雲影觸衣分朵朵，雨聲吹磬散潺潺。", "傳心莫學羅浮去，後輩思量待扣關。"]'),
('25e3d347-bc4f-4ed2-93d2-e3167b608fa6','宜春江上寄仰山長老二首 二','齊己','唐','唐诗','tang','','[]','雨晴天半碧光流，影倒殘陽濕郡樓。',64,'全唐诗/poet.tang.46000.json','["雨晴天半碧光流，影倒殘陽濕郡樓。", "絕頂有人經劫在，浮生無客暫時遊。", "窗開萬壑春泉亂，塔鎖孤燈萬木稠。", "欲爲吾師拂衣去，白雲紅葉又新秋。"]'),
('d51cab45-a2b4-4fc5-8cc0-14a2db2e0eb3','螢','齊己','唐','唐诗','tang','','[]','透窗穿竹住還移，萬類俱閑始見伊。',64,'全唐诗/poet.tang.46000.json','["透窗穿竹住還移，萬類俱閑始見伊。", "難把寸光藏暗室，自持孤影助明時。", "空庭散逐金風起，亂葉爭投玉露垂。", "後代儒生懶收拾，夜深飛過讀書帷。"]'),
('3582f0b1-a468-4cd5-9fa1-97c91524e890','湘中送翁員外歸閩','齊己','唐','唐诗','tang','','[]','船滿琴書與酒杯，清湘影裏片帆開。',64,'全唐诗/poet.tang.46000.json','["船滿琴書與酒杯，清湘影裏片帆開。", "人歸南國鄉園去，鴈逐西風日夜來。", "天勢漸低分海樹，山程欲盡見城臺。", "此身未別江邊寺，猶看星郎奉詔迴。"]'),
('31f6c917-bfc8-42ff-8747-db914d4e684f','寄居道林寺作','齊己','唐','唐诗','tang','','[]','嵐濕南朝殿塔寒，此中因得謝塵寰。',64,'全唐诗/poet.tang.46000.json','["嵐濕南朝殿塔寒，此中因得謝塵寰。", "已同庭樹千株老，未負溪雲一片閑。", "石鏡舊遊臨皎潔，岳蓮曾上徹孱顏。", "如今衰颯成多病，黃葉風前晝掩關。"]'),
('845d1ec6-2222-41c7-a335-a68be3292540','沙鷗','齊己','唐','唐诗','tang','','[]','暖傍漁船睡不驚，可憐孤潔似華亭。',64,'全唐诗/poet.tang.46000.json','["暖傍漁船睡不驚，可憐孤潔似華亭。", "晚來灣浦衝平碧，晴過汀洲拂淺青。", "翡翠靜中修羽翼，鴛鴦閑處事儀形。", "何如飛入漢宮裏，留與興亡作典經。"]'),
('e09dac8e-d8d4-41ee-9a69-545e90ff32a3','和翁員外題馬太傅宅賈相公井','齊己','唐','唐诗','tang','','[]','飛塵不敢下相干，闇脈傍應潤牡丹。',64,'全唐诗/poet.tang.46000.json','["飛塵不敢下相干，闇脈傍應潤牡丹。", "心任短長投玉綆，底須三五映金盤。", "神工舊製泓澄在，天澤時加瀲灧寒。", "太傅欲旌前古事，星郎屬思久憑欄。"]'),
('a67a7489-ad7f-4f08-8368-e508911cdea3','看雲','齊己','唐','唐诗','tang','','[]','何峰觸石濕苔錢，便逐高風離瀑泉。',64,'全唐诗/poet.tang.46000.json','["何峰觸石濕苔錢，便逐高風離瀑泉。", "深處臥來真隱逸，上頭行去是神仙。", "千尋有影滄江底，萬里無蹤碧落邊。", "長憶舊山青壁裏，遶庵閑伴老僧禪。"]'),
('a9865338-b3f8-463f-b8b9-7edd736926f7','對雪寄荆幕知己','齊己','唐','唐诗','tang','','[]','猛勢微開萬里清，月中看似日中明。',64,'全唐诗/poet.tang.46000.json','["猛勢微開萬里清，月中看似日中明。", "此時鷗鷺無人見，何處關山有客行。", "郢唱轉高誰敢和，巴歌相顧自銷聲。", "江齋卷箔含毫久，應想梁王禮不經。"]'),
('76b5edde-423b-4f81-b569-5d29d631707a','送相里秀才赴舉','齊己','唐','唐诗','tang','','[]','兩上東堂不見春，文明重去有誰親。',64,'全唐诗/poet.tang.46000.json','["兩上東堂不見春，文明重去有誰親。", "曾逢少海尊前客，舊是神仙會裏人。", "已遂風雲催化羽，却將雷電助燒鱗。", "明年自此登龍後，迴首荆門一路塵。"]'),
('35f52c07-03db-48c5-b687-5b55cdad2c99','荆門疾中喜謝尊師自南嶽來相里秀才自京至','齊己','唐','唐诗','tang','','["\u8861\u5c71"]','閑堂晝臥眼初開，強起徐行遶砌苔。',64,'全唐诗/poet.tang.46000.json','["閑堂晝臥眼初開，強起徐行遶砌苔。", "鶴氅人從衡嶽至，鶉衣客自洛陽來。", "坐聞鄰樹栖幽鳥，吟覺江雲發早雷。", "西笑東遊此相別，兩途消息待誰迴。"]'),
('3c24ecb6-8eb2-4d59-81ba-191bcf2d3e19','吟興自述','齊己','唐','唐诗','tang','','[]','前習都由未盡空，生知雅學妙難窮。',64,'全唐诗/poet.tang.46000.json','["前習都由未盡空，生知雅學妙難窮。", "一千首出悲哀外，五十年銷雪月中。", "興去不妨歸靜慮，情來何止發真風。", "曾無一字干聲利，豈愧操心負至公。"]'),
('eeb6e700-8559-43e8-b261-1d817479b9c5','送謝尊師自南嶽出入京','齊己','唐','唐诗','tang','','["\u8861\u5c71"]','曾聽鹿鳴逢世亂，因披羽服隱衡陽。',64,'全唐诗/poet.tang.46000.json','["曾聽鹿鳴逢世亂，因披羽服隱衡陽。", "幾多事隔丹霄興，三十年成兩鬢霜。", "芝朮未甘銷勇氣，風騷無那激剛腸。", "中朝舊有知音在，可是悠悠入帝鄉。"]'),
('b8c30576-e071-46e2-9b32-cc86000cc015','送司空學士赴京','齊己','唐','唐诗','tang','','[]','弘文初命下江邊，難戀沙鷗與釣船。',64,'全唐诗/poet.tang.46000.json','["弘文初命下江邊，難戀沙鷗與釣船。", "藍綬乍稱新學士，白衫初脫舊神仙。", "龍山送別風生路，雞樹從容雪照筵。", "重謁往年金牓主，便將才術佐陶甄。"]'),
('b3f96422-be66-4f78-9741-b6a16328b978','春寄尚顏','齊己','唐','唐诗','tang','','[]','含桃花謝杏花開，杜宇新啼燕子來。',64,'全唐诗/poet.tang.46000.json','["含桃花謝杏花開，杜宇新啼燕子來。", "好事可能無分得，名山長似有人催。", "簷聲未斷前旬雨，電影還連後夜雷。", "心跡共師爭幾許，似人嫌處自遲迴。"]'),
('92ab02e1-5588-41d7-9e9e-efa688155a86','寄梁先輩','齊己','唐','唐诗','tang','','[]','慈恩塔下曲江邊，別後多應夢到仙。',64,'全唐诗/poet.tang.46000.json','["慈恩塔下曲江邊，別後多應夢到仙。", "時去與誰論此事，亂來何處覓同年？", "陳琳筆硯甘前席，甪里煙霞待共眠。", "愛惜麻衣好顏色，未教朱紫汚天然。"]'),
('2a08e0e5-cb2f-4af0-9b05-b4e1e49edbbd','荆諸偶作','齊己','唐','唐诗','tang','','[]','無味吟詩即把經，竟將疎野訪誰行。',64,'全唐诗/poet.tang.46000.json','["無味吟詩即把經，竟將疎野訪誰行。", "身依江寺庭無樹，山遶天涯路有兵。", "竹瓦雨聲漂永日，紙窗燈焰照殘更。", "從容一覺清涼夢，歸到龍潭掃石枰。"]'),
('2e0653b9-7543-451c-ace3-bb723c193c47','城中晚夏思山','齊己','唐','唐诗','tang','','[]','葛衣霑汗功雖健，紙扇搖風力甚卑。',64,'全唐诗/poet.tang.46000.json','["葛衣霑汗功雖健，紙扇搖風力甚卑。", "苦熱恨無行脚處，微涼喜到立秋時。", "竹軒靜看蜘蛛挂，莎徑閑聽蟋蟀移。", "天外有山歸即是，豈同遊子暮何之。"]'),
('f8057999-df23-4bc7-b453-5314b2d6ced1','憶舊山','齊己','唐','唐诗','tang','','[]','誰請衰羸住北州，七年魂夢舊山丘。',64,'全唐诗/poet.tang.46000.json','["誰請衰羸住北州，七年魂夢舊山丘。", "心清檻底瀟湘月，骨冷禪中太華秋。", "高節未聞馴虎豹，片言何以傲王侯。", "應須脫灑孤峰去，始是分明箇剃頭。"]'),
('5876f377-86a8-4d2b-aa52-7f9f5799938a','寄體休','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南州君去爲尋醫，病色應除似舊時。',64,'全唐诗/poet.tang.46000.json','["南州君去爲尋醫，病色應除似舊時。", "久別莫忘廬阜約，却來須有洞庭詩。", "金陵往歲同窺井，峴首前秋共讀碑。", "兩處山河見興廢，相思更切臥雲期。"]'),
('b6c5f195-2466-4111-a607-7d04f15948e2','過陸鴻漸舊居','齊己','唐','唐诗','tang','','[]','楚客西來過舊居，讀碑尋傳見終初。',64,'全唐诗/poet.tang.46000.json','["楚客西來過舊居，讀碑尋傳見終初。", "佯狂未必輕儒業，高尚何妨誦佛書。", "種竹岸香連菡萏，煮茶泉影落蟾蜍。", "如今若更生來此，知有何人贈白驢。"]'),
('9a72bd30-0a5a-4e6d-a379-a306f7d55350','寄懷鍾陵舊遊因寄知己','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','洗井僧來說舊遊，西江東岸是城樓。',64,'全唐诗/poet.tang.46000.json','["洗井僧來說舊遊，西江東岸是城樓。", "昔年淹跡因王化，長日凭欄看水流。", "真觀上人棲樹石，陳陶處士在林丘。", "終拖老病重尋去，得到匡廬死便休。"]'),
('94625b68-648e-4e16-8ecd-6d7d872836b2','遣懷','齊己','唐','唐诗','tang','','[]','病腸休洗老休醫，七十能饒百歲期。',64,'全唐诗/poet.tang.46000.json','["病腸休洗老休醫，七十能饒百歲期。", "不死任還蓬島客，無生自有雪山師。", "浮雲聚散俱關慮，明月相逢好展眉。", "既兆未萌閑酌度，不如中抱是尋思。"]'),
('89136f94-cbae-4c64-8d93-ef416bb838d3','懷武陵因寄幕中韓先輩何從事','齊己','唐','唐诗','tang','','[]','武陵嘉致跡多幽，每見圖經恨白頭。',64,'全唐诗/poet.tang.46000.json','["武陵嘉致跡多幽，每見圖經恨白頭。", "溪浪碧通何處去，桃花紅過郡前流。", "常聞相幕鴛鴻興，日向神仙洞府遊。", "鑿井耕田人在否，如今天子正徵搜。"]'),
('eceea92a-673b-48d5-b5e6-12cad740aed8','贈樊處士','齊己','唐','唐诗','tang','','[]','小子聲名天下知，滿簪霜雪白麻衣。',64,'全唐诗/poet.tang.46000.json','["小子聲名天下知，滿簪霜雪白麻衣。", "誰將一著爭先後，共向長安定是非。", "有路未曾迷日用，無貪終不亂天機。", "閑尋道士過仙觀，賭得黃庭兩卷歸。"]'),
('9ed4861c-0dee-4bcc-80c4-9e4227fd2fa3','荆渚逢禪友','齊己','唐','唐诗','tang','','[]','澤國相逢話一宵，雲山偶別隔前朝。',64,'全唐诗/poet.tang.46000.json','["澤國相逢話一宵，雲山偶別隔前朝。", "社思匡岳無宗炳，詩憶揚州有鮑昭。", "晨野黍離春漠漠，水天星粲夜遙遙。", "閑吟莫忘傳心祖，曾立階前雪到腰。"]'),
('abdd7568-fbdd-4ba2-aeee-8ed4483c6788','送僧歸洛中','齊己','唐','唐诗','tang','','[]','赤日彤霞照晚坡，東州道路興如何。',64,'全唐诗/poet.tang.46000.json','["赤日彤霞照晚坡，東州道路興如何。", "蟬離楚柳鳴猶少，葉到嵩雲落漸多。", "海內自爲閑去住，關頭誰問舊經過。", "叮嚀與訪春山寺，白樂天真在也麽。"]'),
('9e01acfd-beec-4345-933d-19d0f212ea21','道林寓居','齊己','唐','唐诗','tang','','[]','秋泉一片樹千株，暮汲寒燒外有餘。',64,'全唐诗/poet.tang.46000.json','["秋泉一片樹千株，暮汲寒燒外有餘。", "青嶂這邊來已熟，紅塵那畔去應疎。", "風騷未肯忘雕琢，瀟灑無妨更剃除。", "即問沃州開士僻，愛禽憐駿意何如。"]'),
('7d0dbc01-842e-43ee-aa6a-e6d31966cce7','仙掌','齊己','唐','唐诗','tang','','["\u9ec4\u6cb3"]','峭形寒倚夕陽天，毛女蓮花翠影連。',64,'全唐诗/poet.tang.46000.json','["峭形寒倚夕陽天，毛女蓮花翠影連。", "雲外自爲高出手，人間誰合鬬揮拳。", "鶴拋青漢來巖檜，僧隔黃河望頂煙。", "晴露紅霞長滿掌，只應棲託是神仙。"]'),
('bf3fc1be-e0fc-41ea-a7c5-f5bc57ed6ea9','中秋月','齊己','唐','唐诗','tang','','[]','空碧無雲露濕衣，羣星光外湧清規。',64,'全唐诗/poet.tang.46000.json','["空碧無雲露濕衣，羣星光外湧清規。", "東樓莫礙漸高勢，四海待看當午時。", "還許分明吟皓魄，肯教幽暗取丹枝。", "可憐半夜嬋娟影，正對五侯殘酒池。"]'),
('9d63bb71-c82a-476e-82e7-07504f0de911','送禪者遊南岳','齊己','唐','唐诗','tang','','[]','忽隨南櫂去衡陽，誰住江邊樹下房。',64,'全唐诗/poet.tang.46000.json','["忽隨南櫂去衡陽，誰住江邊樹下房。", "塵夢是非都覺了，野雲心地更何妨。", "漸臨瀑布聽猨思，却背岣嶁有鴈行。", "想到中峰上層寺，石窗秋霽見瀟湘。"]'),
('579a5aee-42b5-4567-98f8-26a5b697523b','聞道林諸友嘗茶因有寄','齊己','唐','唐诗','tang','','[]','槍旗冉冉綠叢園，穀雨初晴叫杜鵑。',64,'全唐诗/poet.tang.46000.json','["槍旗冉冉綠叢園，穀雨初晴叫杜鵑。", "摘帶嶽華蒸曉露，碾和松粉煮春泉。", "高人夢惜藏巖裏，白硾封題寄火前。", "應念苦吟耽睡起，不堪無過夕陽天。"]'),
('d0f164e6-56f4-49a6-9fd1-5423bfdef258','將歸舊山留別錯公','齊己','唐','唐诗','tang','','[]','舊峰前昨下來時，白石叢叢間紫薇。',64,'全唐诗/poet.tang.46000.json','["舊峰前昨下來時，白石叢叢間紫薇。", "章句不堪歌有道，溪山只合退無機。", "雲含曖態晴猶在，鶴養閑神晝不飛。", "欲去更思過丈室，二年頻此揖清暉。"]'),
('0553a7d2-4691-4a15-afb8-b69f83229a6f','聞尚顏上人剏居有寄','齊己','唐','唐诗','tang','','[]','麓山南面橘洲西，別搆新齋與竹齊。',64,'全唐诗/poet.tang.46000.json','["麓山南面橘洲西，別搆新齋與竹齊。", "野客已聞將鶴贈，江僧未說有詩題。", "窗臨杳靄寒千嶂，枕遍潺湲月一溪。", "可想乍移禪榻處，松陰冷濕壁新泥。"]'),
('b546a6e8-eaca-40a7-a80a-962b9f99c8b9','庚午歲九日作','齊己','唐','唐诗','tang','','[]','門底秋苔嫩似藍，此中消息興何堪。',64,'全唐诗/poet.tang.46000.json','["門底秋苔嫩似藍，此中消息興何堪。", "亂離偷過九月九，頭尾算來三十三。", "雲影半晴開夢澤，菊花微暖傍江潭。", "故人今日在不在，胡鴈背風飛向南。"]'),
('043978af-e3aa-4166-a0c0-99ab38fa0e1f','逢進士沈彬','齊己','唐','唐诗','tang','','[]','欲話趨時首重騷，因君倍惜剃頭刀。',64,'全唐诗/poet.tang.46000.json','["欲話趨時首重騷，因君倍惜剃頭刀。", "千般貴在能過達，一片心閑不那高。", "山疊好雲藏玉鳥，海翻狂浪隔金鼇。", "時應記得長安事，曾向文場屬思勞。"]'),
('a333073d-79a7-4d7e-9847-ecdcf98baa6e','聞王員外新恩有寄','齊己','唐','唐诗','tang','','[]','欲退無因貴逼來，少儀官美右丞才。',64,'全唐诗/poet.tang.46000.json','["欲退無因貴逼來，少儀官美右丞才。", "青袍早許淹花幕，霜簡方聞謝柏臺。", "金諾靜宜資講誦，玉山寒稱奉尊罍。", "西峰有客思相賀，門隔瀟湘雪未開。"]'),
('4137f4d3-87f4-4bb6-98da-50119620e993','秋夕言懷寄所知','齊己','唐','唐诗','tang','','[]','休問蒙莊材不材，孤燈影共傍寒灰。',64,'全唐诗/poet.tang.46000.json','["休問蒙莊材不材，孤燈影共傍寒灰。", "忘筌話道心甘死，候體論詩口懶開。", "窗外風濤連建業，夢中雲水憶天台。", "相疎却是相知分，誰訝經年一度來。"]'),
('569d6d04-e8e1-4d9d-bea3-e818919a830e','答禪者','齊己','唐','唐诗','tang','','[]','五老峰前相遇時，兩無言語只揚眉。',64,'全唐诗/poet.tang.46000.json','["五老峰前相遇時，兩無言語只揚眉。", "南宗北祖皆如此，天上人間更問誰。", "山衲靜披雲片片，鐵刀涼削鬢絲絲。", "閑吟莫學湯從事，拋却袈裟負本師。"]'),
('60b40ae2-e5bb-473b-8a5f-7cccd10cfc3a','寄尚顏','齊己','唐','唐诗','tang','','[]','莫向孤峰道息機，有人偷眼羨吾師。',64,'全唐诗/poet.tang.46000.json','["莫向孤峰道息機，有人偷眼羨吾師。", "滿身光化年前寵，幾軸開平歲裏詩。", "北闕故人隨喪亂，南山舊寺在參差。", "清吟但憶徐方政，應恨當時不見時。"]'),
('e7c70edd-9890-4313-a80a-4a3f6672dfac','梓栗杖送人','齊己','唐','唐诗','tang','','[]','禪家何物贈分襟，只有天台杖一尋。',64,'全唐诗/poet.tang.46000.json','["禪家何物贈分襟，只有天台杖一尋。", "拄去客歸青洛遠，採來僧入白雲深。", "遊山曾把探龍穴，出世期將指佛心。", "此日江邊贈君後，却攜筇杖向東林。"]'),
('f7a8914f-7cb4-4eaf-863a-39af17cae487','寄朗陵二禪友','齊己','唐','唐诗','tang','','[]','瀟湘曾宿話詩評，荆楚連秋阻野情。',64,'全唐诗/poet.tang.46000.json','["瀟湘曾宿話詩評，荆楚連秋阻野情。", "金錫罷遊雙鬢白，鐵盂終守一齋清。", "篇章老欲齊高手，風月閑思到極精。", "南望山門石何處，滄浪雲夢浸天橫。"]'),
('191bd6b5-afe7-41f0-99d7-008b771b8e6e','燈','齊己','唐','唐诗','tang','','[]','幽光耿耿草堂空，窗隔飛蛾恨不通。',64,'全唐诗/poet.tang.46000.json','["幽光耿耿草堂空，窗隔飛蛾恨不通。", "紅燼自凝清夜朵，赤心長謝碧紗籠。", "雲藏水國城臺裏，雨閉松門殿塔中。", "金屋玉堂開照睡，豈知螢雪有深功。"]'),
('b2ef0000-07b7-4280-bcb7-714c3dde5e04','寄金陵幕中李郎中','齊己','唐','唐诗','tang','','[]','龍門支派富才能，年少飛翔便大鵬。',64,'全唐诗/poet.tang.46000.json','["龍門支派富才能，年少飛翔便大鵬。", "久待尊罍臨鐵甕，又從幢節鎮金陵。", "精神一隻秋空鶴，騷雅千尋夏井冰。", "長憶相招宿華館，數宵忘寢盡寒燈。"]'),
('a1778ab5-de06-4036-a3d6-60dfc0bf4d66','寄韓蛻秀才','齊己','唐','唐诗','tang','','[]','松門高不似侯門，蘚逕鞋蹤觸處分。',66,'全唐诗/poet.tang.46000.json','["松門高不似侯門，蘚逕鞋蹤觸處分。", "遠事即爲無害鳥，多閑便是有情雲。", "那憂寵辱來驚我，且寄風騷去敵君。", "[知]伴李膺琴酒外，絳紗閑卷共論文。"]'),
('030c2e5a-4197-4d1f-a081-60190821b101','湘中春興','齊己','唐','唐诗','tang','','[]','雨歇江明苑樹乾，物妍時泰恣遊盤。',64,'全唐诗/poet.tang.46000.json','["雨歇江明苑樹乾，物妍時泰恣遊盤。", "更無輕翠勝楊柳，盡覺濃華在牡丹。", "終日去還拋寂寞，遶池迴却凭欄干。", "紅芳片片由青帝，忍向西園看落殘。"]'),
('c4b6ef5c-7fa4-471c-989c-09eefb397dac','送錯公栖公南遊','齊己','唐','唐诗','tang','','[]','洪偃湯休道不殊，高帆共載興何俱。',64,'全唐诗/poet.tang.46000.json','["洪偃湯休道不殊，高帆共載興何俱。", "北京喪亂離丹鳳，南國煙花入鷓鴣。", "明月團圓臨桂水，白雲重疊起蒼梧。", "威儀本是朝天士，暫向遼荒住得無。"]'),
('fc734223-28c2-4e54-806e-55ed2f4ea0e0','寄南岳諸道友','齊己','唐','唐诗','tang','','[]','南望衡陽積瘴開，去年曾踏雪遊迴。',64,'全唐诗/poet.tang.46000.json','["南望衡陽積瘴開，去年曾踏雪遊迴。", "謾爲楚客蹉跎過，却是邊鴻的當來。", "乳竇孤明含海日，石橋危滑長春苔。", "終尋十八高人去，共坐蒼崖養聖胎。"]'),
('ac097c85-092b-42c1-81fc-fbf374e4ac28','送韓蛻秀才赴舉','齊己','唐','唐诗','tang','','[]','槐花館驛暮塵昏，此去分明吏部孫。',64,'全唐诗/poet.tang.46000.json','["槐花館驛暮塵昏，此去分明吏部孫。", "才器合居科第首，風流幸是縉紳門。", "春和洛水清無浪，雪洗高峰碧斷根。", "堪想都人齊指點，列仙相次上崑崙。"]'),
('d44b4860-13a9-4bdd-9e03-6e212b34e1f0','[溪]居寓言','齊己','唐','唐诗','tang','','[]','秋蔬數壠傍潺湲，頗覺生涯異俗緣。',64,'全唐诗/poet.tang.46000.json','["秋蔬數壠傍潺湲，頗覺生涯異俗緣。", "詩興難窮花草外，野情何限水雲邊。", "蟲聲遶屋無人語，月影當松有鶴眠。", "寄向東溪老樵道，莫催丹桂博青錢。"]'),
('cde18858-f034-40ef-ae14-e99e2ff9630f','遣懷','齊己','唐','唐诗','tang','','[]','詩病相兼老病深，世醫徒更費千金。',64,'全唐诗/poet.tang.46000.json','["詩病相兼老病深，世醫徒更費千金。", "餘生豈必虛拋擲，未死何妨樂詠吟。", "流水不迴休歎息，白雲無跡莫追尋。", "閑身自有閑消處，黃葉清風蟬一林。"]'),
('9317d841-2126-47db-bab7-d2e2e5288641','自湘中將入蜀留別諸友','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','巾舃初隨入蜀船，風帆吼過洞庭煙。',64,'全唐诗/poet.tang.46000.json','["巾舃初隨入蜀船，風帆吼過洞庭煙。", "七千里路到何處，十二峰雲更那邊。", "巫女暮歸林淅瀝，巴猨吟斷月嬋娟。", "來年五月峨嵋雪，坐看消融滿錦川。"]'),
('5a03ac44-f9e8-4554-b280-89298ed3504b','寄匡阜諸公二首 一','齊己','唐','唐诗','tang','','[]','松頭柏頂碧森森，虛檻寒吹夏景深。',64,'全唐诗/poet.tang.46000.json','["松頭柏頂碧森森，虛檻寒吹夏景深。", "靜社可追長往跡，白蓮難問久修心。", "山圍四面纔容寺，月到中宵始滿林。", "爭學忘言住幽勝，吾師遺集盡清吟。"]'),
('48c3f519-0bc3-45d0-9bef-c71b41819c10','寄匡阜諸公二首 二','齊己','唐','唐诗','tang','','[]','峰前林下東西寺，地角天涯來往僧。',64,'全唐诗/poet.tang.46000.json','["峰前林下東西寺，地角天涯來往僧。", "泉月淨流閑世界，杉松深鎖盡香燈。", "爭無大士重修社，合有諸賢更服膺。", "曾寄鄰房挂缾錫，雨聞巖溜解春冰。"]'),
('b1a77c3d-e4e2-4df3-9384-c3b258c7a83d','送人入蜀','齊己','唐','唐诗','tang','','[]','何必閑吟蜀道難，知君心出嶮巘間。',64,'全唐诗/poet.tang.46000.json','["何必閑吟蜀道難，知君心出嶮巘間。", "尋常秋泛江陵去，容易春浮錦水還。", "兩面碧懸神女峽，幾重青出丈人山。", "文君酒市逢初雪，滿貰新沽洗旅顏。"]'),
('9074264d-f9ae-452d-a5ca-4eeadb950347','酬廬山張處士','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','髮枯身老任浮沉，懶泥秋風更役吟。',64,'全唐诗/poet.tang.46000.json','["髮枯身老任浮沉，懶泥秋風更役吟。", "新事向人堪結舌，舊詩開卷但傷心。", "苔牀臥憶泉聲遶，麻履行思樹影深。", "終謝柴桑與彭澤，醉遊閑訪入東林。"]'),
('be9a8954-4c83-4652-b934-d9037b29c419','寄峴山道人','齊己','唐','唐诗','tang','','["\u534e\u5c71"]','鳳門高對鹿門青，往歲經過恨未平。',64,'全唐诗/poet.tang.46000.json','["鳳門高對鹿門青，往歲經過恨未平。", "辯鼎上人方話道，臥龍丞相忽追兵。", "爐峰已負重迴計，華嶽終懸未去情。", "聞說東周天子聖，會搖金錫却西行。"]'),
('45eb45b5-0c32-4195-9f26-90a04e72486f','送王處士遊蜀','齊己','唐','唐诗','tang','','[]','又挂寒帆向錦川，木蘭舟裏過殘年。',64,'全唐诗/poet.tang.46000.json','["又挂寒帆向錦川，木蘭舟裏過殘年。", "自修姹姹爐中物，擬作飄飄水上仙。", "三峽浪喧明月夜，萬州山到夕陽天。", "來年的有荆南信，迴札應緘十色牋。"]'),
('552c55a6-5b99-4b8b-9617-f94fdf22aeba','懷金陵李推官僧自牧','齊己','唐','唐诗','tang','','[]','秣陵長憶共吟遊，儒釋風騷道上流。',64,'全唐诗/poet.tang.46000.json','["秣陵長憶共吟遊，儒釋風騷道上流。", "蓮幕少年輕謝朓，雪山真子鄙湯休。", "也應有作懷清苦，莫謂無心過白頭。", "欲附別來千萬意，病身初起向殘秋。"]'),
('0547d4c2-f1ec-4c00-a00e-c74a6de1b13c','寄尋萍公','齊己','唐','唐诗','tang','','[]','聞在湓城多寄住，隨時談笑渾塵埃。',64,'全唐诗/poet.tang.46000.json','["聞在湓城多寄住，隨時談笑渾塵埃。", "孤峰恐憶便歸去，浮世要看還下來。", "萬頃野煙春雨斷，九條寒浪晚窗開。", "虎溪橋上龍潭寺，曾此相尋踏雪迴。"]'),
('e07b043d-1caf-4d42-8016-c1ba1dbe07b2','得李推官近寄懷','齊己','唐','唐诗','tang','','[]','荆門前歲使乎迴，求得星郎近制來。',64,'全唐诗/poet.tang.46000.json','["荆門前歲使乎迴，求得星郎近制來。", "連日借吟終不已，一燈忘寢又重開。", "秋風漫作牽情賦，春草真爲入夢才。", "堪笑陳宮諸狎客，當時空有箇追陪。"]'),
('7b93cea2-1597-485b-af2b-02958879c9ac','對菊','齊己','唐','唐诗','tang','','[]','蝶醉風狂半折時，冷煙清露壓離披。',64,'全唐诗/poet.tang.46000.json','["蝶醉風狂半折時，冷煙清露壓離披。", "欲傾琥珀盃浮爾，好把茱萸朵配伊。", "孔雀毛衣應者是，鳳凰金翠更無之。", "何因栽向僧園裏，門外重陽過不知。"]'),
('6e89121a-f091-4712-9f15-c292d9e4e0c0','憶東林因送二生歸','齊己','唐','唐诗','tang','','[]','好向東林度此生，半天山脚寺門平。',64,'全唐诗/poet.tang.46000.json','["好向東林度此生，半天山脚寺門平。", "紅霞嶂底潺潺色，清夜房前瑟瑟聲。", "偶別十年成瞬息，欲來千里阻刀兵。", "可憐二子同歸興，南國煙花路好行。"]'),
('ad80fb74-de34-494f-8fc6-528730ec3d78','渚宮西城池上居','齊己','唐','唐诗','tang','','[]','城東移錫住城西，綠遶春波引杖藜。',64,'全唐诗/poet.tang.46000.json','["城東移錫住城西，綠遶春波引杖藜。", "翡翠滿身衣有異，鷺鷥通體格非低。", "風搖柳眼開煙小，暖逼蘭芽出土齊。", "猶有幽深不相似，剡溪乘櫂入耶溪。"]'),
('c8b37f4d-3a71-4d1e-af69-28eda4ca7444','中秋夕愴懷寄荆幕孫郎中','齊己','唐','唐诗','tang','','[]','白蓮香散沼痕乾，綠篠陰濃蘚地寒。',64,'全唐诗/poet.tang.46000.json','["白蓮香散沼痕乾，綠篠陰濃蘚地寒。", "年老寄居思隱切，夜涼留客話時難。", "行僧盡去雲山遠，賓鴈同來澤國寬。", "時謝孔璋操檄外，每將空病問衰殘。"]'),
('53ac9da3-60ea-43d0-8a20-778ff5cbba47','酬湘幕徐員外見寄','齊己','唐','唐诗','tang','','[]','東海儒宗事業全，冰稜孤峭類神仙。',64,'全唐诗/poet.tang.46000.json','["東海儒宗事業全，冰稜孤峭類神仙。", "詩同李賀精通鬼，文擬劉軻妙入禪。", "珠履早曾從相府，玳簪今又別官筵。", "篇章幾謝傳西楚，空想雄風度十年。"]'),
('e683122a-1bb3-4dc7-b970-27ccd3fd4ac8','寄蜀國廣濟大師','齊己','唐','唐诗','tang','','[]','冰壓霜壇律格清，三千傳授盡門生。',64,'全唐诗/poet.tang.46000.json','["冰壓霜壇律格清，三千傳授盡門生。", "禪心盡入空無跡，詩句閑搜寂有聲。", "滿國繁華徒自樂，兩朝更變未曾驚。", "終思相約岷峨去，不得攜筇一路行。"]'),
('0ad60c34-cf5c-448e-a26b-791055a44955','答獻上人卷','齊己','唐','唐诗','tang','','[]','衲衣禪客袖篇章，江上相尋共感傷。',64,'全唐诗/poet.tang.46000.json','["衲衣禪客袖篇章，江上相尋共感傷。", "秦甸亂來栖白沒，杼山空後皎然亡。", "清留島月秋凝露，苦寄巴猨夜叫霜。", "珍重南宗好才子，灰心冥目外無妨。"]'),
('2b7294b4-d7b7-4c23-8e0d-154edac67012','寄武陵貫微上人二首 一','齊己','唐','唐诗','tang','','[]','知泛滄浪櫂未還，西峰房鎖夜潺潺。',64,'全唐诗/poet.tang.46000.json','["知泛滄浪櫂未還，西峰房鎖夜潺潺。", "春陪相府遊仙洞，雪共賓寮對玉山。", "詩裏幾添新菡萏，衲痕應換舊斕斑。", "莫忘一句曹溪妙，堪塞孫孫騁度關。"]'),
('b1af4005-e439-4ef6-b382-0f288b246726','寄武陵貫微上人二首 二','齊己','唐','唐诗','tang','','[]','吳頭東面楚西邊，雲接蒼梧水浸天。',64,'全唐诗/poet.tang.46000.json','["吳頭東面楚西邊，雲接蒼梧水浸天。", "兩地別離身已老，一言相合道休傳。", "風騷妙欲凌春草，蹤跡閑思遶嶽蓮。", "不是傲他名利世，吾師本在雪山巔。"]'),
('157a8f0c-1cd1-4369-98e5-98be0e3d2acf','懷體休上人','齊己','唐','唐诗','tang','','["\u534e\u5c71"]','仲宣樓上望重湖，君到瀟湘得健無。',64,'全唐诗/poet.tang.46000.json','["仲宣樓上望重湖，君到瀟湘得健無。", "病遇何人分藥餌，詩逢誰子論功夫。", "杉蘿寺裏尋秋早，橘柚洲邊度日晡。", "許送自身歸華嶽，待來朝暮拂缾盂。"]'),
('4199e133-c2a3-425b-9468-f5abd4859a49','招湖上兄弟','齊己','唐','唐诗','tang','','[]','去歲得君消息在，兩憑人信過重湖。',64,'全唐诗/poet.tang.46000.json','["去歲得君消息在，兩憑人信過重湖。", "忍貪風月當年少，不寄音書慰老夫。", "藥鼎近聞傳祕訣，詩門曾說擁寒爐。", "漢江江路西來便，好傍扁舟訪我無。"]'),
('9e422a9e-8d20-4034-a808-4f85119c2dc3','江居寄關中知己','齊己','唐','唐诗','tang','','[]','多病多慵漢水邊，流年不覺已皤然。',64,'全唐诗/poet.tang.46000.json','["多病多慵漢水邊，流年不覺已皤然。", "舊栽花地添黃竹，新陷盆池換白蓮。", "雪月未忘招遠客，雲山終待去安禪。", "八行書札君休問，不似風騷寄一篇。"]'),
('8e50ac36-6057-4ee5-8fc7-13466a37f699','中秋十五夜寄人','齊己','唐','唐诗','tang','','[]','高河瑟瑟轉金盤，歕露吹光逆凭欄。',64,'全唐诗/poet.tang.46000.json','["高河瑟瑟轉金盤，歕露吹光逆凭欄。", "四海魚龍精魄冷，五山鸞鶴骨毛寒。", "今宵盡向圓時望，後夜誰當缺處看。", "何事清光與蟾兔，却教才小少留難。"]'),
('c7daab8b-5fca-43cc-a286-294b8e5cae76','謝人自鍾陵寄紙筆','齊己','唐','唐诗','tang','','[]','故人猶憶苦吟勞，所惠何殊金錯刀。',64,'全唐诗/poet.tang.46000.json','["故人猶憶苦吟勞，所惠何殊金錯刀。", "霜雪剪栽新剡硾，鋒鋩管束本宣毫。", "知君倒篋情何厚，借我臨池價斗高。", "詞客分張看欲盡，不堪來處隔秋濤。"]'),
('81166747-5b87-45bb-8f44-000830cedaf5','移居西湖作二首 一','齊己','唐','唐诗','tang','','["\u897f\u6e56"]','火雲陽焰欲燒空，小檻幽窗想舊峰。',64,'全唐诗/poet.tang.46000.json','["火雲陽焰欲燒空，小檻幽窗想舊峰。", "白汗此時流枕簟，清風何處動杉松。", "殘更正好眠涼月，遠寺俄聞報曉鐘。", "只待秋聲滌心地，衲衣新洗健形容。"]'),
('dbb47aa0-8c50-4f35-b263-351ac055223d','移居西湖作二首 二','齊己','唐','唐诗','tang','','["\u897f\u6e56"]','官園樹影晝陰陰，咫尺清涼莫浣心。',66,'全唐诗/poet.tang.46000.json','["官園樹影晝陰陰，咫尺清涼莫浣心。", "桃李別教人主掌，煙花不稱我追尋。", "蜩[螗]晚噪風枝穩，翡翠閑眠宿處深。", "爭似出塵地行止，東林苔徑入西林。"]'),
('cf037bf6-0846-4e07-a15a-5c782c6b56d8','題玉泉寺','齊己','唐','唐诗','tang','','[]','高韻雙懸張曲江，聯題兼是孟襄陽。',64,'全唐诗/poet.tang.46000.json','["高韻雙懸張曲江，聯題兼是孟襄陽。", "後人才地誰稱短，前輩經天盡負長。", "勝景飽於閑采拾，靈蹤銷得正思量。", "時移兩板成塵跡，猶挂吾師舊影堂。"]'),
('c40a925a-4ee8-4fc4-b54f-500aa315d040','看金陵圖','齊己','唐','唐诗','tang','','[]','六朝圖畫戰爭多，最是陳宮計數訛。',32,'全唐诗/poet.tang.46000.json','["六朝圖畫戰爭多，最是陳宮計數訛。", "若愛蒼生似歌舞，隋皇自合恥干戈。"]'),
('4ba2e903-92f4-4598-8669-ed0cf7482833','寄南嶽泰禪師','齊己','唐','唐诗','tang','','["\u8861\u5c71"]','江頭默想坐禪峰，白石山前萬丈空。',32,'全唐诗/poet.tang.46000.json','["江頭默想坐禪峰，白石山前萬丈空。", "山下獵人應不到，雪深花鹿在庵中。"]'),
('9c115628-e252-4131-9985-53ab7a102c15','片雲','齊己','唐','唐诗','tang','','[]','水底分明天上雲，可憐形影似吾身。',32,'全唐诗/poet.tang.46000.json','["水底分明天上雲，可憐形影似吾身。", "何妨舒作從龍勢，一雨吹銷萬里塵。"]'),
('6d924414-65f1-4f6e-a7f3-42b4a8b2d07b','寄清溪道者','齊己','唐','唐诗','tang','','[]','萬重千疊紅霞嶂，夜燭朝香白石龕。',32,'全唐诗/poet.tang.46000.json','["萬重千疊紅霞嶂，夜燭朝香白石龕。", "常寄溪窗凭危檻，看經影落古龍潭。"]'),
('b632b049-5f19-4a75-b8d3-837e524a6002','病中勉送小師往清涼山禮大聖','齊己','唐','唐诗','tang','','[]','豐衣足食處莫住，聖跡靈蹤好遍尋。',32,'全唐诗/poet.tang.46000.json','["豐衣足食處莫住，聖跡靈蹤好遍尋。", "忽遇文殊開慧眼，他年應記老師心。"]'),
('3e089ac7-84f5-4b10-8a6f-6a56496568c2','謝人惠拄杖','齊己','唐','唐诗','tang','','[]','何處雲根採得來，黑龍狂欲作風雷。',32,'全唐诗/poet.tang.46000.json','["何處雲根採得來，黑龍狂欲作風雷。", "知師念我形骸老，教把經行拄綠苔。"]'),
('e1aa2da2-4928-4d8b-9f20-13eca752111f','送楚雲上人往南岳刺血寫法華經','齊己','唐','唐诗','tang','','[]','剝皮刺血誠何苦，欲寫靈山九會文。',32,'全唐诗/poet.tang.46000.json','["剝皮刺血誠何苦，欲寫靈山九會文。", "十指瀝乾終七軸，後來求法更無君。"]'),
('b9affc58-da60-4902-9b01-d89a0584d273','送胎髮筆寄仁公','齊己','唐','唐诗','tang','','[]','內唯胎髮外秋毫，綠玉新栽管束牢。',32,'全唐诗/poet.tang.46000.json','["內唯胎髮外秋毫，綠玉新栽管束牢。", "老病手疼無那爾，却資年少寫風騷。"]'),
('4167fad1-1a9c-4da2-8d6a-05a333ee7ed3','謝西川曇域大師玉筯篆書','齊己','唐','唐诗','tang','','[]','玉筯真文久不興，李斯傳到李陽冰。',32,'全唐诗/poet.tang.46000.json','["玉筯真文久不興，李斯傳到李陽冰。", "正悲千載無來者，果見僧中有箇僧。"]'),
('657ae538-3c71-46e3-a303-9a7861a0176e','偶作寄王祕書','齊己','唐','唐诗','tang','','[]','七絲湘水秋深夜，五字河橋日暮時。',32,'全唐诗/poet.tang.46000.json','["七絲湘水秋深夜，五字河橋日暮時。", "借問祕書郎此意，靜彈高詠有誰知。"]'),
('cd91b638-fb2e-468a-93b0-522080d2dab5','謝人惠紙','齊己','唐','唐诗','tang','','[]','烘焙幾工成曉雪，輕明百幅疊春冰。',32,'全唐诗/poet.tang.46000.json','["烘焙幾工成曉雪，輕明百幅疊春冰。", "何消才子題詩外，分與能書貝葉僧。"]'),
('e51ce086-48d7-4caa-a4f4-733da4811206','答文勝大師清柱書','齊己','唐','唐诗','tang','','[]','纔把文章干聖主，便承恩澤換禪衣。',32,'全唐诗/poet.tang.46000.json','["纔把文章干聖主，便承恩澤換禪衣。", "應嫌六祖傳空衲，只向曹溪求息機。"]'),
('8052aa34-cb8e-448c-a7b2-5967d1efcf37','寄懷曾口寺文英大師','齊己','唐','唐诗','tang','','[]','著紫袈裟名已貴，吟紅菡萏價兼高。',32,'全唐诗/poet.tang.46000.json','["著紫袈裟名已貴，吟紅菡萏價兼高。", "秋風曾憶西遊處，門對平湖滿白濤。"]'),
('899be99c-22c0-46a2-94ca-e30774069dba','懷道林寺道友','齊己','唐','唐诗','tang','','[]','四絕堂前萬木秋，碧參差影壓湘流。',32,'全唐诗/poet.tang.46000.json','["四絕堂前萬木秋，碧參差影壓湘流。", "閑思宋杜題詩板，一日憑欄到夜休。"]'),
('27b7211e-66eb-4f26-a999-fdac806700ec','辭主人絕句四首 放鶴','齊己','唐','唐诗','tang','','[]','華亭來復去芝田，丹頂霜毛性可憐。',32,'全唐诗/poet.tang.46000.json','["華亭來復去芝田，丹頂霜毛性可憐。", "縱與乘軒終誤主，不如還放却遼天。"]'),
('89928dc2-f766-4102-a53a-5c93de7584d4','辭主人絕句四首 放猨','齊己','唐','唐诗','tang','','[]','堪憶春雲十二峰，野桃山杏摘香紅。',32,'全唐诗/poet.tang.46000.json','["堪憶春雲十二峰，野桃山杏摘香紅。", "王孫可念愁金鎖，從放斷腸明月中。"]'),
('d77f06d4-c6e4-4e51-96e0-1f64f22d9950','辭主人絕句四首 放鷺鷥','齊己','唐','唐诗','tang','','[]','白萍紅蓼碧江涯，日暖雙雙立睡時。',32,'全唐诗/poet.tang.46000.json','["白萍紅蓼碧江涯，日暖雙雙立睡時。", "顧揭金籠放歸去，却隨沙鶴鬬輕絲。"]'),
('07aa13ab-2292-4707-a173-d3b143e1d357','辭主人絕句四首 放鸚鵡','齊己','唐','唐诗','tang','','[]','隴西蒼巘結巢高，本爲無人識翠毛。',32,'全唐诗/poet.tang.46000.json','["隴西蒼巘結巢高，本爲無人識翠毛。", "今日籠中強言語，乞歸天外啄含桃。"]'),
('ed16a365-15b7-4513-912b-44f907cb6050','猛虎行','齊己','唐','唐诗','tang','','[]','磨爾牙，錯爾爪，狐莫威，兔莫狡，饑來吞噬[取]腸飽。',58,'全唐诗/poet.tang.46000.json','["磨爾牙，錯爾爪，狐莫威，兔莫狡，饑來吞噬[取]腸飽。", "橫行不怕日月明，皇天產爾爲生獰。", "前村半夜聞吼聲，何人按劒燈熒熒。"]'),
('a7465ad2-368c-4eb1-9acc-d3e13f23b293','西山叟','齊己','唐','唐诗','tang','','[]','西山中，多狼虎，去歲傷兒復傷婦。',32,'全唐诗/poet.tang.46000.json','["西山中，多狼虎，去歲傷兒復傷婦。", "官家不問孤老身，還在前山山下住。"]'),
('aa76c5d9-f753-4dab-8bad-fd5fb5a1abf4','君子行','齊己','唐','唐诗','tang','','[]','聖人不生，麟龍何瑞？梧桐不高，鳳凰何止？吾聞古之有君子，行藏以時，進退求己。',80,'全唐诗/poet.tang.46000.json','["聖人不生，麟龍何瑞？梧桐不高，鳳凰何止？吾聞古之有君子，行藏以時，進退求己。", "榮必爲天下榮，恥必爲天下恥。", "苟進不如此，退不如此。", "亦何必用虛僞之文章，取榮名而自美。"]'),
('bb415a1b-6b9c-44a8-9b66-1ec309a4f7e2','善哉行','齊己','唐','唐诗','tang','','[]','大鵬刷翮謝溟渤，青雲萬層高突出。',64,'全唐诗/poet.tang.46000.json','["大鵬刷翮謝溟渤，青雲萬層高突出。", "下視秋濤空渺瀰，舊處魚龍皆細物。", "人生在世何容易，眼濁心昏信生死。", "願除嗜慾待身輕，攜手同尋列仙事。"]'),
('a731f134-b922-401c-bcab-4a07aa582166','日日曲','齊己','唐','唐诗','tang','','[]','日日日東上，日日日西沒。',52,'全唐诗/poet.tang.46000.json','["日日日東上，日日日西沒。", "任是神仙容，也須成朽骨。", "浮雲滅復生，芳草死還出。", "不知千古萬古人，葬向青山爲底物。"]'),
('4d604122-86c3-4d12-aaac-ef556be82580','耕叟','齊己','唐','唐诗','tang','','[]','春風吹蓑衣，暮雨滴箬笠。',48,'全唐诗/poet.tang.46000.json','["春風吹蓑衣，暮雨滴箬笠。", "夫婦耕共勞，兒孫飢對泣。", "田園高且瘦，賦稅重復急。", "官倉鼠雀羣，共待新租入。"]'),
('639368bd-320d-4853-8d7b-2e08c42909b2','苦熱行','齊己','唐','唐诗','tang','','[]','離宮劃開赤帝怒，喝出六龍奔日馭。',64,'全唐诗/poet.tang.46000.json','["離宮劃開赤帝怒，喝出六龍奔日馭。", "下土熬熬若煎煮，蒼生惶惶無處處。", "火雲崢嶸焚泬寥，東臯老農腸欲焦。", "何當一雨蘇我苗，爲君擊壤歌帝堯。"]'),
('80f2cb4f-fab0-49ce-8991-9dbbd48c7a32','苦寒行','齊己','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u54f2\u7406", "\u51ac\u5929"]','冰峰撐空寒矗矗，雲凝水凍埋海陸。',79,'全唐诗/poet.tang.46000.json','["冰峰撐空寒矗矗，雲凝水凍埋海陸。", "殺物之性，傷人之慾。", "既不能斷絕蒺藜荆棘之根株，又不能展鳳皇麒麟之拳跼。", "如此，則何如爲和煦，爲膏雨？", "自然天下之榮枯，融融於萬戶。"]'),
('0e6b5b8c-4c8d-4fa9-83d7-31ad6dc6c3e8','春風曲','齊己','唐','唐诗','tang','','[]','春風有何情，旦暮來林園。',24,'全唐诗/poet.tang.46000.json','["春風有何情，旦暮來林園。", "不問桃李主，吹落紅無言。"]'),
('3fee248d-4b49-4d04-a26a-f2c67f0d5bb2','城中懷山友','齊己','唐','唐诗','tang','','[]','春城來往桃李碧，煖豔紅香斷消息。',32,'全唐诗/poet.tang.46000.json','["春城來往桃李碧，煖豔紅香斷消息。", "吾徒自有山中鄰，白晝冥心坐嵐壁。"]'),
('948d8473-84e1-4320-9535-3aa9c3e67210','讀李賀歌集','齊己','唐','唐诗','tang','','[]','赤水無精華，荆山亦枯槁。',56,'全唐诗/poet.tang.46000.json','["赤水無精華，荆山亦枯槁。", "玄珠與虹玉，璨璨李賀抱。", "清晨醉起臨春臺，吳綾蜀錦胸襟開。", "狂多兩手掀蓬萊，珊瑚掇盡空土堆。"]'),
('d64a419e-2aff-447a-910e-6d19ad1eb089','風琴引','齊己','唐','唐诗','tang','','[]','挼吳絲，雕楚竹，高託天風拂爲曲。',96,'全唐诗/poet.tang.46000.json','["挼吳絲，雕楚竹，高託天風拂爲曲。", "一一宮商在素空，鸞鳴鳳語翹梧桐。", "夜深天碧松風多，孤窗寒夢驚流波。", "愁魂傍枕不肯去，翻疑住處鄰湘娥。", "金風聲盡熏風發，冷泛虛堂韻難歇。", "常恐聽多耳漸煩，清音不絕知音絕。"]'),
('32bb9ae8-5811-4b43-b81f-f72cb511ab1d','夏雲曲','齊己','唐','唐诗','tang','','[]','紅嵯峨，爍晚波，乖龍慵臥旱鬼多。',103,'全唐诗/poet.tang.46000.json','["紅嵯峨，爍晚波，乖龍慵臥旱鬼多。", "爞爞萬里壓天塹，颺雷電光空閃閃。", "好雨不雨風不風，徒倚穹蒼作巖險。", "男巫女覡更走魂，焚香祝天天不聞。", "天若聞，必能使爾爲潤澤，洗埃氛，而又變之成五色。", "捧日輪，將以表唐堯虞舜之明君。"]'),
('8f774df5-7c80-40d3-a546-3832227e07c0','讀李白集','齊己','唐','唐诗','tang','','[]','竭雲濤，刳巨鼇，搜括造化空牢牢。',80,'全唐诗/poet.tang.46000.json','["竭雲濤，刳巨鼇，搜括造化空牢牢。", "冥心入海海神怖，驪龍不敢爲珠主。", "人間物象不供取，飽飲遊神向懸圃。", "鏘金鏗玉千餘篇，膾吞炙嚼人口傳。", "須知一一丈夫氣，不是綺羅兒女言。"]'),
('bc9eb025-d2dc-4aed-8cf3-3d13d745a224','祈真壇','齊己','唐','唐诗','tang','','[]','玉甕瑤壇二三級，學仙弟子參差入。',102,'全唐诗/poet.tang.46000.json','["玉甕瑤壇二三級，學仙弟子參差入。", "霓旌隊仗下不下，松檜森森天露濕。", "殿前寒氣束香雲，朝祈暮禱玄元君。", "茫茫俗骨醉更昏，樓臺十二遙崑崙。", "崑崙縱廣一萬二千里，中有五色雲霞五色水。", "何當斷慾便飛去，不要九轉神丹換精髓。"]'),
('e1327917-f259-4bbc-bf00-9d2abb2fe053','黃雀行','齊己','唐','唐诗','tang','','[]','雙雙野田雀，上下同飲啄。',48,'全唐诗/poet.tang.46000.json','["雙雙野田雀，上下同飲啄。", "暖去栖蓬蒿，寒歸傍籬落。", "殷勤避羅網，乍可遇鵰鶚。", "鵰鶚雖不仁，分明在寥廓。"]'),
('39c85d83-a6bb-445f-b67c-f814f29bc805','石竹花','齊己','唐','唐诗','tang','','[]','石竹花開照庭石，紅蘚自稟離宮色。',96,'全唐诗/poet.tang.46000.json','["石竹花開照庭石，紅蘚自稟離宮色。", "一枝兩枝初笑風，猩猩血潑低低叢。", "常嗟世眼無真鑒，却被丹青苦相陷。", "誰爲根尋造化功，爲君吐出淳元膽。", "白日當午方盛開，彤霞灼灼臨池臺。", "繁香濃豔如未已，粉蝶遊蜂狂欲死。"]'),
('7efd6084-78bd-4f0e-9188-942e4d7eda7c','寄南岳白蓮道士能于長嘯','齊己','唐','唐诗','tang','','[]','猨猱休啼月皎皎，蟋蟀不吟山悄悄。',32,'全唐诗/poet.tang.46000.json','["猨猱休啼月皎皎，蟋蟀不吟山悄悄。", "大耳仙人滿頷鬚，醉倚長松一聲嘯。"]'),
('cb800859-cf83-464e-8518-6ec688a1ade9','古劒歌','齊己','唐','唐诗','tang','','[]','古人手中鑄神物，百鍊百淬始提出。',64,'全唐诗/poet.tang.46000.json','["古人手中鑄神物，百鍊百淬始提出。", "今人不要強硎磨，蓮鍔星文未曾沒。", "一彈一撫聞錚錚，老龍影奪秋燈明。", "何時得遇英雄主，用爾平治天下去。"]'),
('84a34957-ca4b-41cf-acb8-b883edcc20c4','湘妃廟','齊己','唐','唐诗','tang','','[]','湘煙濛濛湘水急，汀露凝紅裛蓮濕。',76,'全唐诗/poet.tang.46000.json','["湘煙濛濛湘水急，汀露凝紅裛蓮濕。", "蒼梧雲疊九嶷深，二女魂飛江上立。", "相攜泣，鳳蓋龍輿追不及。", "廟荒松朽啼飛猩，筍鞭迸出階基傾。", "黃昏一岸陰風起，新月如眉生闊水。"]'),
('665cfbe3-194c-48bc-8c57-4ce73bb306df','巫山高','齊己','唐','唐诗','tang','','[]','巫山高，巫女妖。',88,'全唐诗/poet.tang.46000.json','["巫山高，巫女妖。", "雨爲暮兮雲爲朝，楚王顦顇魂欲銷。", "秋猨嗥嗥日將夕，紅霞紫煙凝老壁。", "千巖萬壑花皆坼，但恐芳菲無正色。", "不知今古行人行，幾人經此無秋情。", "雲深廟遠不可覓，十二峰頭插天碧。"]'),
('d04c1a95-755d-4dab-b75e-afed4071f72f','贈持法華經僧','齊己','唐','唐诗','tang','','[]','衆人有口，不說是，即說非。',142,'全唐诗/poet.tang.47000.json','["衆人有口，不說是，即說非。", "吾師有口何所爲，蓮經七軸六萬九千字。", "日日夜夜終復始。", "乍吟乍諷何悠揚，風篁古松含秋霜。", "但恐天龍夜叉乾闥衆，㽬塞虛空耳皆聳。", "我聞念經功德緣，舌根可算金剛堅。", "他時劫火洞燃後，神光璨璨如紅蓮。", "受持身心苟精潔，尚能使煩惱大海水枯竭。", "魔王輪幢自摧折，何況更如理行如理說。"]'),
('e762d167-3cc2-4aeb-8fb7-d155c8fe01c9','刳腸龜','齊己','唐','唐诗','tang','','[]','爾既能於靈，應久存其生。',48,'全唐诗/poet.tang.47000.json','["爾既能於靈，應久存其生。", "爾既能於瑞，胡得迷其死。", "刳腸徒自屠，曳尾復何累。", "可憐濮水流，一葉泛莊子。"]'),
('afa0991a-57b3-4ddc-a3a1-ce133f6bf93e','贈巖居僧','齊己','唐','唐诗','tang','','[]','石如騏驎巖作室，秋苔漫壇淨於漆。',32,'全唐诗/poet.tang.47000.json','["石如騏驎巖作室，秋苔漫壇淨於漆。", "袈裟蓋頭心在無，黃猨白猨啼日日。"]'),
('428e82d6-21a0-4945-84af-2f1355de0b5a','觀李瓊處士畫海濤','齊己','唐','唐诗','tang','','[]','巨鼇轉側長鰌翻，狂濤顛浪高漫漫。',128,'全唐诗/poet.tang.47000.json','["巨鼇轉側長鰌翻，狂濤顛浪高漫漫。", "李瓊奪得造化本，都盧縮在秋毫端。", "一揮一畫皆筋骨，滉漾崩騰大鯨臬。", "葉撲仙槎擺欲沉，下頭應是驪龍窟。", "昔年曾要涉蓬瀛，唯聞撼動珊瑚聲。", "今來正歎陸沉久，見君此畫思前程。", "千尋萬派功難測，海門山小濤頭白。", "令人錯認錢塘城，羅剎石底奔雷霆。"]'),
('04e2da73-fcd8-4ff4-b1d3-a2bd4b468345','昇天行','齊己','唐','唐诗','tang','','[]','身不沉，骨不重，驅青鸞，駕白鳳。',80,'全唐诗/poet.tang.47000.json','["身不沉，骨不重，驅青鸞，駕白鳳。", "幢蓋飄搖入冷空，天風瑟瑟星河動。", "瑤闕參差阿母家，樓臺戲閉凝彤霞。", "三五仙子乘龍車，堂前碾爛蟠桃花。", "迴頭却顧蓬萊頂，一點濃嵐在深井。"]'),
('9e869707-71c0-4268-b2c3-9e6e4f396dbc','還人卷','齊己','唐','唐诗','tang','','[]','李白李賀遺機杼，散在人間不知處。',96,'全唐诗/poet.tang.47000.json','["李白李賀遺機杼，散在人間不知處。", "聞君收在芙蓉江，日鬬鮫人織秋浦。", "金梭劄劄文離離，吳姬越女羞上機。", "鴛鴦浴煙鸞鳳飛，澄江曉映餘霞輝。", "仙人手持玉刀尺，寸寸酬君珠與璧。", "裁作霞裳何處披，紫皇殿裏深難覓。"]'),
('d9aa05ba-6c7d-4ebd-9401-5edd412f9b93','輕薄行','齊己','唐','唐诗','tang','','[]','玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。',64,'全唐诗/poet.tang.47000.json','["玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。", "五陵春暖芳草齊，笙歌到處花成泥。", "日沉月上且鬬雞，醉來莫問天高低。", "伯陽道德何唾咦，仲尼禮樂徒卑栖。"]'),
('00683cf6-9066-423f-8480-e14b39cfa8fc','浮雲行','齊己','唐','唐诗','tang','','[]','大野有賢人，大朝有聖君。',48,'全唐诗/poet.tang.47000.json','["大野有賢人，大朝有聖君。", "如何彼浮雲，掩蔽白日輪。", "安得東南風，吹散八表外。", "使之天下人，共見堯眉彩。"]'),
('af167d52-44ff-497f-aa19-c4b07c07f974','煌煌京洛行','齊己','唐','唐诗','tang','','["\u9ec4\u6cb3"]','聖君垂衣裳，蕩蕩若朝旭。',72,'全唐诗/poet.tang.47000.json','["聖君垂衣裳，蕩蕩若朝旭。", "大觀無遺物，四夷來率服。", "清晨迴北極，紫氣蓋黃屋。", "雙闕聳雙鼇，九門如川瀆。", "梯山航海至，晝夜車相續。", "我恐紅塵深，變爲黃河曲。"]'),
('65cf19a5-59c6-49bb-9ad8-36de23dec3eb','弔汨羅','齊己','唐','唐诗','tang','','[]','落日倚闌干，徘徊汨羅曲。',98,'全唐诗/poet.tang.47000.json','["落日倚闌干，徘徊汨羅曲。", "冤魂如可弔，煙浪聲似哭。", "我欲考黿鼉之心，烹魚龍之腹。", "爾既啖大夫之血，食大夫之肉。", "千載之後，猶斯暗伏。", "將謂唐堯之尊，還如荒悴之君。", "更有逐臣，於焉葬魂。", "得以縱其噬，[恣]其吞。"]'),
('69e5468d-90a4-4ef8-8479-f5b9ff5045d8','贈念法華經僧','齊己','唐','唐诗','tang','','[]','念念念兮入惡易，念念念兮入善難。',266,'全唐诗/poet.tang.47000.json','["念念念兮入惡易，念念念兮入善難。", "念經念佛能一般，愛河竭處生波瀾。", "言公少年真法器，白晝不出夜不睡。", "心心緣經口緣字，一室寥寥燈照地。", "沈檀卷軸寶函盛，薝蔔香熏水精記。", "空山木落古寺閑，松枝鶴眠霜霰乾。", "牙根舌根水滴寒，珊瑚搥打紅琅玕。", "但恐蓮花七朵一時折，朵朵似君心地白。", "又恐天風吹天花，繽紛如雨飄袈裟。", "況聞此經甚微妙，百千諸佛真祕要。", "靈山說後始傳來，聞者雖多持者少。", "更堪誦入陀羅尼，唐音梵音相雜時。", "舜絃和雅熏風吹，文王武王絃更悲。", "如此爭不遣碧空中有龍來聽，有鬼來聽，亦使人間聞者敬。", "見者敬，自然心虛空，性清淨。", "此經真體即毘盧，雪嶺白牛君識無。"]'),
('4e7c6379-97cb-446c-a7e5-f46ef866afe6','短歌寄鼓山長老','齊己','唐','唐诗','tang','','[]','雪峰雪峰高且雄，峨峨堆積青冥中。',130,'全唐诗/poet.tang.47000.json','["雪峰雪峰高且雄，峨峨堆積青冥中。", "六月赤日燒不鎔，飛禽瞥見人難通。", "常聞中有白象王，五百象子皆威光。", "行圍坐遶同一色，森森影動旃檀香。", "於中一子最雄猛，稱尊獨踞鼓山頂。", "百千眷屬陰□影，身照曜，吞秋景。", "[我]聞岷國民歸依，前王後王皆師資。", "寧同梁武遇達磨，過後彈指空傷悲。"]'),
('19ee43f1-1c4a-401c-8475-9e037360665c','漁父','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','夜釣洞庭月，朝醉巴陵市。',48,'全唐诗/poet.tang.47000.json','["夜釣洞庭月，朝醉巴陵市。", "却歸君山下，魚龍窟邊睡。", "生涯在何處，白浪千萬里。", "曾笑楚臣迷，蒼黃汨羅水。"]'),
('06d931fb-2191-43a6-a02f-ab78920eeead','採蓮曲','齊己','唐','唐诗','tang','','[]','越溪女，越江蓮。',76,'全唐诗/poet.tang.47000.json','["越溪女，越江蓮。", "齊菡萏，雙嬋娟。", "嬉遊向何處，採摘且同船。", "浩唱發容與，清波生漪連。", "時逢島嶼泊，幾共鴛鴦眠。", "襟袖既盈溢，馨香亦相傳。", "薄暮歸去來，苧蘿生碧煙。"]'),
('89e81d4e-15be-4925-be9d-7246601c79b0','啄木','齊己','唐','唐诗','tang','','[]','啄木啄啄，鳴林響壑。',60,'全唐诗/poet.tang.47000.json','["啄木啄啄，鳴林響壑。", "貪心既緣，利嘴斯鑿。", "有朽百尺，微蟲斯宅。", "以啄去害，啄更彌劇。", "層崖豫章，聳幹蒼蒼。", "無縱爾啄，摧我棟梁。"]'),
('eeeac27e-9535-463e-9cd8-93c04d119f6e','靈松歌','齊己','唐','唐诗','tang','','[]','靈松靈松，是何根株。',212,'全唐诗/poet.tang.47000.json','["靈松靈松，是何根株。", "盤擗枝幹，與羣木殊。", "世眼爭知蒼翠容，薜蘿遮體深朦朧。", "先秋瑟瑟生谷風，青陰倒卓寒潭中。", "八月天威行肅殺，萬木凋零向霜雪。", "唯有此松高下枝，一枝枝在無摧折。", "癡凍頑冰如鐵堅，重重鎖到槎牙顛。", "老鱗枯節相把捉，踉蹌立在青崖前。", "有時深洞興雷雹，飛電繞身光閃爍。", "乍似蒼龍驚起時，攫霧穿雲欲騰躍。", "夜深山月照高枝，疎影細落莓苔磯。", "千年朽枿魍魎出，一株寒韻鏘琉璃。", "安得良工妙圖雘，寫將偃蹇懸煙閣。", "飛瀑聲中戰歲寒，紅霞影裏擎蕭索。"]'),
('f36a25a3-4a59-468a-9d23-bb252a73a578','蠹','齊己','唐','唐诗','tang','','[]','蠹不自蠹，而蠹于木。',60,'全唐诗/poet.tang.47000.json','["蠹不自蠹，而蠹于木。", "蠹極木心，以豐爾腹。", "偶或成之，胡爲勗人。", "人而不真，繇爾亂神。", "蠹兮蠹兮，何全其生。", "無託爾形，霜松雪檉。"]'),
('d25f4715-0ecf-44c1-ba86-c59b7ce4d6ba','行路難','齊己','唐','唐诗','tang','','[]','行路難，君好看。',86,'全唐诗/poet.tang.47000.json','["行路難，君好看。", "驚波不在黤黮間，小人心裏藏崩湍。", "七盤九折寒𡺚崒，翻車倒蓋猶堪出。", "未似是非脣舌危，闇中潛毀平人骨。", "君不見楚靈均，千古沉冤湘水濱。", "又不見李太白，一朝却作江南客。"]'),
('48dbd42a-33dc-4d84-a877-d4ab5bcc35f5','謝徽上人見惠二龍障子以短歌酬之','齊己','唐','唐诗','tang','','[]','我見蘇州崑山金城中，金城柱上有二龍。',146,'全唐诗/poet.tang.47000.json','["我見蘇州崑山金城中，金城柱上有二龍。", "老僧相傳道是僧繇手，尋常入海共龍鬬。", "又聞蜀國玉局觀有孫遇跡，盤屈身長八十尺。", "遊人爭看不敢近，頭覻寒泉萬丈碧。", "近有五羊徽上人，閑工小筆得意新。", "畫龍不誇頭角及鬚鱗，只求筋骨與精神。", "徽上人，真藝者。", "惠我雙龍不言價，等閑不敢將懸挂。", "恐是葉公好假龍，及見真龍却驚怕。"]'),
('86c70bb4-157b-403a-adec-c6a0f16d90b9','送人往長沙','齊己','唐','唐诗','tang','','[]','荆門歸路指湖南，千里風帆興可諳。',32,'全唐诗/poet.tang.47000.json','["荆門歸路指湖南，千里風帆興可諳。", "好聽鷓鴣啼雨處，木蘭舟晚泊春潭。"]'),
('60b579d7-c425-4cb4-a241-b6fbcd6eec7f','偶題','齊己','唐','唐诗','tang','','[]','時事嬾言多忌諱，野吟無主若縱橫。',32,'全唐诗/poet.tang.47000.json','["時事嬾言多忌諱，野吟無主若縱橫。", "君看三百篇章首，何處分明著姓名。"]'),
('8e7dfcb2-db62-49e8-976c-5e194f64cad1','寄山中叟','齊己','唐','唐诗','tang','','[]','青泉碧樹夏風涼，紫蕨紅粳午爨香。',32,'全唐诗/poet.tang.47000.json','["青泉碧樹夏風涼，紫蕨紅粳午爨香。", "應笑晨持一盂苦，腥羶市裏呌家常。"]'),
('dffab256-67f9-440c-b567-7adab89bd14f','贈琴客','齊己','唐','唐诗','tang','','[]','曾攜五老峰前過，幾向雙松石上彈。',32,'全唐诗/poet.tang.47000.json','["曾攜五老峰前過，幾向雙松石上彈。", "此境此身誰更愛，掀天羯鼓滿長安。"]'),
('2f7f35ed-19af-4e03-a573-dd7fdb74de45','勉吟僧','齊己','唐','唐诗','tang','','[]','千途萬轍亂真源，白晝勞形夜斷魂。',32,'全唐诗/poet.tang.47000.json','["千途萬轍亂真源，白晝勞形夜斷魂。", "忍著袈裟把名紙，學他低折五侯門。"]'),
('e0350d46-4847-4b17-b1a2-065595fb5af3','送人歸華下','齊己','唐','唐诗','tang','','[]','蓮花峰翠濕凝秋，舊業園林在下頭。',32,'全唐诗/poet.tang.47000.json','["蓮花峰翠濕凝秋，舊業園林在下頭。", "好束詩書且歸去，而今不愛事風流。"]'),
('f5e15d6a-1494-4766-ac8d-55b186e6128e','夏日城中作二首 一','齊己','唐','唐诗','tang','','[]','三面僧鄰一面牆，更無風路可吹涼。',32,'全唐诗/poet.tang.47000.json','["三面僧鄰一面牆，更無風路可吹涼。", "他年捨此歸何處，青壁紅霞裹石房。"]'),
('9ef037e3-dc9b-4936-816d-6c9b766933f3','夏日城中作二首 二','齊己','唐','唐诗','tang','','[]','竹低莎淺雨濛濛，水檻幽窗暑月中。',32,'全唐诗/poet.tang.47000.json','["竹低莎淺雨濛濛，水檻幽窗暑月中。", "有境牽懷人不會，東林門外翠橫空。"]'),
('8a028c4a-17b0-48dc-a133-2fd04501b5e1','默坐','齊己','唐','唐诗','tang','','[]','燈引飛蛾拂焰迷，露淋栖鶴壓枝低。',32,'全唐诗/poet.tang.47000.json','["燈引飛蛾拂焰迷，露淋栖鶴壓枝低。", "冥心坐滿蒲團穩，夢到天台過剡溪。"]'),
