('a7a5bccb-12cd-4d73-a2f9-393375647012','翡翠','齊己','唐','唐诗','tang','','[]','水邊飛去青難辨，竹裏歸來色一般。',32,'全唐诗/poet.tang.47000.json','["水邊飛去青難辨，竹裏歸來色一般。", "磨吻鷹鸇莫相害，白鷗鴻鶴滿沙灘。"]'),
('49529bde-7ec1-45cf-80e2-ccce647137a0','與節供奉大德遊京口寺留題','齊己','唐','唐诗','tang','','[]','柳岸晴緣十里來，水邊精舍絕塵埃。',32,'全唐诗/poet.tang.47000.json','["柳岸晴緣十里來，水邊精舍絕塵埃。", "煮茶嘗摘興何極，直至殘陽未欲迴。"]'),
('70fffc93-d45d-4e68-880a-f7f8c2d26f62','謝荆幕孫郎中見示樂府歌集二十八字','齊己','唐','唐诗','tang','','[]','長吉才狂太白顛，二公文陣勢橫前。',32,'全唐诗/poet.tang.47000.json','["長吉才狂太白顛，二公文陣勢橫前。", "誰言後代無高手，奪得秦皇鞭鬼鞭。"]'),
('fd45f048-9336-46b0-b4de-9a74b2e0e619','謝陰符經勉送藏休上人二首 一','齊己','唐','唐诗','tang','','[]','事遂鼎湖遺劒履，時來渭水擲魚竿。',32,'全唐诗/poet.tang.47000.json','["事遂鼎湖遺劒履，時來渭水擲魚竿。", "欲知賢聖存亡道，自向心機反覆看。"]'),
('1eec4cbe-f723-402c-b0af-b064089c57d8','謝陰符經勉送藏休上人二首 二','齊己','唐','唐诗','tang','','[]','一林霜雪未霑頭，爭遣藏休肯便休。',32,'全唐诗/poet.tang.47000.json','["一林霜雪未霑頭，爭遣藏休肯便休。", "學盡世間難學事，始堪隨處任虛舟。"]'),
('8834e3f2-f5e7-4000-ad41-8f9e8368b444','幽齋偶作','齊己','唐','唐诗','tang','','[]','幽院纔容箇小庭，疎篁低短不堪情。',32,'全唐诗/poet.tang.47000.json','["幽院纔容箇小庭，疎篁低短不堪情。", "春來猶賴鄰僧樹，時引流鶯送好聲。"]'),
('36121eb2-af72-4077-97d0-82d0aca03862','贈念法華經僧','齊己','唐','唐诗','tang','','[]','萬境心隨一念平，紅芙蓉折愛河清。',32,'全唐诗/poet.tang.47000.json','["萬境心隨一念平，紅芙蓉折愛河清。", "持經功力能如是，任駕白牛安穩行。"]'),
('bcb88719-cc4a-46d8-a61b-e1705450ae26','對菊','齊己','唐','唐诗','tang','','[]','無豔無妖別有香，栽多不爲待重陽。',32,'全唐诗/poet.tang.47000.json','["無豔無妖別有香，栽多不爲待重陽。", "莫嫌醒眼相看過，却是真心愛澹黃。"]'),
('19007cd2-c25b-42b2-913e-51bd92d4d1b3','閉門','齊己','唐','唐诗','tang','','[]','正是閉門爭合閉，大家開處不須開。',32,'全唐诗/poet.tang.47000.json','["正是閉門爭合閉，大家開處不須開。", "還防朗月清風夜，有箇詩人相訪來。"]'),
('a0df7cfb-3547-4c58-a270-38d5785abff6','勉送吳國三五新戒歸','齊己','唐','唐诗','tang','','[]','法王遺制付仁王，難得難持劫數長。',32,'全唐诗/poet.tang.47000.json','["法王遺制付仁王，難得難持劫數長。", "努力只須堅守護，三千八萬是垣牆。"]'),
('62126502-cb40-46c7-be87-1dd30de80e90','夏日寄清溪道者','齊己','唐','唐诗','tang','','[]','老病不能求藥餌，朝昏祗是但焚燒。',34,'全唐诗/poet.tang.47000.json','["老病不能求藥餌，朝昏祗是但焚燒。", "不知誰爲收灰骨，[壘]石栽松傍寺橋。"]'),
('3b41b2af-040f-4d19-a11e-55ae0ce4cd47','送惠空北遊','齊己','唐','唐诗','tang','','[]','君向峴山遊聖境，我將何以記多才。',32,'全唐诗/poet.tang.47000.json','["君向峴山遊聖境，我將何以記多才。", "叮嚀墮淚碑前過，寫取斯文寄我來。"]'),
('790e6ce6-5aba-4ac4-a400-4dc1ea1e78c6','寄懷歸州馬判官','齊己','唐','唐诗','tang','','[]','三年爲倅興何長，歸計應多事少忙。',32,'全唐诗/poet.tang.47000.json','["三年爲倅興何長，歸計應多事少忙。", "又見秋風霜裛樹，滿山椒熟水雲香。"]'),
('28693c72-4d60-4c07-86a8-6ea0bac5e3e4','觀荷葉露珠','齊己','唐','唐诗','tang','','[]','霏微曉露成珠顆，宛轉田田未有風。',32,'全唐诗/poet.tang.47000.json','["霏微曉露成珠顆，宛轉田田未有風。", "任器方圓性終在，不妨翻覆落池中。"]'),
('e09d497b-e62c-4867-a10b-763b87d96d3b','苦熱懷玉泉寺寄仁上人','齊己','唐','唐诗','tang','','[]','火雲如燒接蒼梧，原野煙連大澤枯。',32,'全唐诗/poet.tang.47000.json','["火雲如燒接蒼梧，原野煙連大澤枯。", "謾費葛衫葵扇力，爭禁泉石潤肌膚。"]'),
('b3542b26-2054-4dd1-a0df-fc1e2cc86096','觀盆池白蓮','齊己','唐','唐诗','tang','','[]','素萼金英歕露開，倚風凝立獨徘徊。',32,'全唐诗/poet.tang.47000.json','["素萼金英歕露開，倚風凝立獨徘徊。", "應思瀲灧秋池底，更有歸天伴侶來。"]'),
('65e23c10-ac2c-45c7-89c8-2bf778d5e5dd','折楊柳詞四首 一','齊己','唐','唐诗','tang','','[]','鳳樓高映綠陰陰，凝重多含雨露深。',32,'全唐诗/poet.tang.47000.json','["鳳樓高映綠陰陰，凝重多含雨露深。", "莫謂一枝柔軟力，幾曾牽破別離心。"]'),
('386197f4-7356-4ac7-82e6-1c38a71720a4','折楊柳詞四首 二','齊己','唐','唐诗','tang','','[]','館娃宮畔響廊前，依託吳王養翠煙。',32,'全唐诗/poet.tang.47000.json','["館娃宮畔響廊前，依託吳王養翠煙。", "劒去國亡臺殿毀，却隨紅樹噪秋蟬。"]'),
('40ea7503-7b55-4005-a02a-95cdc9466b0d','折楊柳詞四首 三','齊己','唐','唐诗','tang','','[]','穠低似中陶潛酒，軟極如傷宋玉風。',32,'全唐诗/poet.tang.47000.json','["穠低似中陶潛酒，軟極如傷宋玉風。", "多謝將軍遶營種，翠中閑卓戰旗紅。"]'),
('975a664b-3687-47c8-917f-db76f5927c0d','折楊柳詞四首 四','齊己','唐','唐诗','tang','','[]','高僧愛惜遮江寺，遊子傷殘露野橋。',32,'全唐诗/poet.tang.47000.json','["高僧愛惜遮江寺，遊子傷殘露野橋。", "爭似著行垂上苑，碧桃紅杏對搖搖。"]'),
('b688aec9-9033-4809-9b09-6fba00df3207','荅長沙丁秀才書','齊己','唐','唐诗','tang','','[]','月月便車奔帝闕，年年貢士過荆臺。',32,'全唐诗/poet.tang.47000.json','["月月便車奔帝闕，年年貢士過荆臺。", "如何三度槐花落，未見故人攜卷來。"]'),
('481ac4f0-7279-443d-b8a7-8161bbefa949','戒小師','齊己','唐','唐诗','tang','','[]','不肯吟詩不聽經，禪宗異岳嬾遊行。',32,'全唐诗/poet.tang.47000.json','["不肯吟詩不聽經，禪宗異岳嬾遊行。", "他年白首當人問，將底言談對後生。"]'),
('610fdb00-2ee2-4368-8ad1-ec4a79f83536','題舊拄杖','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','親採匡廬瀑布西，層崖懸壁更安梯。',32,'全唐诗/poet.tang.47000.json','["親採匡廬瀑布西，層崖懸壁更安梯。", "攜行三十年吟伴，未有詩人□□□。"]'),
('de26998d-9144-4004-ab5b-d2ede7f0f9d7','酬歐陽秀才卷','齊己','唐','唐诗','tang','','[]','三十篇多十九章，□聲風力撼疎篁。',32,'全唐诗/poet.tang.47000.json','["三十篇多十九章，□聲風力撼疎篁。", "不堪更有精搜處，誰見蕭蕭雨夜堂。"]'),
('86d09b58-c834-40f3-91f2-654f3242fe9b','聞鴈','齊己','唐','唐诗','tang','','[]','瀟湘浦暖全迷鶴，邏逤川寒只有鵰。',32,'全唐诗/poet.tang.47000.json','["瀟湘浦暖全迷鶴，邏逤川寒只有鵰。", "誰向孤舟憶兄弟，坐看連鴈度橫橋。"]'),
('c2da3ac3-7e9c-4cf6-9e28-bfab309be50b','送高麗二僧南遊','齊己','唐','唐诗','tang','','[]','日邊鄉井別年深，中國靈蹤欲徧尋。',32,'全唐诗/poet.tang.47000.json','["日邊鄉井別年深，中國靈蹤欲徧尋。", "何處碧山逢長老，分明認取祖師心。"]'),
('1f56fc20-e960-4a53-b367-e51a78699014','謝猨皮','齊己','唐','唐诗','tang','','[]','貴向獵師家買得，攜來乞與坐禪牀。',32,'全唐诗/poet.tang.47000.json','["貴向獵師家買得，攜來乞與坐禪牀。", "不知摘月秋潭畔，曾對何人啼斷腸。"]'),
('778e34ea-2f59-4705-b465-87953bf35736','酬光上人','齊己','唐','唐诗','tang','','[]','禪言難後到詩言，坐石心同立月魂。',32,'全唐诗/poet.tang.47000.json','["禪言難後到詩言，坐石心同立月魂。", "應記前秋會吟處，五更猶在老松根。"]'),
('75c43cce-1210-4f49-a314-5fec02c947e1','送僧歸日本','齊己','唐','唐诗','tang','','[]','日東來向日西遊，一鉢閑尋徧九州。',32,'全唐诗/poet.tang.47000.json','["日東來向日西遊，一鉢閑尋徧九州。", "却憶雞林本師寺，欲歸還待海風秋。"]'),
('83a28514-343e-4fea-b5e0-4b88bcd4eabe','庚午歲十五夜對月','齊己','唐','唐诗','tang','','[]','海澄空碧正團圓，吟想玄宗此夜寒。',32,'全唐诗/poet.tang.47000.json','["海澄空碧正團圓，吟想玄宗此夜寒。", "玉兔有情應記得，西邊不見舊長安。"]'),
('2df7eca1-7ae0-4d34-bfd7-f702f8d2ca11','紅薔薇花','齊己','唐','唐诗','tang','','[]','晴日當樓曉香歇，錦帶盤空欲成結。',32,'全唐诗/poet.tang.47000.json','["晴日當樓曉香歇，錦帶盤空欲成結。", "鶯聲漸老柳飛時，狂風吹落猩猩血。"]'),
('72e848a7-3b9d-4c18-a7bb-58066e33c74a','貽九華上人','齊己','唐','唐诗','tang','','[]','一法傳聞繼老能，九華閑臥最高層。',32,'全唐诗/poet.tang.47000.json','["一法傳聞繼老能，九華閑臥最高層。", "秋鐘盡後殘陽暝，門掩松邊雨夜燈。"]'),
('d5e0ae3c-6e96-4a01-a373-58d77de612e7','寄賡匡圖兄弟','齊己','唐','唐诗','tang','','[]','僧外閑吟樂最清，年登八十喪南荆。',32,'全唐诗/poet.tang.47000.json','["僧外閑吟樂最清，年登八十喪南荆。", "風騷作者爲商確，道去碧雲爭幾程。"]'),
('c5dc58f4-2b75-4545-aa69-af394aed671a','句','齊己','唐','唐诗','tang','','[]','春晴游寺客，花落閉門僧。',103,'全唐诗/poet.tang.47000.json','["春晴游寺客，花落閉門僧。", "香傳天下口。", "□貴火前名，角開香滿室，爐動綠凝鐺。", "園林將向夕，風雨更吹花相思坐溪石，□□□山風。", "夕照背高臺，殘鐘殘角催。", "五老峰前相見時，兩無言語各揚眉。", "高人愛惜藏岩裏，白甀封題寄火前。"]'),
('6c35d057-ae49-4086-9600-5abe856c0252','言興','尚顏','唐','唐诗','tang','','[]','矻矻被吟牽，因師賈浪仙。',48,'全唐诗/poet.tang.47000.json','["矻矻被吟牽，因師賈浪仙。", "江山風月處，一十二三年。", "雅頌在於此，浮華致那邊。", "猶慚功未至，謾道近千篇。"]'),
('668250d1-7418-47c5-b787-637e247a4a14','江上秋思','尚顏','唐','唐诗','tang','','[]','到來江上久，誰念旅游心。',48,'全唐诗/poet.tang.47000.json','["到來江上久，誰念旅游心。", "故國無秋信，鄰家有夜砧。", "坐遙翻不睡，愁極却成吟。", "即恐髭連鬢，還爲白所侵。"]'),
('270fde6a-7957-4c84-94ec-7723a0496876','匡山居','尚顏','唐','唐诗','tang','','["\u5e90\u5c71"]','無才加性拙，道理合藏蹤。',48,'全唐诗/poet.tang.47000.json','["無才加性拙，道理合藏蹤。", "是處非深遠，其山已萬重。", "經時隣境戰，獨夜隔雲舂。", "昨日泉中見，常魚亦化龍。"]'),
('6f987a9a-a349-4c29-8c84-b4123e0efe52','夷陵即事','尚顏','唐','唐诗','tang','','[]','不難饒白髮，相續是灘波。',48,'全唐诗/poet.tang.47000.json','["不難饒白髮，相續是灘波。", "避世嫌身晚，思家乞夢多。", "暑衣經雪着，凍硯向陽呵。", "豈謂臨岐路，還聞聖主過。"]'),
('56db223b-ff2e-476c-823f-94cfdbf4dd96','紫閣隱者','尚顏','唐','唐诗','tang','','[]','天高紫閣侵，隱者信沈沈。',48,'全唐诗/poet.tang.47000.json','["天高紫閣侵，隱者信沈沈。", "道長年兼長，雲深草復深。", "如非禪客見，即是獵人尋。", "北笑長安道，埃塵古到今。"]'),
('fb54622e-164a-4a22-bfac-c1bde33b785b','與陳陶處士','尚顏','唐','唐诗','tang','','[]','鍾陵城外住，喻似玉沈泥。',48,'全唐诗/poet.tang.47000.json','["鍾陵城外住，喻似玉沈泥。", "道直貧嫌殺，神清語亦低。", "雪深加酒債，春盡減詩題。", "記得曾邀宿，山茶獨自攜。"]'),
('b7ca159c-233c-4139-b806-ad229af2c67a','與王嵩隱','尚顏','唐','唐诗','tang','','[]','一生吟興僻，方見業精微。',48,'全唐诗/poet.tang.47000.json','["一生吟興僻，方見業精微。", "事若終難得，鄉應不易歸。", "亂收西日葉，雙掩北風扉。", "合國諸卿相，皆曾着布衣。"]'),
('e6b9e2de-f918-40a1-8268-48997009b1be','懷陸龜蒙處士','尚顏','唐','唐诗','tang','','[]','布褐東南隱，相傳繼謝敷。',48,'全唐诗/poet.tang.47000.json','["布褐東南隱，相傳繼謝敷。", "高譚夫子道，靜看海山圖。", "事免傷心否，碁逢敵手無。", "關中花數內，獨不見菖蒲。"]'),
('2a02387b-b2ee-418a-ba00-2ddbdd8f22d2','寄華陰司空侍郎','尚顏','唐','唐诗','tang','','[]','劒[佩]已深扃，茅爲嶽面亭。',50,'全唐诗/poet.tang.47000.json','["劒[佩]已深扃，茅爲嶽面亭。", "詩猶少綺美，畫肯愛丹青。", "換筆修僧史，焚香閱道經。", "相邀來未得，但想鶴儀形。"]'),
('2fef05e6-d56f-437c-b06f-a8c111ebf80f','送陸肱入關','尚顏','唐','唐诗','tang','','[]','舟行復陸行，始得到咸京。',48,'全唐诗/poet.tang.47000.json','["舟行復陸行，始得到咸京。", "准擬何人口，吹噓六義名。", "亂山遙減翠，叢菊早含英。", "衣錦還鄉日，他時有此榮。"]'),
('c05ecb53-2f33-4175-8750-7352d6fc970f','送劉必先','尚顏','唐','唐诗','tang','','[]','力進憑詩業，心焦闕問安。',48,'全唐诗/poet.tang.47000.json','["力進憑詩業，心焦闕問安。", "遠行無處易，孤立本來難。", "楚月船中沒，秦星馬上殘。", "明年有公道，更以命推看。"]'),
('f2375300-e087-40dc-b7b8-fdbbad0ec0ca','寄方干處士','尚顏','唐','唐诗','tang','','[]','格外綴清詩，詩名獨得知。',48,'全唐诗/poet.tang.47000.json','["格外綴清詩，詩名獨得知。", "閑居公道日，醉臥牡丹時。", "海鳥和濤望，山僧帶雪期。", "仍聞稱處士，聖主肯相違。"]'),
('fcc080c4-b886-4586-9337-755823541a29','寄劉逸士','尚顏','唐','唐诗','tang','','[]','無愁無累者，偶向市朝游。',48,'全唐诗/poet.tang.47000.json','["無愁無累者，偶向市朝游。", "此後乘孤艇，依前入亂流。", "高眠歌聖日，下釣坐清秋。", "道不離方寸，而能混俗求。"]'),
('bf296377-319c-4224-85bc-c3b1b426ae8b','送獨孤處士','尚顏','唐','唐诗','tang','','[]','萬里去非忙，惟攜貯藥囊。',48,'全唐诗/poet.tang.47000.json','["萬里去非忙，惟攜貯藥囊。", "山家消夜景，酒肆過年光。", "立鶴洲侵浪，喧蛬壁近床。", "誰人臨上路，乞得變髭方。"]'),
('ce47beba-69cd-4ac1-84dd-e84efbf2964d','早春送人歸岳陽','尚顏','唐','唐诗','tang','','[]','久食主人魚，春來復舊居。',48,'全唐诗/poet.tang.47000.json','["久食主人魚，春來復舊居。", "遠無千里浪，輕有半船書。", "過片晴雲淡，消殘暮雪虛。", "岳陽多異境，搜思勿令疎。"]'),
('1f5bd41e-c3ce-40d3-808b-b1ddb5c35933','冬暮送人','尚顏','唐','唐诗','tang','','[]','長安冬欲盡，又送一遺賢。',48,'全唐诗/poet.tang.47000.json','["長安冬欲盡，又送一遺賢。", "醉後情渾可，言休理不然。", "射衣秦嶺雪，搖月漢江船。", "亦過春兼夏，回期信有蟬。"]'),
('d5c7e3c3-614e-4ed9-b627-81bd40ae0158','送徐道人東游','尚顏','唐','唐诗','tang','','[]','長安人擾擾，獨自有閑心。',48,'全唐诗/poet.tang.47000.json','["長安人擾擾，獨自有閑心。", "海上山中去，風前月下吟。", "引猿秋果熟，藏鶴曉雲深。", "易姓更名數，難教弟子尋。"]'),
('da6ecf10-61e1-474d-b619-077fb0416b08','自紀','尚顏','唐','唐诗','tang','','[]','諸機忘盡未忘詩，似向詩中有所依。',64,'全唐诗/poet.tang.47000.json','["諸機忘盡未忘詩，似向詩中有所依。", "遠境等閑支枕覓，空山容易杖藜歸。", "清猿一一居林叫，白鳥雙雙避釣飛。", "欲畫淨名居士像，焚香願見陸探微。"]'),
('2d750b9a-016e-49c1-8d37-3c37f10cc091','懷智栖上人','尚顏','唐','唐诗','tang','','[]','臨水登山自有期，不同游子暮何之。',64,'全唐诗/poet.tang.47000.json','["臨水登山自有期，不同游子暮何之。", "閑眠默坐身堪賞，已去還來事可知。", "林鳥隔雲飛一餉，草蟲和雨叫多時。", "思君最易令人老，倚檻空吟所寄詩。"]'),
('5ff4ae18-fb4a-4d28-b73c-9682000095db','峽中酬荆南鄭準','尚顏','唐','唐诗','tang','','[]','山齋西向蜀江濆，四載安居復有羣。',64,'全唐诗/poet.tang.47000.json','["山齋西向蜀江濆，四載安居復有羣。", "風雁勢高猶可見，雪猿聲苦不堪聞。", "新詩寫出難勝寶，破衲披行却類雲。", "每喜泝流賓客說，元瑜刀筆潤雄軍。"]'),
('89e8facb-79ed-4258-974f-97412c4786a5','寄荆門鄭準','尚顏','唐','唐诗','tang','','[]','傳衣傳鉢理難論，綺靡銷磨二雅尊。',64,'全唐诗/poet.tang.47000.json','["傳衣傳鉢理難論，綺靡銷磨二雅尊。", "不許姓名留月觀，終攜瓶錫去雲門。", "窗間挂燭通宵在，竹上題詩隔歲存。", "珍重荆門鄭從事，十年同受景升恩。"]'),
('7b39770e-4aa5-46f9-ae2c-e145a51e31a9','將欲再游荆渚留辭岐下司徒','尚顏','唐','唐诗','tang','','[]','竹錫銅瓶配衲衣，殷公樓畔偶然離。',64,'全唐诗/poet.tang.47000.json','["竹錫銅瓶配衲衣，殷公樓畔偶然離。", "白蓮幾看從開日，明月長吟到落時。", "活計本無桑柘潤，疎慵尋有水雲資。", "今朝回去精神別，爲得頭廳宰相詩。"]'),
('b9637703-529c-416a-afbe-7085bf658799','贈村公','尚顏','唐','唐诗','tang','','[]','紬衣木突此鄉尊，白盡鬚眉眼未昏。',64,'全唐诗/poet.tang.47000.json','["紬衣木突此鄉尊，白盡鬚眉眼未昏。", "醉舞神筵隨鼓笛，閑歌聖代和兒孫。", "黍苗一頃垂秋日，茅棟三間映古原。", "也笑長安名利處，紅塵半是馬蹄翻。"]'),
('92a65a08-50dd-4e8f-acaa-7e535932e6df','秋夜吟','尚顏','唐','唐诗','tang','','[]','梧桐雨畔夜愁吟，抖擻衣裾蘚色侵。',32,'全唐诗/poet.tang.47000.json','["梧桐雨畔夜愁吟，抖擻衣裾蘚色侵。", "枉道一生無繫着，湘南山水別人尋。"]'),
('76398943-d3fe-4e9e-9d04-e40410c1d561','讀齊己上人集','尚顏','唐','唐诗','tang','','[]','詩爲儒者禪，此格的惟仙。',48,'全唐诗/poet.tang.47000.json','["詩爲儒者禪，此格的惟仙。", "古雅如周頌，清和甚舜弦。", "冰生聽瀑句，香發早梅篇。", "想得吟成夜，文星照楚天。"]'),
('3ebd9ca3-ea82-4f6a-9017-5275f8915a79','除夜','尚顏','唐','唐诗','tang','','[]','九冬三十夜，寒與暖分開。',48,'全唐诗/poet.tang.47000.json','["九冬三十夜，寒與暖分開。", "坐到四更後，身添一歲來。", "魚燈延臘火，獸炭化春灰。", "青帝今應老，迎新見幾迴。"]'),
('d2b57220-2acf-4fad-b544-64f28c051c33','送人歸鄉','尚顏','唐','唐诗','tang','','[]','多才與命違，末路憶柴扉。',48,'全唐诗/poet.tang.47000.json','["多才與命違，末路憶柴扉。", "白髮何人問，青山一劒歸。", "晴煙獨鳥沒，野渡亂花飛。", "寂寞長亭外，依然空落暉。"]'),
('07818486-2e99-4c98-8c4e-896a92f9ed0c','述懷 一','尚顏','唐','唐诗','tang','','[]','青門聊極望，何事久離羣。',48,'全唐诗/poet.tang.47000.json','["青門聊極望，何事久離羣。", "芳草失歸路，故鄉空暮雲。", "信回陵樹老，夢斷灞流分。", "兄弟正南北，鴻聲堪獨聞。"]'),
('d3d54be8-d5d8-4baa-adc6-3a7788a27172','述懷 二','尚顏','唐','唐诗','tang','','[]','五城初罷構，海上憶閑行。',48,'全唐诗/poet.tang.47000.json','["五城初罷構，海上憶閑行。", "觸雪麻衣靜，登山竹錫輕。", "天寒嶽寺出，日晚島泉清。", "坐與幽期遇，何湖心渺冥。"]'),
('9927f7a8-e7d8-48a3-aea9-081eabd53655','宿壽安甘棠館 一','尚顏','唐','唐诗','tang','','[]','行人方倦役，到此似還鄉。',48,'全唐诗/poet.tang.47000.json','["行人方倦役，到此似還鄉。", "流水來關外，青山近洛陽。", "溪雲歸洞鶴，松月半軒霜。", "坐恐晨鐘動，天涯道路長。"]'),
('2dc5037f-583f-4dda-889c-888c18a3acf2','宿壽安甘棠館 二','尚顏','唐','唐诗','tang','','[]','山空蕙氣香，乳管折雲房。',48,'全唐诗/poet.tang.47000.json','["山空蕙氣香，乳管折雲房。", "願值壺中客，親傳肘後方。", "三更禮星斗，寸匕服丹霜。", "默坐樹陰下，仙經橫石床。"]'),
('c9ce0374-406e-4ee3-8e70-ef99c119d190','送朴山人歸新羅','尚顏','唐','唐诗','tang','','[]','浩渺行無極，揚帆但信風。',48,'全唐诗/poet.tang.47000.json','["浩渺行無極，揚帆但信風。", "雲山過海半，鄉樹入舟中。", "波定遙天出，沙平遠岸窮。", "離心寄何處，目擊曙霞東。"]'),
('ea4b533f-e0ad-4e1f-a492-aa0b45d28482','宿清遠峽山寺','尚顏','唐','唐诗','tang','','[]','寺近朝天路，多聞玉佩音。',48,'全唐诗/poet.tang.47000.json','["寺近朝天路，多聞玉佩音。", "鑒人開慧眼，歸鳥息禪心。", "磬接星河曙，窗連夏木深。", "此中能宴坐，何必在雲林。"]'),
('687d1418-a6b6-4ff4-b446-44e5bd9935d8','松山嶺','尚顏','唐','唐诗','tang','','["\u534e\u5c71"]','平生閑放久，野鹿許爲羣。',48,'全唐诗/poet.tang.47000.json','["平生閑放久，野鹿許爲羣。", "居止隣西嶽，軒窗度白雲。", "齋心飯松子，話道接茅君。", "漢主恩情去，空山起夕氛。"]'),
('273368a8-8c26-4736-bf01-939f582685f8','句','尚顏','唐','唐诗','tang','','[]','浸浸三楚白，渺渺九江寒。',12,'全唐诗/poet.tang.47000.json','["浸浸三楚白，渺渺九江寒。"]'),
('e08c14bd-385a-4be6-a954-c5d106110edc','泊洞庭','虛中','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','槐柳未知秋，依依舘驛頭。',48,'全唐诗/poet.tang.47000.json','["槐柳未知秋，依依舘驛頭。", "客心俱念遠，時雨自相留。", "浪沒貨魚市，帆高賣酒樓。", "夜來思展轉，故里在南州。"]'),
('6cafa341-07c3-4071-9069-1f77081c28e3','善卷壇','虛中','唐','唐诗','tang','','[]','耕荒鑿原時，高趣在希夷。',48,'全唐诗/poet.tang.47000.json','["耕荒鑿原時，高趣在希夷。", "大舜欲遜國，先生空歛眉。", "五溪清不足，千古美無虧。", "縱遣亡淳者，何人投所思。"]'),
('34345b1e-92d4-4713-933b-d9d0bdbba149','石城金谷','虛中','唐','唐诗','tang','','[]','晉祚一傾摧，驕奢去不回。',48,'全唐诗/poet.tang.47000.json','["晉祚一傾摧，驕奢去不回。", "只應荆棘地，猶作綺羅灰。", "狐兔閑生長，樵蘇靜往來。", "踟躕意無盡，寒日又西頹。"]'),
('9715cfbe-8ab3-44e0-90d0-a80c382a94de','庾樓','虛中','唐','唐诗','tang','','["\u5e90\u5c71"]','郡樓名甚遠，幾換見樓人。',48,'全唐诗/poet.tang.47000.json','["郡樓名甚遠，幾換見樓人。", "庾亮魂應在，清風到白蘋。", "晴軒分楚漢，夜酒揖星辰。", "何必匡山上，獨言無世塵。"]'),
('d1064f15-c3f7-42e8-8c82-0f03743437b7','經賀監舊居','虛中','唐','唐诗','tang','','[]','不戀明皇寵，歸來鏡水隅。',48,'全唐诗/poet.tang.47000.json','["不戀明皇寵，歸來鏡水隅。", "道裝汀鶴識，春醉釣人扶。", "逐朵雲如吐，成行雁侶驅。", "蘭亭名景在，蹤跡未爲孤。"]'),
('ea4b05c6-98bc-4e70-bf01-9d26f3cca3b6','獻鄭都官','虛中','唐','唐诗','tang','','[]','早晚辭班列，歸尋舊隱峰。',48,'全唐诗/poet.tang.47000.json','["早晚辭班列，歸尋舊隱峰。", "代移家集在，身老詔書重。", "藥秘仙都訣，茶開蜀國封。", "何當荅羣望，高躡傅巖蹤。"]'),
('40b49788-12e5-42b3-9662-387e0e252805','寄華山司空圖二首 一','虛中','唐','唐诗','tang','','[]','門徑放莎垂，往來投刺稀。',48,'全唐诗/poet.tang.47000.json','["門徑放莎垂，往來投刺稀。", "有時開御札，特地掛朝衣。", "嶽信僧傳去，仙香鶴帶歸。", "他年二南化，無復更衰微。"]'),
('2b316389-b872-4912-ae40-10058b633bfa','寄華山司空圖二首 二','虛中','唐','唐诗','tang','','[]','逍遙短褐成，一劒動精靈。',48,'全唐诗/poet.tang.47000.json','["逍遙短褐成，一劒動精靈。", "白晝夢仙島，清晨禮道經。", "黍苗侵野徑，桑椹汚閑庭。", "肯要爲隣者，西南太華青。"]'),
('65085bd6-6bb6-43e3-8816-4b1d7b7084cb','贈屏風巖栖蟾上人','虛中','唐','唐诗','tang','','[]','巖房高且靜，住此幾寒暄。',48,'全唐诗/poet.tang.47000.json','["巖房高且靜，住此幾寒暄。", "鹿嗅安禪石，猿啼乞食村。", "朝陽生樹罅，古路透雲根。", "獨我閑相覓，淒涼碧洞門。"]'),
('52cbb85b-45a7-44d2-ae18-bf18fbe9b776','贈秀才','虛中','唐','唐诗','tang','','[]','筠陽多勝致，夫子縱游遨。',48,'全唐诗/poet.tang.47000.json','["筠陽多勝致，夫子縱游遨。", "鳳鳥瑞不見，鱸魚價轉高。", "門開沙觜靜，船繫樹根牢。", "誰解伊人趣，村沽對鬱陶。"]'),
('4b887966-6c20-4f5f-9c18-d4aead5c6517','送遷客','虛中','唐','唐诗','tang','','["\u52c9\u52b1", "\u9001\u522b", "\u8d2c\u8c2a", "\u53cb\u60c5"]','倏忽墮鵷行，天南去路長。',48,'全唐诗/poet.tang.47000.json','["倏忽墮鵷行，天南去路長。", "片言曾不諂，獲罪亦何傷。", "象戀藏牙浦，人貪賣子鄉。", "此心終合雪，去已莫思量。"]'),
('4f47c3d0-21eb-48ca-80da-94baa2fa5ccc','哭悼朝賢','虛中','唐','唐诗','tang','','[]','前昨回私第，旋聞寢疾終。',48,'全唐诗/poet.tang.47000.json','["前昨回私第，旋聞寢疾終。", "四隣方響絕，二月牡丹空。", "冢已遷名境，碑仍待至公。", "秪應遺愛理，長在楚南風。"]'),
('936c1ba5-e210-4f7c-a1b2-ccc6791b9b31','悼方干處士','虛中','唐','唐诗','tang','','[]','先生在世日，秪向鏡湖居。',48,'全唐诗/poet.tang.47000.json','["先生在世日，秪向鏡湖居。", "明主未巡狩，白頭閑釣魚。", "煙莎一徑小，洲島四隣疎。", "獨有爲儒者，時來弔舊廬。"]'),
('fdc4cc6f-de8f-4666-a268-96e926fb8644','聽軒轅先生琴','虛中','唐','唐诗','tang','','[]','訣妙與功精，通宵膝上橫。',48,'全唐诗/poet.tang.47000.json','["訣妙與功精，通宵膝上橫。", "一堂風冷淡，千古意分明。", "坐客禪魂凝，巢禽耳目傾。", "酷哉商紂世，曾不遇先生。"]'),
('dec985f9-1def-4e04-8129-5690c355ac5c','芳草','虛中','唐','唐诗','tang','','[]','綿綿芳草綠，何處動深思。',48,'全唐诗/poet.tang.47000.json','["綿綿芳草綠，何處動深思。", "金谷人亡後，沙塲日暖時。", "龍鱗藏有瑞，風雨灑無私。", "欲採蘭兼蕙，清香可贈誰。"]'),
('2ebe1586-9399-45d2-a42f-168cab2fff0d','句','虛中','唐','唐诗','tang','','[]','喜魚在深處，幽鳥立多時。',72,'全唐诗/poet.tang.47000.json','["喜魚在深處，幽鳥立多時。", "菖蒲花不豔，鸜鵒性多靈。", "盤中是祥瑞，天下恰炎蒸。", "待暖還須去，門前有路岐。", "春雨無高下，花枝有短長。", "老負峨眉月，閑看雲水心。"]'),
('fd04194c-ad1c-4635-a9cc-0c057f1f6bcc','短歌行','棲蟾','唐','唐诗','tang','','[]','蟾光堪自笑，浮世懶思量。',48,'全唐诗/poet.tang.47000.json','["蟾光堪自笑，浮世懶思量。", "身得幾時活，眼開終日忙。", "千門無壽藥，一鏡有愁霜。", "早向塵埃外，光陰任短長。"]'),
('1925c281-86a5-43e5-a464-a07c8c30f866','除夜','棲蟾','唐','唐诗','tang','','[]','九冬三十夜，寒與暖分開。',48,'全唐诗/poet.tang.47000.json','["九冬三十夜，寒與暖分開。", "坐到四更後，身添一歲來。", "魚燈延臘火，獸炭化春灰。", "青帝今應老，迎新見幾回。"]'),
('a717944f-1652-4184-a9b8-bdd48f413328','宿巴江','棲蟾','唐','唐诗','tang','','[]','江聲五十里，瀉碧急于弦。',48,'全唐诗/poet.tang.47000.json','["江聲五十里，瀉碧急于弦。", "不覺日又夜，爭教人少年。", "一汀巫峽月，兩岸子規天。", "山影似相伴，濃遮到曉船。"]'),
('15ab3ff3-26f6-43b3-ac55-dfc56341a970','游邊','棲蟾','唐','唐诗','tang','','[]','邊雲四顧濃，飢馬嗅枯叢。',48,'全唐诗/poet.tang.47000.json','["邊雲四顧濃，飢馬嗅枯叢。", "萬里八九月，一身西北風。", "偷營天正黑，戰地雪多紅。", "昨夜東歸夢，桃花煖色中。"]'),
('ba7be46f-15f0-497d-ba81-7e731c6b8fc2','居南嶽懷沈彬','棲蟾','唐','唐诗','tang','','["\u8861\u5c71"]','石房開竹扉，茗外獨支頤。',48,'全唐诗/poet.tang.47000.json','["石房開竹扉，茗外獨支頤。", "萬木還無葉，百年能幾時。", "隔雲聞狖過，截雨見虹垂。", "因憶嶽南客，晏眠吟好詩。"]'),
('fd631736-f18f-45dd-a65a-2c61d5785bd9','南中懷友生','棲蟾','唐','唐诗','tang','','[]','荔枝江上立，望北幾思量。',48,'全唐诗/poet.tang.47000.json','["荔枝江上立，望北幾思量。", "隔海無書劄，前年在漢陽。", "瘴村人起早，銅柱象揩光。", "居此成何事，尋君過碧湘。"]'),
('fff94eb7-4c7c-43f2-9d0a-9ff2c66a2186','贈南嶽玄泰布衲','棲蟾','唐','唐诗','tang','','["\u8861\u5c71"]','曹溪入室人，終老甚難羣。',48,'全唐诗/poet.tang.47000.json','["曹溪入室人，終老甚難羣。", "四十餘年內，青山與白雲。", "松和巢鶴看，果共野猨分。", "海外僧來說，名高自小聞。"]'),
('97cea944-7823-436d-a241-3801ab018d2d','寄問政山聶威儀','棲蟾','唐','唐诗','tang','','[]','先生臥碧岑，諸祖是知音。',48,'全唐诗/poet.tang.47000.json','["先生臥碧岑，諸祖是知音。", "得道無一法，孤雲同寸心。", "嵐光薰鶴詔，茶味敵人參。", "苦向壺中去，他年許我尋。"]'),
('946c715d-44c6-4899-8744-ba71b4a36f6e','送遷客','棲蟾','唐','唐诗','tang','','["\u9001\u522b", "\u8d2c\u8c2a", "\u53cb\u60c5", "\u60cb\u60dc"]','諫頻甘得罪，一騎入南深。',48,'全唐诗/poet.tang.47000.json','["諫頻甘得罪，一騎入南深。", "若順吾皇意，即無臣子心。", "織花蠻市布，擣月象州砧。", "蒙雪知何日，凭樓望北吟。"]'),
('4f73f990-4a4d-4e94-b59e-06654888b990','讀齊己上人集','棲蟾','唐','唐诗','tang','','[]','詩爲儒者禪，此格的惟仙。',48,'全唐诗/poet.tang.47000.json','["詩爲儒者禪，此格的惟仙。", "古雅如周頌，清和甚舜弦。", "冰生聽瀑句，香發早梅篇。", "想得吟成夜，文星照楚天。"]'),
('159a79d5-d709-4258-9a7d-47ec058cc11e','牧童','棲蟾','唐','唐诗','tang','','[]','牛得自由騎，春風細雨飛。',48,'全唐诗/poet.tang.47000.json','["牛得自由騎，春風細雨飛。", "青山青草裏，一笛一蓑衣。", "日出唱歌去，月明撫掌歸。", "何人得似爾，無是亦無非。"]'),
('4462d7aa-576b-4b06-b2b9-12a0b8fe725a','再宿京口禪院','棲蟾','唐','唐诗','tang','','[]','灘聲依舊水溶溶，岸影參差對梵宮。',64,'全唐诗/poet.tang.47000.json','["灘聲依舊水溶溶，岸影參差對梵宮。", "楚樹七回凋舊葉，江人兩至宿秋風。", "蟾蜍竹老搖疎白，菡萏池乾落碎紅。", "多病支郎念行止，晚年生計轉如蓬。"]'),
('4caea753-1511-4f21-9ef2-f87486b87b20','耕田鼓詩','可朋','唐','唐诗','tang','','[]','農舍田頭鼓，王孫筵上鼓。',66,'全唐诗/poet.tang.47000.json','["農舍田頭鼓，王孫筵上鼓。", "擊鼓兮皆爲鼓，一何樂兮一何苦。", "上有烈日，下有焦土。", "願我天翁，降之以雨。", "令桑麻熟，倉箱富。", "不飢不寒，上下一般。"]'),
('20f5d8ee-f575-48be-b551-2dfd9c3db937','賦洞庭','可朋','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','周極八百里，凝眸望則勞。',48,'全唐诗/poet.tang.47000.json','["周極八百里，凝眸望則勞。", "水涵天影闊，山拔地形高。", "賈客停非久，漁翁轉幾遭。", "颯然風起處，又是鼓波濤。"]'),
('8135987e-407b-4790-a56c-951db9cdf4d7','贈方干','可朋','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','盛名傳出自皇州，一舉參差便縮頭。',64,'全唐诗/poet.tang.47000.json','["盛名傳出自皇州，一舉參差便縮頭。", "月裏豈無攀桂分，湖中剛愛釣魚休。", "童偷詩藁呈鄰叟，客乞書題謁郡侯。", "獨泛短舟何限景，波濤西接洞庭秋。"]'),
('907611ce-a590-422e-af15-4681d72c2a43','桐花鳥','可朋','唐','唐诗','tang','','[]','五色毛衣比鳳雛，深花叢裏祗如無。',32,'全唐诗/poet.tang.47000.json','["五色毛衣比鳳雛，深花叢裏祗如無。", "美人買得偏憐惜，移向金釵重幾銖。"]'),
('d41d4a79-10ef-45b6-80a1-ff2b0e754d9c','句','可朋','唐','唐诗','tang','','[]','來多不似客，坐久却垂簾。',88,'全唐诗/poet.tang.47000.json','["來多不似客，坐久却垂簾。", "虹收千嶂雨，潮展半江天。", "詩因試客分題僻，棊爲饒人下著低。", "傷心盡日有啼鳥，獨步殘春空落花。", "唯陪北楚三千客，多話東林十八賢。", "乍當暖景飛仍慢，欲就芳叢舞更高。"]'),
('f87fd39b-48c1-4744-9007-492620647204','宿鄭諫議山居','曇域','唐','唐诗','tang','','[]','堂開星斗邊，大諫採薇還。',48,'全唐诗/poet.tang.47000.json','["堂開星斗邊，大諫採薇還。", "禽隱石中樹，月生池上山。", "涼風吹詠思，幽語隔禪關。", "莫擬歸城計，終妨此地閑。"]'),
('166fd5fa-a55f-4ef6-b03d-7ad19fb07857','懷齊己','曇域','唐','唐诗','tang','','[]','鬢髯秋景兩蒼蒼，靜對茅齋一炷香。',64,'全唐诗/poet.tang.47000.json','["鬢髯秋景兩蒼蒼，靜對茅齋一炷香。", "病後身心俱澹泊，老來朋友半凋傷。", "峨眉山色侵雲直，巫峽灘聲入夜長。", "猶喜深交有支遁，時時音信到松房。"]'),
('62819c51-0ce0-4d87-8093-6bdbed30aa84','贈島雲禪師','曇域','唐','唐诗','tang','','[]','遠庵枯葉滿，羣鹿亦相隨。',48,'全唐诗/poet.tang.47000.json','["遠庵枯葉滿，羣鹿亦相隨。", "頂骨生新髮，庭松長舊枝。", "禪高太白月，行出祖師碑。", "亂後潛來此，南人總不知。"]'),
('a2a8fb60-2a91-43ec-8b27-0b5ed1939f24','垓下懷古','栖一','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u548f\u53f2\u6000\u53e4", "\u5730\u540d"]','緬想咸陽事可嗟，楚歌哀怨思無涯。',64,'全唐诗/poet.tang.47000.json','["緬想咸陽事可嗟，楚歌哀怨思無涯。", "八千子弟歸何處，萬里鴻溝屬漢家。", "弓指陣前爭日月，血流垓下定龍蛇。", "拔山力盡烏江水，今古悠悠空浪花。"]'),
('cb001d8b-9f57-43b4-884a-2cd5d29f44ea','武昌懷古','栖一','唐','唐诗','tang','','[]','戰國城池盡悄然，昔人遺迹遍山川。',64,'全唐诗/poet.tang.47000.json','["戰國城池盡悄然，昔人遺迹遍山川。", "笙歌罷吹幾多日，臺榭荒涼七百年。", "蟬響夕陽風滿樹，雁橫秋島雨漫天。", "堪嗟世事如流水，空見蘆花一釣船。"]'),
('91b8805d-725e-42d5-9eab-60ad0f580982','聖果寺','處默','唐','唐诗','tang','','[]','路自中峰上，盤回出薜蘿。',48,'全唐诗/poet.tang.47000.json','["路自中峰上，盤回出薜蘿。", "到江吳地盡，隔岸越山多。", "古木叢青靄，遙天浸白波。", "下方城郭近，鐘磬雜笙歌。"]'),
('e371a6ae-c713-4bc9-823f-c29f940d22a3','送僧游西域','處默','唐','唐诗','tang','','[]','一盂兼一錫，秪此度流沙。',48,'全唐诗/poet.tang.47000.json','["一盂兼一錫，秪此度流沙。", "野性雖爲客，禪心即是家。", "寺披雲嶠雪，路入曉天霞。", "自說游諸國，回應歲月賒。"]'),
('dbef36be-4107-49c7-a04d-44aed14f192e','遠煙','處默','唐','唐诗','tang','','[]','靄靄前山上，凝光滿薜蘿。',48,'全唐诗/poet.tang.47000.json','["靄靄前山上，凝光滿薜蘿。", "高風吹不盡，遠樹得偏多。", "翠與晴雲合，輕將淑氣和。", "正堪流野目，朱閣意如何。"]'),
('6d1cd574-9e71-4128-aeaa-0c61cea4a307','螢','處默','唐','唐诗','tang','','[]','熠熠與娟娟，池塘竹樹邊。',48,'全唐诗/poet.tang.47000.json','["熠熠與娟娟，池塘竹樹邊。", "亂飛如拽火，成聚却無煙。", "微雨灑不滅，輕風吹欲燃。", "昔時書案上，頻把作囊懸。"]'),
('1e9094d5-7bb7-4867-811c-83ac4449dcd7','憶廬山舊居','處默','唐','唐诗','tang','','["\u5e90\u5c71"]','麤衣糲食老煙霞，勉把衰顏惜歲華。',64,'全唐诗/poet.tang.47000.json','["麤衣糲食老煙霞，勉把衰顏惜歲華。", "獨鶴秪爲山客伴，閑雲常在野僧家。", "叢生嫩蕨黏松粉，自落乾薪帶蘚花。", "明月清風舊相得，十年歸恨可能賒。"]'),
('9cfa4e3f-a3b0-4db7-9caa-08e2d8efb25d','題棲霞寺僧房','處默','唐','唐诗','tang','','[]','名山不取買山錢，任構花宮近碧巔。',64,'全唐诗/poet.tang.47000.json','["名山不取買山錢，任構花宮近碧巔。", "松檜老依雲裏寺，樓臺深鎖洞中天。", "風經絕嶂回疎雨，石倚危屏挂落泉。", "欲結茅菴共師住，肯饒多少薜蘿煙。"]'),
('cd92c23c-af43-4f85-a310-31fd3b15ba63','山中作','處默','唐','唐诗','tang','','[]','席簾高捲枕高攲，門掩垂蘿蘸碧溪。',32,'全唐诗/poet.tang.47000.json','["席簾高捲枕高攲，門掩垂蘿蘸碧溪。", "閑把史書眠一覺，起來山日過松西。"]'),
('df95f1da-9e42-4f3b-b34b-50e23b3b0d86','織婦','處默','唐','唐诗','tang','','[]','蓬鬢蓬門積恨多，夜闌燈下不停梭。',32,'全唐诗/poet.tang.47000.json','["蓬鬢蓬門積恨多，夜闌燈下不停梭。", "成縑猶自陪錢納，未直青樓一曲歌。"]'),
('021259c6-3fb7-4e1e-9fce-17b453c4e106','句','處默','唐','唐诗','tang','','[]','太平時節無人看，雪刃閑封滿匣塵。',16,'全唐诗/poet.tang.47000.json','["太平時節無人看，雪刃閑封滿匣塵。"]'),
('44f6bfb2-a329-465b-82b5-75400f5ecfd4','秋日閑居','修睦','唐','唐诗','tang','','[]','是事不相關，誰人似此閑。',48,'全唐诗/poet.tang.47000.json','["是事不相關，誰人似此閑。", "卷簾當白晝，移榻對青山。", "野鶴眠松上，秋苔長雨間。", "岳僧頻有信，昨日得書還。"]'),
('15234a58-dec1-45d7-9e3a-e06a1484b1c7','宿岳陽開元寺','修睦','唐','唐诗','tang','','[]','竟夕憑虛檻，何當興歎頻。',48,'全唐诗/poet.tang.47000.json','["竟夕憑虛檻，何當興歎頻。", "往來人自老，今古月常新。", "風逆沈魚唱，松疎露鶴身。", "無眠鐘又動，幾客在迷津。"]'),
('c1aa3c81-c47f-4201-bfe0-d85f933fd671','送邊將','修睦','唐','唐诗','tang','','[]','人盡有離別，而君獨可嗟。',48,'全唐诗/poet.tang.47000.json','["人盡有離別，而君獨可嗟。", "言將身報國，敢望祿榮家。", "戰思風吹野，鄉心月照沙。", "歸期定何日，塞北樹無花。"]'),
('5d806b2e-0e90-4790-9aa8-1bd34ebd186b','雪中送人北遊','修睦','唐','唐诗','tang','','[]','然知心去速，其奈雪飛頻。',48,'全唐诗/poet.tang.47000.json','["然知心去速，其奈雪飛頻。", "莫喜無危道，雖平更陷人。", "遠郊光接漢，曠野色通秦。", "此去迢遙極，却回應過春。"]'),
('27ce7c9c-eab7-4d70-ac69-4bf7cf7db5a7','落葉','修睦','唐','唐诗','tang','','[]','雨過閑田地，重重落葉紅。',48,'全唐诗/poet.tang.47000.json','["雨過閑田地，重重落葉紅。", "翻思向春日，肯信有秋風。", "幾處隨流水，河邊亂暮空。", "秪應松自立，而不與君同。"]'),
('eb09df72-3dd3-4c98-8296-d3add5beec30','落花','修睦','唐','唐诗','tang','','[]','一片又一片，等閑苔面紅。',48,'全唐诗/poet.tang.47000.json','["一片又一片，等閑苔面紅。", "不能延數日，開亦是春風。", "公子歌聲歇，詩人眼界空。", "遙思故山下，經雨兩三叢。"]'),
('0e0cc50d-f64b-4f34-81f3-82162a0e5797','題田道者院','修睦','唐','唐诗','tang','','[]','入門空寂寂，真箇出家兒。',48,'全唐诗/poet.tang.47000.json','["入門空寂寂，真箇出家兒。", "有行鬼不見，無心人謂癡。", "古巖寒柏對，流水落花隨。", "欲別一何嬾，相從所恨遲。"]'),
('ecedbedb-0105-4c06-b1e2-6d228fcc1d66','東林寺','修睦','唐','唐诗','tang','','["\u8861\u5c71"]','欲去不忍去，徘徊吟繞廊。',48,'全唐诗/poet.tang.47000.json','["欲去不忍去，徘徊吟繞廊。", "水光秋澹蕩，僧好語尋常。", "碑古苔文疊，山晴鐘韻長。", "翻思南嶽上，欠此白蓮香。"]'),
('bbc9b01a-1d32-4f48-8e6e-57608d18727e','寄貫休上人','修睦','唐','唐诗','tang','','[]','常語亦關詩，常流安得知。',48,'全唐诗/poet.tang.47000.json','["常語亦關詩，常流安得知。", "楚郊來未久，吳地住多時。", "立月無人近，歸林有鶴隨。", "所居渾不遠，相識偶然遲。"]'),
('38e58ff3-3798-41fb-a24c-cf426ac6a448','喜僧友到','修睦','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','十年消息斷，空使夢煙蘿。',48,'全唐诗/poet.tang.47000.json','["十年消息斷，空使夢煙蘿。", "嵩嶽幾時下，洞庭何日過。", "瓶乾離澗久，衲壞臥雲多。", "意欲相留住，游方肯舍麽。"]'),
('c5432009-d47e-4967-a3cf-a69df2097e82','懷虛中上人','修睦','唐','唐诗','tang','','[]','簷雨滴更殘，思君安未安。',48,'全唐诗/poet.tang.47000.json','["簷雨滴更殘，思君安未安。", "湘川聞不遠，道路去尋難。", "吟鬢霜應蝕，禪衣雪漸寒。", "倚松因獨立，一鳥下江干。"]'),
('87d6f59f-c5e9-41c3-b50d-425a27118e22','簡寂觀','修睦','唐','唐诗','tang','','[]','正同高士坐煙霞，思著閑忙又是嗟。',64,'全唐诗/poet.tang.47000.json','["正同高士坐煙霞，思著閑忙又是嗟。", "碧岫觀中人似鶴，紅塵路上事如麻。", "石肥滯雨添蒼蘚，松老涵風落翠花。", "莫道此間無我分，遺民長在惠持家。"]'),
('c0b2822b-c3a2-4131-b389-a26a669cbf34','睡起作','修睦','唐','唐诗','tang','','[]','長空秋雨歇，睡起覺精神。',48,'全唐诗/poet.tang.47000.json','["長空秋雨歇，睡起覺精神。", "看水看山坐，無名無利身。", "偈吟諸祖意，茶碾去年春。", "此外誰相識，孤雲到砌頻。"]'),
('9286f193-d032-4fa3-bfe4-0be15744c9eb','賣松者','修睦','唐','唐诗','tang','','[]','求利有何限，將松入市來。',48,'全唐诗/poet.tang.47000.json','["求利有何限，將松入市來。", "直饒人買去，也向柳邊栽。", "細葉猶粘雪，孤根尚惹苔。", "知君用心錯，舉世重花開。"]'),
('048b5ca3-0baa-44d1-866a-57ba47125a58','思齊己上人','修睦','唐','唐诗','tang','','[]','同人與流俗，相謂好襟靈。',48,'全唐诗/poet.tang.47000.json','["同人與流俗，相謂好襟靈。", "有口不他說，長年自誦經。", "水聲秋後石，山色晚來庭。", "客問修何法，指松千歲青。"]'),
('f7f86afd-654a-4ad9-9716-1c4b159ddbe4','送玄泰禪師','修睦','唐','唐诗','tang','','[]','去去去何住，一盂兼一瓶。',48,'全唐诗/poet.tang.47000.json','["去去去何住，一盂兼一瓶。", "水邊寒草白，島外晚峰青。", "宿處林聞虎，行時天有星。", "回期誰可定，浮世重看經。"]'),
('16f0adc7-ea5d-485d-b09b-8e8845044975','三生石','修睦','唐','唐诗','tang','','[]','聖迹誰會得，每到亦徘徊。',48,'全唐诗/poet.tang.47000.json','["聖迹誰會得，每到亦徘徊。", "一尚不可得，三從何處來。", "清宵寒露滴，白晝野雲隈。", "應是表靈異，凡情安可猜。"]'),
('f020c2a1-d202-4922-bce4-387eeeea7cd4','題僧夢微房','修睦','唐','唐诗','tang','','[]','東海日未出，九衢人已行。',48,'全唐诗/poet.tang.47000.json','["東海日未出，九衢人已行。", "吾師無事坐，苔蘚入門生。", "雨過閑花落，風來古木聲。", "天台頻說法，石壁欠題名。"]'),
('25d7f357-1554-43a4-8688-3bd027cadc36','秋臺作','修睦','唐','唐诗','tang','','[]','獨上高樓上，客情何物同。',48,'全唐诗/poet.tang.47000.json','["獨上高樓上，客情何物同。", "孤雲無定處，長日信秋風。", "兄弟多年別，關河此夕中。", "到頭歸去是，免使歎洪濛。"]'),
('18463c2e-0730-4b72-8214-c8448f6b8566','懷故園','修睦','唐','唐诗','tang','','[]','故園歸未得，此日意何傷。',24,'全唐诗/poet.tang.47000.json','["故園歸未得，此日意何傷。", "獨坐水邊草，水流春日長。"]'),
('079143ac-83f5-48e4-8fc9-40297701aa69','謝武肅王','無作','唐','唐诗','tang','','[]','雲鶴性孤單，爭堪名利關。',24,'全唐诗/poet.tang.47000.json','["雲鶴性孤單，爭堪名利關。", "銜恩雖入國，辭命却歸山。"]'),
('639b3939-c861-43d4-8228-8765fc97b9f8','哭僧','清尚','唐','唐诗','tang','','[]','道力自超然，身亡同坐禪。',48,'全唐诗/poet.tang.47000.json','["道力自超然，身亡同坐禪。", "水流元在海，月落不離天。", "溪白葬時雪，風香焚處煙。", "世人頻下淚，不見我師玄。"]'),
('96fd575b-1bc3-4bc2-ae45-8bab9fc348d0','投謁齊己','乾康','唐','唐诗','tang','','[]','隔岸紅塵忙似火，當軒青嶂冷如冰。',32,'全唐诗/poet.tang.47000.json','["隔岸紅塵忙似火，當軒青嶂冷如冰。", "烹茶童子休相問，報道門前是衲僧。"]'),
('1dff6459-89b1-4569-8bb1-394183e706e3','賦殘雪','乾康','唐','唐诗','tang','','[]','六出奇花已住開，郡城相次見樓臺。',32,'全唐诗/poet.tang.47000.json','["六出奇花已住開，郡城相次見樓臺。", "時人莫把和泥看，一片飛從天上來。"]'),
('84914311-08ad-4d7f-b270-96b68e642831','句','乾康','唐','唐诗','tang','','[]','鏡湖中有月，處士後無人。',24,'全唐诗/poet.tang.47000.json','["鏡湖中有月，處士後無人。", "荻笋抽高節，鱸魚躍老鱗。"]'),
('36721980-a020-45b3-a6c5-aef15ffeac13','招隱','曇翼','唐','唐诗','tang','','[]','連峰數千里，修林帶平津。',60,'全唐诗/poet.tang.47000.json','["連峰數千里，修林帶平津。", "雲起遠山翳，風至□荒榛。", "茅茨隱不見，雞鳴知有人。", "躡磴踐其跡，處處見遺薪。", "乃知百代下，固有上皇民。"]'),
('3ff1c567-fdc9-4074-a407-5e924babb4c3','石橋琪樹','隱求','唐','唐诗','tang','','[]','山上天將近，人間路漸遙。',24,'全唐诗/poet.tang.47000.json','["山上天將近，人間路漸遙。", "誰當雲裏見，知欲渡仙橋。"]'),
('468989a5-0c33-488a-ab49-05d65c5444e0','律僧','智遠','唐','唐诗','tang','','[]','濾水與龕燈，長長護有情。',48,'全唐诗/poet.tang.47000.json','["濾水與龕燈，長長護有情。", "自從青草出，便不下階行。", "北闕應無夢，南山舊有名。", "將何喻浮世，惟指浪漚輕。"]'),
('bec8a074-2a1c-4859-a40e-24e878910fff','暮春送人','無悶','唐','唐诗','tang','','[]','折柳亭邊手重攜，江煙澹澹草萋萋。',32,'全唐诗/poet.tang.47000.json','["折柳亭邊手重攜，江煙澹澹草萋萋。", "杜鵑不解離人意，更向落花枝上啼。"]'),
('00a09c6e-99bd-4d5d-8bb5-a55d580673be','寒林石屏','無悶','唐','唐诗','tang','','[]','草堂無物伴身閑，惟有屏風枕簟間。',32,'全唐诗/poet.tang.47000.json','["草堂無物伴身閑，惟有屏風枕簟間。", "本向他山求得石，却於石上看他山。"]'),
('7a5c02f2-ba1a-4d02-938e-99c57e580258','江上秋志','尚志','唐','唐诗','tang','','[]','到來江上久，誰念旅游心。',48,'全唐诗/poet.tang.47000.json','["到來江上久，誰念旅游心。", "故國無秋信，隣家有暮砧。", "坐遙翻不睡，愁極却成吟。", "即恐髭連鬢，還爲白所侵。"]'),
('fada1a94-40e4-4c5a-a484-febb24eb2e78','路','玄寶','唐','唐诗','tang','','[]','南北東西去，茫茫萬古塵。',48,'全唐诗/poet.tang.47000.json','["南北東西去，茫茫萬古塵。", "關河無盡處，風雪有行人。", "險極山通蜀，平多地入秦。", "營營名利者，來往豈辭頻。"]'),
('0c2fd0f8-90e3-4790-94ba-7714cca5905d','贈智舟三藏','懷浦','唐','唐诗','tang','','[]','壯歲心難伏，師心伏豈難。',48,'全唐诗/poet.tang.47000.json','["壯歲心難伏，師心伏豈難。", "尋常獨在院，行坐不離壇。", "岳雪當禪暝，松聲入咒寒。", "更因文字外，多把史書看。"]'),
('63c10bec-1587-4264-9821-0c16864d5f01','初冬旅舍早懷','懷浦','唐','唐诗','tang','','[]','枕上角聲微，離情未息機。',48,'全唐诗/poet.tang.47000.json','["枕上角聲微，離情未息機。", "夢回三楚寺，寒入五更衣。", "月沒棲禽動，霜晴凍葉飛。", "自慙行役早，深與道相違。"]'),
('02f270a1-676f-4385-a33e-2d4b7db7be5e','對御書後一絕','亞棲','唐','唐诗','tang','','[]','通神筆法得玄門，親入長安謁至尊。',32,'全唐诗/poet.tang.47000.json','["通神筆法得玄門，親入長安謁至尊。", "莫怪出來多意氣，草書曾悅聖明君。"]'),
('dec2fee7-6e47-4f44-b57e-f3c4c40ceef5','題英禪師','亞棲','唐','唐诗','tang','','[]','將知德行異尋常，每見持經在道場。',32,'全唐诗/poet.tang.47000.json','["將知德行異尋常，每見持經在道場。", "欲識用心精潔處，一瓶秋水一爐香。"]'),
('5455b735-c6e9-4a0b-ba42-b9222d745bf9','別友人','惟審','唐','唐诗','tang','','[]','一身無定處，萬里獨銷魂。',48,'全唐诗/poet.tang.47000.json','["一身無定處，萬里獨銷魂。", "芳草迷歸路，春衣滴淚痕。", "幾時休旅食，向夜宿江村。", "欲識異鄉苦，空山啼暮猨。"]'),
('011b8349-5bb4-4515-8c7c-15d806536c9d','賦得聞曉鶯啼','惟審','唐','唐诗','tang','','[]','捲簾清夢後，芳樹引流鶯。',48,'全唐诗/poet.tang.47000.json','["捲簾清夢後，芳樹引流鶯。", "隔葉傳春意，穿花送曉聲。", "未調雲路翼，空負桂枝情。", "莫盡關關興，羇愁正厭生。"]'),
('9d1b26f2-0a5d-4b77-80ee-91f44dead780','春日旅懷呈知己','惟審','唐','唐诗','tang','','[]','生涯萬事有蒼蒼，應任流萍便越鄉。',64,'全唐诗/poet.tang.47000.json','["生涯萬事有蒼蒼，應任流萍便越鄉。", "春水獨行人漸遠，故園歸夢夜空長。", "一聲隔浦猨啼處，數滴驚心淚滿裳。", "不爲知音皆鮑叔，信誰江上去茫茫。"]'),
('898882b9-127f-4f74-9b98-f5258036076e','劒客','慕幽','唐','唐诗','tang','','[]','去住知何處，空將一劒行。',48,'全唐诗/poet.tang.47000.json','["去住知何處，空將一劒行。", "殺人雖取次，爲事愛公平。", "戟立嗔髭鬢，星流忿眼睛。", "曉來湘市說，拂曙別遼城。"]'),
('eb994ba4-7e85-41f6-886f-95cb38771e7d','酬和友人見寄','慕幽','唐','唐诗','tang','','[]','勞歌好自看，終久偶齊桓。',48,'全唐诗/poet.tang.47000.json','["勞歌好自看，終久偶齊桓。", "五字若教易，一名爭得難。", "侵窓紅樹老，蔭砌雪花殘。", "莫効齊僚屬，東歸翦釣竿。"]'),
('495e2566-51a4-4aa0-ae50-8868e1942ddd','冬日淮上別文上人','慕幽','唐','唐诗','tang','','[]','家國各萬里，同吟六七年。',48,'全唐诗/poet.tang.47000.json','["家國各萬里，同吟六七年。", "可堪隨北雁，迢遰向南天。", "水共行人遠，山將落日連。", "春淮有雙鯉，莫忘尺書傳。"]'),
('1379e014-4fd6-49dc-b247-f0da2f901ee2','柳','慕幽','唐','唐诗','tang','','[]','今古憑君一贈行，幾回折盡復重生。',64,'全唐诗/poet.tang.47000.json','["今古憑君一贈行，幾回折盡復重生。", "五株斜傍淵明宅，千樹低垂太尉營。", "臨水帶煙藏翡翠，倚風兼雨宿流鶯。", "隋皇隄畔依依在，曾惹當時歌吹聲。"]'),
('27869dc6-5d63-42a1-879c-8f59d7cb8d13','三峽聞猨','慕幽','唐','唐诗','tang','','[]','誰向茲來不恨生，聲聲都是斷腸聲。',64,'全唐诗/poet.tang.47000.json','["誰向茲來不恨生，聲聲都是斷腸聲。", "七千里外一家住，十二峰前獨自行。", "瘴雨晚藏神女廟，蠻煙寒鎖夜郎城。", "憑君且聽哀吟好，會待青雲道路平。"]'),
('8a5c8257-7977-4e22-b1ae-0f9eeba6c10e','燈','慕幽','唐','唐诗','tang','','[]','鐘斷危樓鳥不飛，熒熒何處最相宜。',64,'全唐诗/poet.tang.47000.json','["鐘斷危樓鳥不飛，熒熒何處最相宜。", "香然水寺僧開卷，筆寫春幃客著詩。", "忽爾思多穿壁處，偶然心盡斷纓時。", "孫康勤苦誰能念，少減餘光借與伊。"]'),
('2976c300-2c2e-4853-8603-bfe0feba7b6e','寶琴','釋彪','唐','唐诗','tang','','[]','吾有一寶琴，價重雙南金。',48,'全唐诗/poet.tang.47000.json','["吾有一寶琴，價重雙南金。", "刻作龍鳳象，彈爲山水音。", "星從徽裏發，風來弦上吟。", "鍾期不可遇，誰辨曲中心。"]'),
('848877f9-a8d2-43eb-890d-ba7cbad2426a','觀大駕出敘事寄懷','法輪','唐','唐诗','tang','','[]','紫臺宵漏竭，青門曙鼓通。',120,'全唐诗/poet.tang.47000.json','["紫臺宵漏竭，青門曙鼓通。", "輕霞照複道，徐吹轉相風。", "玉鸞光萬騎，金輿鬱五戎。", "鳴笳猶度闕，清蹕尚喧宮。", "雲旗亂陌紫，羽斾雜塵紅。", "百城歸北麗，兩漢久慚雄。", "吾曹陋薄技，餘慶洽微躬。", "平原已起洛，印手亦還豐。", "得奉衣冠盛，仍觀書軌同。", "猶言待封告，未忍向華嵩。"]'),
('102a90fd-ea23-4952-841e-ea1790ad20da','中秋旅懷','尚能','唐','唐诗','tang','','[]','所畜惟騷雅，兼之得固窮。',48,'全唐诗/poet.tang.47000.json','["所畜惟騷雅，兼之得固窮。", "望鄉連北斗，聽雨帶西風。", "稼穡村坊遠，煙波路逕通。", "冥搜清絕句，恰似有神功。"]'),
('7381d894-f04d-4e34-b9e1-ca73a9464ebd','句','尚能','唐','唐诗','tang','','[]','霜洲楓落盡，月館竹生寒。',12,'全唐诗/poet.tang.47000.json','["霜洲楓落盡，月館竹生寒。"]'),
('63b0385a-7165-484b-afcc-d827c4cd4223','題伍相廟','常雅','唐','唐诗','tang','','[]','蒼蒼古廟映林巒，漠漠煙霞覆古壇。',32,'全唐诗/poet.tang.47000.json','["蒼蒼古廟映林巒，漠漠煙霞覆古壇。", "精魄不知何處在，威風猶入浙江寒。"]'),
('1c650469-d210-4636-95ee-35d61db64c52','懷舊山','滄浩','唐','唐诗','tang','','[]','一坐西林寺，從來未下山。',48,'全唐诗/poet.tang.47000.json','["一坐西林寺，從來未下山。", "不因尋長者，無事到人間。", "宿雨愁爲客，寒花笑未還。", "空懷舊山月，童子誦經閑。"]'),
('2798a0f7-37cc-4f0a-ab07-142f30060b4c','題慧山泉','若水','唐','唐诗','tang','','[]','石脈綻寒光，松根噴曉涼。',48,'全唐诗/poet.tang.47000.json','["石脈綻寒光，松根噴曉涼。", "注缾雲母滑，漱齒茯苓香。", "野客偷煎茗，山僧借淨牀。", "安禪何所問，孤月在中央。"]'),
('97c62642-6862-4ebd-b939-1b2073f2f24b','題馬跡山','文鑒','唐','唐诗','tang','','[]','瀛洲西望沃洲山，山在平湖縹緲間。',32,'全唐诗/poet.tang.47000.json','["瀛洲西望沃洲山，山在平湖縹緲間。", "常說使君千里馬，至今龍跡尚堪攀。"]'),
('8edb1c49-bcac-4f90-9b45-9aa8a9913ade','和御製遊慈恩寺','慈恩寺沙門','唐','唐诗','tang','','[]','皇風扇祇樹，至德茂禪林。',48,'全唐诗/poet.tang.47000.json','["皇風扇祇樹，至德茂禪林。", "仙華曜日彩，神旛曳遠陰。", "綺殿籠霞影，飛閣出雲心。", "細草希慈澤，恩光重更深。"]'),
('d7b84a93-68f2-4417-9393-a8f9a829196e','贈賈松先輩','水心寺僧','唐','唐诗','tang','','[]','嵯峨山上石，歲歲色長新。',24,'全唐诗/poet.tang.47000.json','["嵯峨山上石，歲歲色長新。", "若使盡成寶，誰爲知己人。"]'),
('462a9b2c-c4cf-422f-838f-9f3565a84b35','古梅','無名釋','唐','唐诗','tang','','[]','火虐風饕水漬根，霜皴雪皺古苔痕。',32,'全唐诗/poet.tang.47000.json','["火虐風饕水漬根，霜皴雪皺古苔痕。", "東風未肯隨寒暑，又蘖清香與返魂。"]'),
('568c138d-8242-488f-bc93-400338a27dac','月','南唐失名僧','唐','唐诗','tang','','[]','徐徐東海出，漸漸上天衢。',24,'全唐诗/poet.tang.47000.json','["徐徐東海出，漸漸上天衢。", "此夜一輪滿，清光何處無。"]'),
('0b48cfab-7638-4dff-b054-f5feea86bb07','武肅王有旨石橋設齋會進士一詩共六首 一','吳越僧','唐','唐诗','tang','','[]','南有天台事可尊，孕靈含秀獨超羣。',64,'全唐诗/poet.tang.47000.json','["南有天台事可尊，孕靈含秀獨超羣。", "重重曲澗侵危石，步步層巖踏碎雲。", "金雀每從雲裏現，異香多向夜深聞。", "當知此界非凡界，一道幽奇各自分。"]'),
('026b6449-e74d-4bd0-a8f0-8b7a4ff7ffa0','武肅王有旨石橋設齋會進士一詩共六首 二','吳越僧','唐','唐诗','tang','','[]','仙源佛窟有天台，今古嘉名遍九垓。',64,'全唐诗/poet.tang.47000.json','["仙源佛窟有天台，今古嘉名遍九垓。", "石磴嵌空神匠出，瀑泉雄壯雨聲來。", "景強偏感高僧上，地勝能令遠思開。", "一等翹誠依此處，自然靈貺作梯媒。"]'),
('c4d9400d-14e7-463f-83b0-701ee6123fc2','武肅王有旨石橋設齋會進士一詩共六首 三','吳越僧','唐','唐诗','tang','','[]','智泉福海莫能逾，親自王恩運睿謨。',64,'全唐诗/poet.tang.47000.json','["智泉福海莫能逾，親自王恩運睿謨。", "感現盡冥心境界，資持全固道根株。", "石梁低翥紅鸚鵡，煙嶺高翔碧鷓鴣。", "勝妙重重惟禱祝，永資軍庶息災虞。"]'),
('cc8f7407-9df6-4071-8799-86081d66ed98','武肅王有旨石橋設齋會進士一詩共六首 四','吳越僧','唐','唐诗','tang','','[]','凌晨迎請倍精誠，親散鮮花異處清。',64,'全唐诗/poet.tang.47000.json','["凌晨迎請倍精誠，親散鮮花異處清。", "羅漢攀枝呈梵相，巖僧倚樹現真形。", "神幡雙出紅霞動，寶塔全開白氣生。", "都爲王心標意切，滿空盈月瑞分明。"]'),
('9474841a-b631-4692-83f7-58e4d9f6bac4','武肅王有旨石橋設齋會進士一詩共六首 五','吳越僧','唐','唐诗','tang','','[]','幡花寶蓋滿青川，祈禱迎來聖半千。',64,'全唐诗/poet.tang.47000.json','["幡花寶蓋滿青川，祈禱迎來聖半千。", "莫道勝緣無影響，須知嘉會有因緣。", "空中長似聞天樂，巖畔常疑有地仙。", "何必更尋兜率去，重重靈應事昭然。"]'),
('5becd9b9-3fd4-4485-a2e8-115ceaffbc99','武肅王有旨石橋設齋會進士一詩共六首 六','吳越僧','唐','唐诗','tang','','[]','登雲步嶺涉煙程，好景隨心次第生。',64,'全唐诗/poet.tang.47000.json','["登雲步嶺涉煙程，好景隨心次第生。", "聖者已符祥瑞事，地靈全副禱祈情。", "洞深重疊拖雲濕，灘淺潺湲漱水清。", "願滿事圓歸去路，便風相送片帆輕。"]'),
('006a07c2-01cc-4e9f-b94e-1857378337ec','題戶詩','唐末僧','唐','唐诗','tang','','[]','枕有思鄉淚，門無問疾人。',24,'全唐诗/poet.tang.47000.json','["枕有思鄉淚，門無問疾人。", "塵埋牀下履，風動架頭巾。"]'),
('f3c2f321-a0d3-48bd-a36c-02c4aba1de66','逸句','神迥','唐','唐诗','tang','','[]','鵶鳴東牖曙，草秀南湖春。',12,'全唐诗/poet.tang.47000.json','["鵶鳴東牖曙，草秀南湖春。"]'),
('d51049d5-bcca-44ef-a38f-01aec94313c1','逸句','可隆','唐','唐诗','tang','','[]','萬般思後行，一失廢前功。',12,'全唐诗/poet.tang.47000.json','["萬般思後行，一失廢前功。"]'),
('0f8c2662-3ed0-440f-a89d-5d6f02ea9abf','逸句','爾鳥','唐','唐诗','tang','','[]','鯨目光燒半海紅，鰲頭浪蹙掀天白。',16,'全唐诗/poet.tang.47000.json','["鯨目光燒半海紅，鰲頭浪蹙掀天白。"]'),
('1726123e-d3ac-4bee-8aab-03fdcb2d7a67','逸句','元礎','唐','唐诗','tang','','[]','寺隔殘潮去，採藥過泉聲。',24,'全唐诗/poet.tang.47000.json','["寺隔殘潮去，採藥過泉聲。", "林塘秋半宿，風雨夜深來。"]'),
('d15a7252-5797-40a8-8a93-20cd9a617f5d','逸句','悟清','唐','唐诗','tang','','[]','鳥歸花影動，魚沒浪痕圓。',12,'全唐诗/poet.tang.47000.json','["鳥歸花影動，魚沒浪痕圓。"]'),
('4c4cb6ad-13cd-4da7-91f2-7adc70de3f1f','逸句','契盈','唐','唐诗','tang','','[]','三千里外一條水，十二時中兩度潮。',16,'全唐诗/poet.tang.47000.json','["三千里外一條水，十二時中兩度潮。"]'),
('fd9858ca-7aaf-4f06-82f4-d10c7852f2ae','逸句','淡然','唐','唐诗','tang','','[]','到處自鑿井，不能飲常流。',12,'全唐诗/poet.tang.47000.json','["到處自鑿井，不能飲常流。"]'),
('aa0e89fd-8ab6-4ee4-8d61-8d423389866e','逸句','庭實','唐','唐诗','tang','','[]','吟中雙鬢白，笑裏一生貧。',12,'全唐诗/poet.tang.47000.json','["吟中雙鬢白，笑裏一生貧。"]'),
('a907660e-e1b4-4a04-b3f2-354cac81780a','逸句','知業','唐','唐诗','tang','','[]','接岸橋通何處路，倚欄人[是阿]誰家。',18,'全唐诗/poet.tang.47000.json','["接岸橋通何處路，倚欄人[是阿]誰家。"]'),
('10002fb5-b269-4bf5-b1fd-c1b624915b57','逸句','雲容','唐','唐诗','tang','','[]','木末上明星。',6,'全唐诗/poet.tang.47000.json','["木末上明星。"]'),
('f708e169-9b50-47c6-b58d-5e2b29da7fa1','逸句','玄幽','唐','唐诗','tang','','[]','三萬蓮經三十春，半生不蹋院門塵。',16,'全唐诗/poet.tang.47000.json','["三萬蓮經三十春，半生不蹋院門塵。"]'),
('bb0821f2-2099-4c6e-81f5-83820891699e','逸句','志定','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','惟有罇前今夜月，當時曾照墮樓人。',32,'全唐诗/poet.tang.47000.json','["惟有罇前今夜月，當時曾照墮樓人。", "梧桐葉老蟬聲死，一夜洞庭波上風。"]'),
('c883641c-c4d9-4ea5-9307-db987330fa0f','逸句','靈準','唐','唐诗','tang','','[]','晴看漢水廣，秋覺峴山高。',12,'全唐诗/poet.tang.47000.json','["晴看漢水廣，秋覺峴山高。"]'),
('c968e274-ab29-4fc0-ab16-d4b1acef77c6','逸句','荆州僧','唐','唐诗','tang','','[]','犬熟護鄰房。',6,'全唐诗/poet.tang.47000.json','["犬熟護鄰房。"]'),
('2f2c78e6-76b6-4ae9-8845-4518df36967d','荅宋之問','司馬承禎','唐','唐诗','tang','','[]','時既暮兮節欲春，山林寂兮懷幽人。',64,'全唐诗/poet.tang.47000.json','["時既暮兮節欲春，山林寂兮懷幽人。", "登奇峰兮望白雲，悵緬邈兮象欲紛。", "白雲悠悠去不返，寒風颼颼吹日晚。", "不見其人誰與言，歸坐彈琴思逾遠。"]'),
('afd8310a-2b65-40a3-88d0-adb26822917b','醉吟三首 一','張氳','唐','唐诗','tang','','[]','去歲無田種，今春乏酒材。',24,'全唐诗/poet.tang.47000.json','["去歲無田種，今春乏酒材。", "從他花鳥笑，佯醉臥樓臺。"]'),
('21c5f628-2276-4adb-8951-2f6283fb049e','醉吟三首 二','張氳','唐','唐诗','tang','','[]','下調無人睬，高心又被瞋。',24,'全唐诗/poet.tang.47000.json','["下調無人睬，高心又被瞋。", "不知時俗意，教我若爲人。"]'),
('2283af39-ff3f-474e-9d69-7521b0ac958a','醉吟三首 三','張氳','唐','唐诗','tang','','[]','入市非求利，過朝不爲名。',24,'全唐诗/poet.tang.47000.json','["入市非求利，過朝不爲名。", "有時隨俗物，相伴且營營。"]'),
('096601bd-576c-441c-a572-1b5b2ce14598','洗心','司馬退之','唐','唐诗','tang','','[]','不踐名利道，始覺塵土腥。',108,'全唐诗/poet.tang.47000.json','["不踐名利道，始覺塵土腥。", "不味稻粱食，始覺精神清。", "羅浮奔走外，日月無短明。", "山瘦松亦勁，鶴老飛更輕。", "逍遙此中客，翠髮皆長生。", "草木多古色，雞犬無新聲。", "君有出俗志，不貪英雄名。", "傲然脫冠帶，改換人間情。", "去矣丹霄路，向曉雲冥冥。"]'),
('926f4798-8d1b-4d11-bb9b-b981667832e5','夜醉臥街','裴翛然','唐','唐诗','tang','','[]','遮莫鼕鼕動，須傾滿滿杯。',24,'全唐诗/poet.tang.47000.json','["遮莫鼕鼕動，須傾滿滿杯。", "金吾如借問，但道玉山頹。"]'),
('aafc69a3-07c7-4347-8938-416bda2f482f','謁堯帝廟','軒轅彌明','唐','唐诗','tang','','[]','祖龍開國盡遐荒，廟建唐堯鎮此邦。',64,'全唐诗/poet.tang.47000.json','["祖龍開國盡遐荒，廟建唐堯鎮此邦。", "山卷白雲朝帝座，林疎紅日列仙幢。", "巍巍聖蹟陵松嶠，蕩蕩恩波洽桂江。", "瞻仰威靈共回首，紫霞深處鎖軒窗。"]'),
('57dfb63c-4a91-4227-ad7a-c5e7ddaf0008','山居 一','陳寡言','唐','唐诗','tang','','[]','照水冰如鑑，掃雪玉爲塵。',24,'全唐诗/poet.tang.47000.json','["照水冰如鑑，掃雪玉爲塵。", "何須問今古，便是上皇人。"]'),
('714c780c-f630-42be-88d1-ceb90bae92e7','山居 二','陳寡言','唐','唐诗','tang','','[]','醉臥茅堂不閉關，覺來開眼見青山。',32,'全唐诗/poet.tang.47000.json','["醉臥茅堂不閉關，覺來開眼見青山。", "松花落處宿猨在，麋鹿羣羣林際還。"]'),
('2fe8eced-e7e0-4621-aaa7-4ace58739200','臨化示弟子','陳寡言','唐','唐诗','tang','','[]','我本無形暫有形，偶來人世逐營營。',32,'全唐诗/poet.tang.47000.json','["我本無形暫有形，偶來人世逐營營。", "輪迴債負今還畢，搔首翛然歸上清。"]'),
('4988dee8-c0d1-46b4-953d-38384f7933d5','元白席上作','李昇','唐','唐诗','tang','','[]','生在儒家遇太平，懸纓垂帶布衣輕。',32,'全唐诗/poet.tang.47000.json','["生在儒家遇太平，懸纓垂帶布衣輕。", "誰能世路趨名利，臣事玉皇歸上清。"]'),
('4a5163e2-e99f-43c1-8e1f-88d550fabc87','一字至七字詩 書','范堯佐','唐','唐诗','tang','','["\u5e90\u5c71"]','書，憑鴈，寄魚。',68,'全唐诗/poet.tang.47000.json','["書，憑鴈，寄魚。", "出王屋，入匡廬。", "文生益智，道著清虛。", "葛洪一萬卷，惠子五車餘。", "銀鉤屈曲索靖，題橋司馬相如。", "別後莫暌千里信，數封緘送到閑居。"]'),
('000c1478-af14-4ddd-b0b6-6a60eb367e7f','言志獻浙東廉訪辭召','徐靈府','唐','唐诗','tang','','[]','野性歌三樂，皇恩出九重。',48,'全唐诗/poet.tang.47000.json','["野性歌三樂，皇恩出九重。", "那煩紫宸命，遠下白雲峰。", "多媿書傳鶴，深慚紙畫龍。", "將何佐明主，甘老在巖松。"]'),
('cf467a58-45e1-42b7-8bec-e6db8ed049b9','自詠二首 一','徐靈府','唐','唐诗','tang','','[]','寂寂凝神太極初，無心應物等空虛。',32,'全唐诗/poet.tang.47000.json','["寂寂凝神太極初，無心應物等空虛。", "性修自性非求得，欲識真人祗是渠。"]'),
('5ffa103a-c0a2-4cdc-a558-fc9eb861c60e','自詠二首 二','徐靈府','唐','唐诗','tang','','[]','學道全真在此生，何須待死更求生。',32,'全唐诗/poet.tang.47000.json','["學道全真在此生，何須待死更求生。", "今生不了無生理，縱復生知那處生。"]'),
('fb8797cf-0bf8-4914-99ac-fc31dfc6170a','留觀中詩二首 一','吳子來','唐','唐诗','tang','','[]','終日草堂間，清風常往還。',48,'全唐诗/poet.tang.47000.json','["終日草堂間，清風常往還。", "耳無塵事擾，心有翫雲閑。", "對酒惟思月，餐松不厭山。", "時時吟內景，自合駐童顏。"]'),
('8e783367-449b-4b65-8c47-dd2061bbca24','留觀中詩二首 二','吳子來','唐','唐诗','tang','','[]','此生此物當生涯，白石青松便是家。',32,'全唐诗/poet.tang.47000.json','["此生此物當生涯，白石青松便是家。", "對月臥雲如野鹿，時時買酒醉煙霞。"]'),
('15310db9-e651-401d-9ff0-c9fd6112c67f','遊仙二十四首 一','吳筠','唐','唐诗','tang','','[]','啓冊觀往載，搖懷考今情。',96,'全唐诗/poet.tang.47000.json','["啓冊觀往載，搖懷考今情。", "終古已寂寂，舉世何營營。", "悟彼衆仙妙，超然含至精。", "凝神契沖玄，化服凌太清。", "心同宇宙廣，體合雲霞輕。", "翔風吹羽蓋，慶霄拂霓旌。", "龍駕朝紫微，後天保令名。", "豈如寰中士，軒冕矜蹔榮。"]'),
('ed5e3c07-5cb6-4dd9-a326-66238e611261','遊仙二十四首 二','吳筠','唐','唐诗','tang','','[]','鸞鳳棲瑤林，鵰鶚集平楚。',60,'全唐诗/poet.tang.47000.json','["鸞鳳棲瑤林，鵰鶚集平楚。", "飲啄本殊好，翺翔終異所。", "吾方遺諠囂，立節慕高舉。", "解茲區中戀，結彼霄外侶。", "誰謂天路遐，感通自無阻。"]'),
('dfd38f3b-0634-483c-b5a8-37b3ffbadede','遊仙二十四首 三','吳筠','唐','唐诗','tang','','[]','愍俗從遷謝，尋仙去淪沒。',72,'全唐诗/poet.tang.47000.json','["愍俗從遷謝，尋仙去淪沒。", "三元有真人，與我生道骨。", "凌晨吸丹景，入夜飲黃月。", "百關彌調暢，方寸益清越。", "棲神合虛無，洞覽周恍惚。", "不覺隨玉皇，焚香詣金闕。"]'),
('c643f801-9491-407a-b2e1-00445bcab550','遊仙二十四首 四','吳筠','唐','唐诗','tang','','[]','西龜初定籙，東華已校名。',60,'全唐诗/poet.tang.47000.json','["西龜初定籙，東華已校名。", "三官無遺譴，七祖升雲軿。", "體妙塵累隔，心微玄化幷。", "一朝出天地，億載猶童嬰。", "使我齊浩劫，蕭蕭宴玉清。"]'),
('2094ffd2-5887-46e2-8e66-e6625cbf927b','遊仙二十四首 五','吳筠','唐','唐诗','tang','','[]','怡神在靈府，皎皎含清澄。',60,'全唐诗/poet.tang.47000.json','["怡神在靈府，皎皎含清澄。", "仙經不吾欺，輕舉信有徵。", "疇昔希道念，而今果天矜。", "豈非陰功著，乃致白日升。", "焉用過洞府，吾其越朱陵。"]'),
('27666e82-2f90-4063-bbf5-8422f6b4bb08','遊仙二十四首 六','吳筠','唐','唐诗','tang','','[]','高真誠寥邈，道合不我遺。',60,'全唐诗/poet.tang.47000.json','["高真誠寥邈，道合不我遺。", "孰謂姑射遠，神人可同嬉。", "結駕從之遊，飄飄出天垂。", "不理人自化，神凝物無疵。", "因知至精感，足以和四時。"]'),
('b685f8e9-e58d-4540-8534-c92b0140c88c','遊仙二十四首 七','吳筠','唐','唐诗','tang','','[]','碧海廣無際，三山高不極。',60,'全唐诗/poet.tang.47000.json','["碧海廣無際，三山高不極。", "金臺羅中天，羽客恣遊息。", "霞液朝可飲，虹芝晚堪食。", "嘯歌自忘心，騰舉寧假翼。", "保壽同三光，安能紀千億。"]'),
('d957d9ea-039b-4085-9e5f-b29d3989ca04','遊仙二十四首 八','吳筠','唐','唐诗','tang','','[]','將過太帝宮，蹔詣扶桑處。',72,'全唐诗/poet.tang.47000.json','["將過太帝宮，蹔詣扶桑處。", "真童已相迓，爲我清宿霧。", "海若寧洪濤，羲和止奔馭。", "五雲結層閣，八景動飛輿。", "青霞正可挹，丹椹時一遇。", "留我宴玉堂，歸軒不令遽。"]'),
('9e583b03-22b0-4e73-8280-3bee5a1691aa','遊仙二十四首 九','吳筠','唐','唐诗','tang','','[]','欲超洞陽界，試鑒丹極表。',60,'全唐诗/poet.tang.47000.json','["欲超洞陽界，試鑒丹極表。", "赤帝躍火龍，炎官控朱鳥。", "導我升絳府，長軀出天杪。", "陽靈赫重暉，四達何皎皎。", "爲爾流飄風，羣生遂無夭。"]'),
('147447ae-84f4-4e35-93fc-be11baf0cc14','遊仙二十四首 十','吳筠','唐','唐诗','tang','','[]','予因詣金母，飛蓋超西極。',60,'全唐诗/poet.tang.47000.json','["予因詣金母，飛蓋超西極。", "遂入素中天，停輪太濛側。", "若華拂流影，不使白日匿。", "傾曦復亭午，六合無暝色。", "道化隨感遷，此理誰能測。"]'),
('daee03d9-8763-485c-a1bb-9b82b3852adc','遊仙二十四首 十一','吳筠','唐','唐诗','tang','','[]','九龍何蜿蜿，載我升雲綱。',60,'全唐诗/poet.tang.47000.json','["九龍何蜿蜿，載我升雲綱。", "臨睨懷舊國，風塵混蒼茫。", "依依遠人寰，去去邇帝鄉。", "上超星辰紀，下視日月光。", "倏已過太微，天居煥煌煌。"]'),
('6280b2e3-2db5-47c0-9e99-b4ba884cf186','遊仙二十四首 十二','吳筠','唐','唐诗','tang','','[]','停驂太儀側，整服金闕前。',60,'全唐诗/poet.tang.47000.json','["停驂太儀側，整服金闕前。", "肅肅承上帝，鏘鏘會羣仙。", "鴻鑪發靈香，廣廡張鈞天。", "玉醴洽中座，霞膏充四筵。", "良期無終極，俛仰移億年。"]'),
('e66b1f36-80f3-4644-8300-ada2bb3c6c21','遊仙二十四首 十三','吳筠','唐','唐诗','tang','','[]','峻朗妙門闢，澄微真鑒通。',48,'全唐诗/poet.tang.47000.json','["峻朗妙門闢，澄微真鑒通。", "瓊林九霞上，金閣三天中。", "飛虬躍慶雲，翔鶴摶靈風。", "鬱彼玉京會，仙期六合同。"]'),
('b79655c8-6a3a-49f5-8762-eac776699cfc','遊仙二十四首 十四','吳筠','唐','唐诗','tang','','[]','予昇至陽元，欲憩明霞館。',60,'全唐诗/poet.tang.47000.json','["予昇至陽元，欲憩明霞館。", "飄飄瓊輪舉，曄曄金景散。", "結虛成萬有，高妙咸可翫。", "玉山鬱嵯峨，琅海杳無岸。", "蹔賞過千椿，遐齡誰復算。"]'),
('b715f4a7-3866-4117-9f49-e86e3a772c15','遊仙二十四首 十五','吳筠','唐','唐诗','tang','','[]','招攜紫陽友，合宴玉清臺。',48,'全唐诗/poet.tang.47000.json','["招攜紫陽友，合宴玉清臺。", "排景羽衣振，浮空雲駕來。", "靈旛七曜動，瓊障九光開。", "鳳舞龍璈奏，虬軒殊未迴。"]'),
('2decc867-c816-440e-bb41-eab42e1da742','遊仙二十四首 十六','吳筠','唐','唐诗','tang','','[]','高升紫極上，宴此玄都岑。',60,'全唐诗/poet.tang.47000.json','["高升紫極上，宴此玄都岑。", "玉藻散奇香，瓊柯流雅音。", "靈風生太漠，習習吹人襟。", "體混希微廣，神凝空洞深。", "蕭然宇宙外，自得乾坤心。"]'),
('3b2f6a50-e1d9-485f-839b-ca4b08536037','遊仙二十四首 十七','吳筠','唐','唐诗','tang','','[]','晨登千仞嶺，俯瞰四人居。',72,'全唐诗/poet.tang.47000.json','["晨登千仞嶺，俯瞰四人居。", "原野間城邑，山河分里閭。", "眇彼埃塵中，爭奔聲利途。", "百齡寵辱盡，萬事皆爲虛。", "自昔無成功，安能與爾俱。", "將期駕雲景，超跡升天衢。"]'),
('213e900e-f90f-4242-b128-7dba7d8d5856','遊仙二十四首 十八','吳筠','唐','唐诗','tang','','[]','骨鍊體彌清，鑒明塵已絕。',60,'全唐诗/poet.tang.47000.json','["骨鍊體彌清，鑒明塵已絕。", "恬夷宇宙泰，煥朗天光徹。", "羽服參煙霄，童顏皎冰雪。", "隱符千魔駭，鳴玉萬帝悅。", "遂使區宇中，祅氣永淪滅。"]'),
('7cd8d142-d6e9-4b89-91d9-449db7c2fb9d','遊仙二十四首 十九','吳筠','唐','唐诗','tang','','[]','朝逾弱水北，夕憩鍾山頂。',72,'全唐诗/poet.tang.47000.json','["朝逾弱水北，夕憩鍾山頂。", "顓頊清玄宮，禺強掃幽境。", "燭龍發神曜，陰野彌煥炳。", "導達三氣和，驅除六天靜。", "玉樓互相暉，煙客何秀頴。", "一舉流霞津，千年在俄傾。"]'),
('421d2289-e00e-47df-9d7c-844bb2e9effb','遊仙二十四首 二十','吳筠','唐','唐诗','tang','','[]','揚蓋造辰極，乘煙遊閬風。',72,'全唐诗/poet.tang.47000.json','["揚蓋造辰極，乘煙遊閬風。", "上元降玉闥，王母開琳宮。", "天人何濟濟，高會碧堂中。", "列侍奏雲歌，真音滿太空。", "千年紫柰熟，四劫靈瓜豐。", "斯樂異荒讌，陶陶殊未終。"]'),
('6d3a3e06-bd9a-4c91-bf97-46cbe62b4062','遊仙二十四首 二十一','吳筠','唐','唐诗','tang','','[]','整駕辭五嶽，排煙凌九霄。',48,'全唐诗/poet.tang.47000.json','["整駕辭五嶽，排煙凌九霄。", "紛然太虛中，羽斾更相招。", "且盼蓬壺近，誰言崑閬遙。", "悠悠竟安適，仰赴三天朝。"]'),
('073a99d4-de47-4f98-b79a-70ed2cd01d09','遊仙二十四首 二十二','吳筠','唐','唐诗','tang','','[]','予招三清友，逈出九天上。',60,'全唐诗/poet.tang.47000.json','["予招三清友，逈出九天上。", "撓挑絕漠中，差池遙相望。", "大空含常明，八外無隱障。", "鸞鳳有逸翮，泠然恣飄颺。", "寥寥唯玄虛，至樂在神王。"]'),
('5850dcae-3d06-4cfd-9a5c-524185befa83','遊仙二十四首 二十三','吳筠','唐','唐诗','tang','','[]','縱身太霞上，眇眇虛中浮。',72,'全唐诗/poet.tang.47000.json','["縱身太霞上，眇眇虛中浮。", "八威先啓行，五老同我遊。", "靈景何灼灼，祥風正寥寥。", "嘯歌振長空，逸響清且柔。", "遨嬉無迹賞，顧眄皆真儔。", "不疾而自速，萬天俄已周。"]'),
('bf100d0d-452c-4da2-ac62-fd7bdf892509','遊仙二十四首 二十四','吳筠','唐','唐诗','tang','','[]','返視太初先，與道冥至一。',60,'全唐诗/poet.tang.47000.json','["返視太初先，與道冥至一。", "空洞凝真精，乃爲虛中實。", "變通有常性，合散無定質。", "不行迅飛電，隱曜光白日。", "玄棲忘玄深，無得固無失。"]'),
('8c772d71-c4ec-43f1-8275-d5b912caae7d','覽古十四首 一','吳筠','唐','唐诗','tang','','[]','聖人重周濟，明道欲救時。',120,'全唐诗/poet.tang.47000.json','["聖人重周濟，明道欲救時。", "孔席不暇暖，墨突何嘗緇。", "興言振頹綱，將以有所維。", "君臣恣淫惑，風俗日凋衰。", "三代業遽隕，七雄遂交馳。", "庶物墜塗炭，區中若棼絲。", "秦皇燎儒術，方冊靡孑遺。", "大漢歷五葉，斯文復崇推。", "乃驗經籍道，與世同屯夷。", "弛張固天意，設教安能持。"]'),
('9e35c5f3-7a34-4bfa-9e81-ab44b5bc3352','覽古十四首 二','吳筠','唐','唐诗','tang','','[]','興亡道之運，否泰理所全。',84,'全唐诗/poet.tang.47000.json','["興亡道之運，否泰理所全。", "奈何淳古風，既往不復旋。", "三皇已散朴，五帝初尚賢。", "王業與霸功，浮僞日以宣。", "忠誠及狙詐，殽混安可甄。", "餘智入九霄，守愚淪重泉。", "永懷巢居時，感涕徒泫然。"]'),
('c72cfcd3-37dc-45eb-b6b2-f30773bca753','覽古十四首 三','吳筠','唐','唐诗','tang','','[]','棟宇代巢穴，其來自三皇。',96,'全唐诗/poet.tang.47000.json','["棟宇代巢穴，其來自三皇。", "跡生固爲累，經始增百王。", "瑤臺既滅夏，瓊室復隕湯。", "覆車世不悟，秦氏興阿房。", "繼踵迷反正，漢家崇建章。", "力役弊萬人，瓌奇殫八方。", "徇志仍未極，促齡已云亡。", "侈靡竟何在，荆榛生廟堂。"]'),
('5a33718c-bb81-4e66-9a74-3e0b03ca7954','覽古十四首 四','吳筠','唐','唐诗','tang','','[]','閑居覽前載，惻彼商與秦。',60,'全唐诗/poet.tang.47000.json','["閑居覽前載，惻彼商與秦。", "所殘必忠良，所寶皆兇嚚。", "昵諛方自聖，不悟禍滅身。", "箕子作周輔，孫通爲漢臣。", "洪範及禮儀，後王用經綸。"]'),
('5fc05249-878f-4dc4-ab18-e570d6af233f','覽古十四首 五','吳筠','唐','唐诗','tang','','[]','吾觀采苓什，復感青蠅詩。',96,'全唐诗/poet.tang.47000.json','["吾觀采苓什，復感青蠅詩。", "讒佞亂忠孝，古今同所悲。", "姦邪起狡猾，骨肉相殘夷。", "漢儲殞江充，晉嗣滅驪姬。", "天性猶可間，君臣固其宜。", "子胥烹吳鼎，文種斷越鈹。", "屈原沈湘流，厥戚咸自貽。", "何不若范蠡，扁舟無還期。"]'),
('7c1e3717-8172-4eef-8b16-e88e92acb695','覽古十四首 六','吳筠','唐','唐诗','tang','','[]','嘗稽真仙道，清寂祛衆煩。',132,'全唐诗/poet.tang.47000.json','["嘗稽真仙道，清寂祛衆煩。", "秦皇及漢武，焉得遊其藩。", "情擾萬機屑，位驕四海尊。", "既欲先宇宙，仍規後乾坤。", "崇高與久遠，物莫能兩存。", "矧乃恣所慾，荒淫伐靈根。", "金膏恃延期，玉色復動魂。", "征戰窮外域，殺傷被中原。", "天鑒諒難誣，神理不可諼。", "安期返蓬萊，王母還崑崙。", "異術終莫告，悲哉竟何言。"]'),
('bb90ae08-1016-4ef8-8b74-277ca5e5bd29','覽古十四首 七','吳筠','唐','唐诗','tang','','[]','魯侯祈政術，尼父從棄捐。',72,'全唐诗/poet.tang.47000.json','["魯侯祈政術，尼父從棄捐。", "漢主思英才，賈生被排遷。", "始皇重韓子，及覩乃不全。", "武帝愛相如，既徵復忘賢。", "貴遠世咸爾，賤今理共然。", "方知古來主，難以効當年。"]'),
('2f5031a8-03c2-4db1-9873-baad3d385c0d','覽古十四首 八','吳筠','唐','唐诗','tang','','[]','食其昔未偶，落魄爲狂生。',60,'全唐诗/poet.tang.47000.json','["食其昔未偶，落魄爲狂生。", "一朝君臣契，雄辯何縱橫。", "運籌康漢業，憑軾下齊城。", "既以智所達，還爲智所烹。", "豈若終貧賤，酣歌本無營。"]'),
('559febf1-d86a-4a79-a229-fef97f893569','覽古十四首 九','吳筠','唐','唐诗','tang','','[]','晁錯抱遠策，爲君納良規。',72,'全唐诗/poet.tang.47000.json','["晁錯抱遠策，爲君納良規。", "削彼諸侯權，永用得所宜。", "姦臣負舊隙，乘釁謀相危。", "世主竟不辨，身戮宗且夷。", "漢景稱欽明，濫罰猶如斯。", "比干與龍逢，殘害何足悲。"]'),
('9a6a1564-9493-4099-97bd-095930cd512e','覽古十四首 十','吳筠','唐','唐诗','tang','','[]','絳侯成大績，賞厚位仍尊。',132,'全唐诗/poet.tang.47000.json','["絳侯成大績，賞厚位仍尊。", "一朝對獄吏，榮辱安可論。", "蘇生佩六印，奕奕爲殃源。", "主父食五鼎，昭昭成禍根。", "李斯佐二辟，巨釁鍾其門。", "霍孟翼三后，伊戚及後昆。", "天人忌盈滿，茲理固永存。", "方知得意者，何必乘朱輪。", "滅景栖遠壑，弦歌對清樽。", "二疏返海濱，蔣詡歸林園。", "蕭灑去物累，此謀誠足敦。"]'),
('6e335f46-51ea-4d63-ad64-c22ae3f27482','覽古十四首 十一','吳筠','唐','唐诗','tang','','[]','至人順通塞，委命固無疵。',72,'全唐诗/poet.tang.47000.json','["至人順通塞，委命固無疵。", "吾觀太史公，可謂識道規。", "留滯焉足憤，感懷殄生涯。", "吾歎龔夫子，秉義確不移。", "晦跡一何晚，天年夭當時。", "薰膏自銷鑠，楚老空餘悲。"]'),
('8bfb388c-b6d2-4ad2-b512-89a916d204d3','覽古十四首 十二','吳筠','唐','唐诗','tang','','[]','達者貴量力，至人尚知幾。',48,'全唐诗/poet.tang.47000.json','["達者貴量力，至人尚知幾。", "京房洞幽贊，神奧咸發揮。", "如何嫉元惡，不悟禍所歸。", "謀物闇謀己，誰言爾精微。"]'),
('b001c8f1-bc31-4ea1-9570-e04afed2f6d6','覽古十四首 十三','吳筠','唐','唐诗','tang','','[]','玄元明知止，大雅尚保躬。',84,'全唐诗/poet.tang.47000.json','["玄元明知止，大雅尚保躬。", "茂先洽聞者，幽賾咸該通。", "弱年賦鷦鷯，可謂達養蒙。", "晚節希鸞鵠，長飛戾曾穹。", "知進不知退，遂令其道窮。", "伊昔辨福初，胡爲迷禍終。", "方驗嘉遁客，永貞天壤同。"]'),
('84c4f194-1eac-46bc-8926-e9e8a17594ea','覽古十四首 十四','吳筠','唐','唐诗','tang','','[]','聖人垂大訓，奧義不苟設。',204,'全唐诗/poet.tang.47000.json','["聖人垂大訓，奧義不苟設。", "天道殃頑兇，神明祐懿哲。", "斯言猶影響，安得復迴穴。", "鯀瞍誕英睿，唐虞育昏孽。", "盜跖何延期，顏生乃短折。", "魯隱全克讓，禍機遂潛結。", "楚穆肆巨逆，福柄奚赫烈。", "田常弒其主，祚國久罔缺。", "管仲存霸功，世祖成詭說。", "漢氏方版蕩，羣閹恣邪譎。", "謇謇陳蕃徒，孜孜抗忠節。", "誓期區宇靜，爰使兇醜絕。", "謀協事靡從，俄而反誅滅。", "古來若茲類，紛擾難盡列。", "道遐理微茫，誰爲我昭晰。", "吾將詢上帝，寥廓詎躋徹。", "已矣勿用言，忘懷庶自悅。"]'),
('cd73612c-aa92-4796-91ec-ba034d26081f','步虛詞十首 一','吳筠','唐','唐诗','tang','','[]','衆仙仰靈範，肅駕朝神宗。',84,'全唐诗/poet.tang.47000.json','["衆仙仰靈範，肅駕朝神宗。", "金景相照曜，逶迤升太空。", "七玄已高飛，火鍊生珠宮。", "餘慶逮天壤，平和王道融。", "八威清遊氣，十絕舞祥風。", "使我躋陽源，其來自陰功。", "逍遙太霞上，真鑒靡不通。"]'),
('775c0ac7-9838-4add-aa2a-15b7b088c778','步虛詞十首 二','吳筠','唐','唐诗','tang','','[]','逸轡登紫清，乘光邁奔電。',72,'全唐诗/poet.tang.47000.json','["逸轡登紫清，乘光邁奔電。", "閬風隔三天，俯視猶可見。", "玉闥摽敞朗，瓊林鬱葱蒨。", "自非挺金骨，焉得諧夙願。", "真朋何森森，合景恣遊宴。", "良會忘淹留，千齡纔一眄。"]'),
('411bc735-9cb8-4840-b61a-feec24121f6d','步虛詞十首 三','吳筠','唐','唐诗','tang','','[]','三宮發明景，朗照同鬱儀。',72,'全唐诗/poet.tang.47000.json','["三宮發明景，朗照同鬱儀。", "紛然馳飆歘，上釆空清蕤。", "令我洞金色，後天耀瓊姿。", "心協太虛靜，寥寥竟何思。", "玄中有至樂，淡泊終無爲。", "但與正真友，飄颻散遨嬉。"]'),
('2b829150-d577-48a6-9093-75a51558ae14','步虛詞十首 四','吳筠','唐','唐诗','tang','','[]','稟化凝正氣，鍊形爲真仙。',84,'全唐诗/poet.tang.47000.json','["稟化凝正氣，鍊形爲真仙。", "忘心符元宗，返本協自然。", "帝一集絳宮，流光出丹玄。", "元英與桃君，朗詠長生篇。", "六府煥明霞，百關羅紫煙。", "飆車涉寥廓，靡靡乘景遷。", "不覺雲路遠，斯須遊萬天。"]'),
('baefb1bb-b0de-476b-85ab-c67bc5007d91','步虛詞十首 五','吳筠','唐','唐诗','tang','','[]','扶桑誕初景，羽蓋凌晨霞。',72,'全唐诗/poet.tang.47000.json','["扶桑誕初景，羽蓋凌晨霞。", "倏歘造西域，嬉遊金母家。", "碧津湛洪源，灼爍敷荷花。", "煌煌青琳宮，粲粲列玉華。", "真氣溢絳府，自然思無邪。", "俯矜區中士，夭濁良可嗟。"]'),
('6fc0c432-41e3-4d28-9ea6-c2b44100364a','步虛詞十首 六','吳筠','唐','唐诗','tang','','[]','瓊臺劫萬仞，孤映大羅表。',72,'全唐诗/poet.tang.47000.json','["瓊臺劫萬仞，孤映大羅表。", "常有三素雲，凝光自飛繞。", "羽幢泛明霞，升降何縹緲。", "鸞鳳吹雅音，栖翔絳林標。", "玉虛無晝夜，靈景何皎皎。", "一覩太上京，方知衆天小。"]'),
('053edf34-23b5-454f-9221-130fe6d50ac5','步虛詞十首 七','吳筠','唐','唐诗','tang','','[]','灼灼青華林，靈風振瓊柯。',60,'全唐诗/poet.tang.47000.json','["灼灼青華林，靈風振瓊柯。", "三光無冬春，一氣清且和。", "迴首邇結靈，傾眸親曜羅。", "豁落制六天，流鈴威百魔。", "緜緜慶不極，誰謂椿齡多。"]'),
('fb4b2d7b-1327-4300-8dd7-7857ae619dd4','步虛詞十首 八','吳筠','唐','唐诗','tang','','[]','高情無侈靡，遇物生華光。',60,'全唐诗/poet.tang.47000.json','["高情無侈靡，遇物生華光。", "至樂無簫歌，金玉音琅琅。", "或登明真臺，宴此羽景堂。", "杳靄結寶雲，霏微散靈香。", "天人誠遐曠，歡泰不可量。"]'),
('9a09d87a-ba13-4a0f-9ef2-396a987f222b','步虛詞十首 九','吳筠','唐','唐诗','tang','','[]','爰從太微上，肆覲虛皇尊。',72,'全唐诗/poet.tang.47000.json','["爰從太微上，肆覲虛皇尊。", "騰我八景輿，威遲入天門。", "既登玉宸庭，肅肅仰紫軒。", "敢問龍漢末，如何闢乾坤。", "怡然輟雲璈，告我希夷言。", "幸聞至精理，方見造化源。"]'),
('a97f541a-39b9-486b-b962-d6b05303c43f','步虛詞十首 十','吳筠','唐','唐诗','tang','','[]','二氣播萬有，化機無停輪。',72,'全唐诗/poet.tang.47000.json','["二氣播萬有，化機無停輪。", "而我操其端，乃能出陶鈞。", "寥寥大漠上，所遇皆清真。", "澄瑩含元和，氣同自相親。", "絳樹結丹實，紫霞流碧津。", "以茲保童嬰，永用超形神。"]'),
('865a0bf9-b994-4ce1-ba27-d1bbfc599c3a','登北固山望海','吳筠','唐','唐诗','tang','','[]','此山鎮京口，逈出滄海湄。',72,'全唐诗/poet.tang.47000.json','["此山鎮京口，逈出滄海湄。", "躋覽何所見，茫茫潮汐馳。", "雲生蓬萊島，日出扶桑枝。", "萬里混一色，焉能分兩儀。", "願言策煙駕，縹緲尋安期。", "揮手謝人境，吾將從此辭。"]'),
('2f16de20-4d22-47ea-8602-467351731f10','聽尹鍊師彈琴','吳筠','唐','唐诗','tang','','[]','至樂本太一，幽琴和乾坤。',84,'全唐诗/poet.tang.47000.json','["至樂本太一，幽琴和乾坤。", "鄭聲久亂雅，此道稀能尊。", "吾見尹仙翁，伯牙今復存。", "衆人乘其流，夫子達其源。", "在山峻峰峙，在水洪濤奔。", "都忘邇城闕，但覺清心魂。", "代乏識微者，幽音誰與論。"]'),
('0160b6eb-58f0-4b17-95ae-31ff6dce6265','題龔山人草堂','吳筠','唐','唐诗','tang','','[]','世人負一美，未肯甘陸沉。',96,'全唐诗/poet.tang.47000.json','["世人負一美，未肯甘陸沉。", "獨抱匡濟器，能懷真隱心。", "結廬邇城郭，及到雲木深。", "滅跡慕潁陽，忘機同漢陰。", "啓戶面白水，憑軒對蒼岑。", "但歌考槃詩，不學梁父吟。", "茲道我所適，感君齊素襟。", "勗哉龔夫子，勿使囂塵侵。"]'),
('c309e188-c4dc-4df1-8130-7d42c42f4c00','遊廬山五老峰','吳筠','唐','唐诗','tang','','["\u5e90\u5c71"]','彭蠡隱深翠，滄波照芙蓉。',120,'全唐诗/poet.tang.47000.json','["彭蠡隱深翠，滄波照芙蓉。", "日初金光滿，景落黛色濃。", "雲外聽猨鳥，煙中見杉松。", "自然符幽情，瀟灑愜所從。", "整策務探討，嬉遊任從容。", "玉膏正滴瀝，瑤草多䒠茸。", "羽人栖層崖，道合乃一逢。", "揮手欲輕舉，爲余扣瓊鐘。", "空香清人心，正氣信有宗。", "永用謝物累，吾將乘鸞龍。"]'),
('8b65e9b1-3c1c-47a2-a4a2-ccc418f1ae5d','登廬山東峰觀九江合彭蠡湖','吳筠','唐','唐诗','tang','','["\u5e90\u5c71"]','百川灌彭蠡，秋水方浩浩。',96,'全唐诗/poet.tang.47000.json','["百川灌彭蠡，秋水方浩浩。", "九派混東流，朝宗合天沼。", "寫心陟雲峰，縱目還縹緲。", "宛轉衆浦分，差池羣山繞。", "江妃弄明霞，彷彿呈窈窕。", "而我臨長風，飄然欲騰矯。", "昔懷滄洲興，斯志果已紹。", "焉得忘機人，相從洽魚鳥。"]'),
('995a5b70-d807-44c4-bf29-f98ede5fb7f8','建業懷古','吳筠','唐','唐诗','tang','','["\u957f\u6c5f"]','炎精既失御，宇內爲三分。',288,'全唐诗/poet.tang.47000.json','["炎精既失御，宇內爲三分。", "吳王霸荆越，建都長江濱。", "爰資股肱力，以靜淮海民。", "魏后欲濟師，臨流遽旋軍。", "豈惟限天塹，所忌在有人。", "惜哉歸命侯，淫虐敗前勳。", "銜璧入洛陽，委躬爲晉臣。", "無何覆宗社，爲爾含悲辛。", "俄及永嘉末，中原塞胡塵。", "五馬浮渡江，一龍躍天津。", "此時成大業，實賴賢縉紳。", "闢土雖未遠，規模亦振振。", "謝公佐王室，仗節掃僞秦。", "誰爲吳兵孱，用之在有倫。", "荏苒宋齊末，斯須變梁陳。", "綿歷已六代，興亡互紛綸。", "在德不在險，成敗良有因。", "高堞復于隍，廣殿摧于榛。", "王風久泯滅，勝氣猶氤氳。", "皇家一區域，玄化通無垠。", "常言宇宙泰，忽遘雲雷屯。", "極目梁宋郊，茫茫晦妖氛。", "安得倚天劒，斬茲橫海鱗。", "徘徊江山暮，感激爲誰申。"]'),
('5b47ac94-7d04-4104-b2dd-101e3ed99d2f','經羊角哀墓作','吳筠','唐','唐诗','tang','','[]','祇召出江國，路傍旌古墳。',96,'全唐诗/poet.tang.47000.json','["祇召出江國，路傍旌古墳。", "伯桃葬角哀，墓近荆將軍。", "神道不相得，稱兵解其紛。", "幽明信難知，勝負理莫分。", "長呼遂刎頸，此節古未聞。", "兩賢結情愛，骨肉何足云。", "感子初併糧，我心正氛氳。", "遲迴駐征騎，不覺空林醺。"]'),
('1422a3b8-f6db-44e5-a842-3a1c44359b59','過天門山懷友','吳筠','唐','唐诗','tang','','["\u5929\u95e8\u5c71"]','舉帆遇風勁，逸勢如飛奔。',84,'全唐诗/poet.tang.47000.json','["舉帆遇風勁，逸勢如飛奔。", "縹緲凌煙波，崩騰走川原。", "兩山夾滄江，豁爾開天門。", "須臾輕舟遠，想象孤嶼存。", "歸路日已近，怡然慰心魂。", "所經多奇趣，待與吾友論。", "一日如三秋，相思意彌敦。"]'),
('da7f5880-f3e4-4d14-94c3-9051c847cfae','舟中遇柳伯存歸潛山因有此贈 一','吳筠','唐','唐诗','tang','','[]','澆風久成俗，真隱不可求。',48,'全唐诗/poet.tang.47000.json','["澆風久成俗，真隱不可求。", "何悟非所冀，得君在扁舟。", "目擊道已存，一笑遂忘言。", "況觀絕交書，兼覩箴隱文。"]'),
('a24fe613-0c93-4256-b0b4-7d85ef1359e2','舟中遇柳伯存歸潛山因有此贈 二','吳筠','唐','唐诗','tang','','["\u5e90\u5c71"]','見君浩然心，視世如浮空。',48,'全唐诗/poet.tang.47000.json','["見君浩然心，視世如浮空。", "君歸潛山曲，我復廬山中。", "形間心不隔，誰能嗟異同。", "他日或相訪，無辭馭冷風。"]'),
('1113e339-6271-481a-9f5c-8514d36134e9','舟中夜行','吳筠','唐','唐诗','tang','','[]','榜人識江路，挂席從宵征。',60,'全唐诗/poet.tang.47000.json','["榜人識江路，挂席從宵征。", "莫辨洲渚狀，但聞風波驚。", "陰雲正飄颻，落月無光晶。", "豈不畏艱險，所憑在忠誠。", "何時達遙夜，佇見初日明。"]'),
('60c998ab-04ca-412c-98fc-f7e128be9340','晚到湖口見廬山作呈諸故人','吳筠','唐','唐诗','tang','','["\u5e90\u5c71"]','夜舟達湖口，漸近廬山側。',96,'全唐诗/poet.tang.47000.json','["夜舟達湖口，漸近廬山側。", "高高標橫天，隱隱何峻極。", "石鏡啓晨暉，罏煙凝寒色。", "旅泊將休暇，歸心已隮陟。", "虛名久爲累，使我辭逸域。", "良願道不違，幽襟果茲得。", "故人在雲嶠，乃復同晏息。", "鴻飛入青冥，虞氏罷繒弋。"]'),
('a5b74e99-e532-4bd3-b382-643ee57f9ea1','苦春霖作寄友','吳筠','唐','唐诗','tang','','[]','應龍遷南方，霪雨備江干。',120,'全唐诗/poet.tang.47000.json','["應龍遷南方，霪雨備江干。", "俯望失平陸，仰瞻隱崇巒。", "陰風斂暄氣，殘月淒已寒。", "時鳥戢好音，衆芳亦微殘。", "萬流注江湖，日夜增波瀾。", "數君曠不接，悄然無與歡。", "對酒聊自娛，援琴爲誰彈。", "彈爲愁霖引，曲罷仍永歎。", "此歎因感物，誰能識其端。", "寫懷寄同心，詞極意未殫。"]'),
('a28d04d1-9f9b-492e-8f1f-2d70542ffa27','酬葉縣劉明府避地廬山言懷詒鄭錄事昆季苟尊師兼見贈之','吳筠','唐','唐诗','tang','','["\u5e90\u5c71"]','明哲良罕遇，遇君輙思齊。',180,'全唐诗/poet.tang.47000.json','["明哲良罕遇，遇君輙思齊。", "挺生著天爵，自可析人珪。", "河洛初沸騰，方期掃虹霓。", "時命竟未合，安能親鼓鼙。", "從此罷飛鳧，投簪辭割雞。", "驅車適南土，忠孝兩不暌。", "廬嶽鎮江介，於焉愜林棲。", "入門披綵服，出谷杖紅藜。", "隱令舊閭里，而今復成躋。", "鄭公解簪紱，華萼曜松谿。", "賢哉苟徵君，滅跡爲圃畦。", "顧已成非薄，忝茲忘筌蹄。", "相觀對綠樽，逸思凌丹梯。", "道泰我長往，時清君勿迷。", "王孫且無歸，芳草正萋萋。"]'),
('1b3b94e4-5b5b-4577-8a4c-9b7278518111','高士詠 混元皇帝','吳筠','唐','唐诗','tang','','[]','玄元九仙主，道冠三氣初。',48,'全唐诗/poet.tang.47000.json','["玄元九仙主，道冠三氣初。", "應物方佐命，棲真亦歸居。", "貽篇訓終古，駕景還太虛。", "孔父歎猶龍，誰能知所如。"]'),
('815fbf8d-d9ee-4abe-846d-52d9ab730177','高士詠 廣成子','吳筠','唐','唐诗','tang','','[]','廣成臥雲岫，緬邈逾千齡。',48,'全唐诗/poet.tang.47000.json','["廣成臥雲岫，緬邈逾千齡。", "軒轅來順風，問道修神形。", "至言發玄理，告以從杳冥。", "三光入無窮，寂默返太寧。"]'),
('c5e9d3e1-d1da-417f-a62c-d2157b443aa9','高士詠 許先生','吳筠','唐','唐诗','tang','','[]','大名賢所尚，寶位聖所珍。',48,'全唐诗/poet.tang.47000.json','["大名賢所尚，寶位聖所珍。", "皎皎許仲武，遺之若纖塵。", "棄瓢箕山下，洗耳潁水濱。", "物外兩寂寞，獨與玄冥均。"]'),
('2f47f79b-5c79-4b1b-8780-58600f08053a','高士詠 樊先生','吳筠','唐','唐诗','tang','','[]','巢父志何遠，潛精人莫知。',48,'全唐诗/poet.tang.47000.json','["巢父志何遠，潛精人莫知。", "耻聞讓王事，飲犢方見移。", "不欲散大朴，焉能爲堯師。", "鍊真自輕舉，浮世何足遺。"]'),
('618d7c33-d856-4465-a8bf-f0adf1df3564','高士詠 柏成子高','吳筠','唐','唐诗','tang','','[]','大禹受禪讓，子高辭諸侯。',48,'全唐诗/poet.tang.47000.json','["大禹受禪讓，子高辭諸侯。", "退躬適外野，放浪夫何求。", "萬乘造中畝，一言良見酬。", "俋俋耕不顧，斯情邈難儔。"]'),
('361e8e0c-082b-4461-aad2-a0c0eabfae58','高士詠 臧丈人','吳筠','唐','唐诗','tang','','[]','臧叟隱中壑，垂綸心浩然。',48,'全唐诗/poet.tang.47000.json','["臧叟隱中壑，垂綸心浩然。", "文王感昔夢，授政道斯全。", "一遵無爲術，三載淳化宣。", "功成遂不處，遁跡符沖玄。"]'),
('b29759b6-ffce-4b78-b057-faf25480945e','高士詠 伯夷叔齊','吳筠','唐','唐诗','tang','','[]','夷齊互崇讓，棄國從所欽。',48,'全唐诗/poet.tang.47000.json','["夷齊互崇讓，棄國從所欽。", "聿來及宗周，乃復非其心。", "世濁不可處，冰清首陽岑。", "采薇詠羲農，高義越古今。"]'),
('61a05218-fbf2-4dba-b102-8152e85b0956','高士詠 南華真人','吳筠','唐','唐诗','tang','','[]','南華源道宗，玄遠故不測。',48,'全唐诗/poet.tang.47000.json','["南華源道宗，玄遠故不測。", "動與造化遊，靜合太和息。", "放曠生死外，逍遙神明域。", "況乃資九丹，輕舉歸太極。"]'),
('9e62b92d-ee8c-4064-9bfc-be55479eca2a','高士詠 沖虛真人','吳筠','唐','唐诗','tang','','[]','沖虛冥至理，體道自玄通。',48,'全唐诗/poet.tang.47000.json','["沖虛冥至理，體道自玄通。", "不受子陽祿，但飲壺丘宗。", "泠然竟何依，撓挑遊大空。", "未知風乘我，爲是我乘風。"]'),
('12a9ba2c-0a7d-4375-9e5d-af110f6bd598','高士詠 洞靈真人','吳筠','唐','唐诗','tang','','[]','亢倉致虛極，潛跡依遠岫。',48,'全唐诗/poet.tang.47000.json','["亢倉致虛極，潛跡依遠岫。", "智去愚獨留，日虧歲方就。", "鄉人謀尸祝，不欲聞俎豆。", "尚賢非至理，堯舜固爲陋。"]'),
('b7f35660-4b6f-4c40-8117-6a13571a55cd','高士詠 通玄真人','吳筠','唐','唐诗','tang','','[]','通玄貴陰德，利物非市朝。',48,'全唐诗/poet.tang.47000.json','["通玄貴陰德，利物非市朝。", "悠然大江上，散髮揮輕橈。", "已陳緇帷說，復表滄浪謠。", "滅跡竟何往，遺文獨昭昭。"]'),
('297ebe1c-f57b-4280-83cf-6e501c319505','高士詠 文始真人','吳筠','唐','唐诗','tang','','[]','文始通道源，含光隱關吏。',48,'全唐诗/poet.tang.47000.json','["文始通道源，含光隱關吏。", "遙欣紫氣浮，果驗真人至。", "玄誥已云錫，世榮何足累。", "高步三清境，超登九仙位。"]'),
('5af0bf48-264c-4397-9c1c-5ef4ff2279da','高士詠 榮啓期','吳筠','唐','唐诗','tang','','[]','榮期信知止，帶索無所求。',48,'全唐诗/poet.tang.47000.json','["榮期信知止，帶索無所求。", "外物非我尚，琴歌自優游。", "三樂通至道，一言醉孔丘。", "居常以待終，嘯傲夫何憂。"]'),
('ce4385f4-a8fd-4e6a-a091-c86e07b65bb9','高士詠 長沮桀溺','吳筠','唐','唐诗','tang','','[]','賢哉彼沮溺，避世全其真。',48,'全唐诗/poet.tang.47000.json','["賢哉彼沮溺，避世全其真。", "孔父棲棲者，征途方問津。", "行藏既異跡，語默豈同倫。", "耦耕長林下，甘與鳥雀羣。"]'),
('7610ff06-b818-481b-9b9e-57071093312e','高士詠 顏闔','吳筠','唐','唐诗','tang','','[]','世情矜寵譽，傚節徼當時。',48,'全唐诗/poet.tang.47000.json','["世情矜寵譽，傚節徼當時。", "顏闔遵無名，飯牛聊自怡。", "逃聘鄙束帛，鑿坏欣茅茨。", "託聘囂塵表，放浪世莫知。"]'),
('2008d984-4395-4f91-b88c-45b305a482bd','高士詠 老萊夫妻','吳筠','唐','唐诗','tang','','[]','萊氏道已遠，懿妻德彌清。',48,'全唐诗/poet.tang.47000.json','["萊氏道已遠，懿妻德彌清。", "一遁囂煩趣，永契雲壑情。", "祿位非所重，拂衣遂遐征。", "杳然從我願，豈爲物所攖。"]'),
('3974ab94-a6e0-43db-8838-ec48bea1fd80','高士詠 楚狂接輿夫妻','吳筠','唐','唐诗','tang','','[]','接輿耽沖玄，伉儷亦真逸。',48,'全唐诗/poet.tang.47000.json','["接輿耽沖玄，伉儷亦真逸。", "傲然辭徵聘，耕績代祿秩。", "鳳歌誡文宣，龍德遂隱密。", "一遊峨嵋上，千載保靈術。"]'),
('f9cad435-e097-45ce-a8f2-19bb273fc97e','高士詠 鄭商人弦高','吳筠','唐','唐诗','tang','','[]','卓哉弦高子，商隱獨摽奇。',48,'全唐诗/poet.tang.47000.json','["卓哉弦高子，商隱獨摽奇。", "傚謀全鄭國，矯命犒秦師。", "賞神義不受，存公滅其私。", "虛心貴無名，遠跡居九夷。"]'),
('83795a0e-0f13-4c85-a682-464b6d461fad','高士詠 柳下惠','吳筠','唐','唐诗','tang','','[]','展禽抱純粹，滅跡和光塵。',48,'全唐诗/poet.tang.47000.json','["展禽抱純粹，滅跡和光塵。", "高情遺軒冕，降志救世人。", "百行既無點，三黜道彌真。", "信謂德超古，豈惟言中倫。"]'),
('101f606f-e0a3-4d91-9851-bf63c20bd824','高士詠 荷蓧晨門','吳筠','唐','唐诗','tang','','[]','荷蓧隱耕藝，晨門潛抱關。',48,'全唐诗/poet.tang.47000.json','["荷蓧隱耕藝，晨門潛抱關。", "道尊名可賤，理愜心彌閑。", "混跡是非域，縱懷天地間。", "同譏孔宣父，匿景杳不還。"]'),
('97eb79e4-088d-456c-9c53-f0356a3f6621','高士詠 漢陰丈人','吳筠','唐','唐诗','tang','','[]','野哉漢陰叟，好古遂忘機。',48,'全唐诗/poet.tang.47000.json','["野哉漢陰叟，好古遂忘機。", "抱甕誠亦勤，守朴全道微。", "子貢初不達，聽言識其非。", "已爲風波人，怳惘失所依。"]'),
('d059add4-8828-4772-a5e6-a160c09e0448','高士詠 於陵夫妻','吳筠','唐','唐诗','tang','','[]','皎皎於陵子，己賢妻亦明。',48,'全唐诗/poet.tang.47000.json','["皎皎於陵子，己賢妻亦明。", "安茲道德重，顧彼浮華輕。", "琴書不爲務，祿位不可榮。", "逃跡終灌園，誰能達世情。"]'),
('5897e695-5ebe-4ae9-b493-380210088784','高士詠 項槖','吳筠','唐','唐诗','tang','','[]','太項冥虛極，微遠不可究。',48,'全唐诗/poet.tang.47000.json','["太項冥虛極，微遠不可究。", "稟量合太初，返形寄童幼。", "孔父慙至理，顏生賴真授。", "泛然同萬流，無跡世莫覯。"]'),
('88329648-6912-4775-846d-75dbc2e18ec8','高士詠 太伯延陵','吳筠','唐','唐诗','tang','','[]','太伯全至讓，遠投蠻夷間。',48,'全唐诗/poet.tang.47000.json','["太伯全至讓，遠投蠻夷間。", "延陵嗣高風，去國不復還。", "尊榮比蟬翼，道義侔崇山。", "元規與峻節，歷世無能攀。"]'),
('4e2d3dc8-3c7b-4de2-aa4a-3ed0d50f3eb4','高士詠 壺丘子','吳筠','唐','唐诗','tang','','[]','壺丘道爲量，玄虛固難知。',48,'全唐诗/poet.tang.47000.json','["壺丘道爲量，玄虛固難知。", "季咸曜淺術，禦寇初深疑。", "至人忘禍福，感變靡定期。", "太沖杳無朕，元化誰能知。"]'),
('d94cfe70-fe7c-4677-84c7-99a7f121fc7c','高士詠 段干木','吳筠','唐','唐诗','tang','','[]','干木布衣者，守道杜衡門。',48,'全唐诗/poet.tang.47000.json','["干木布衣者，守道杜衡門。", "德光義且富，肯易王侯尊。", "魏主欽其賢，軾廬情亦敦。", "秦兵遂不舉，高臥爲國藩。"]'),
('b72f5c9e-bcc2-434c-a760-92d3d1e7036c','高士詠 魯仲連','吳筠','唐','唐诗','tang','','[]','仲連秉奇節，釋難含道情。',48,'全唐诗/poet.tang.47000.json','["仲連秉奇節，釋難含道情。", "一言却秦圍，片札降聊城。", "辭金義何遠，讓祿心益清。", "處世功已立，拂衣蹈滄溟。"]'),
('4701377e-18fd-4c56-8859-76aa051cb716','高士詠 顏歜','吳筠','唐','唐诗','tang','','[]','高哉彼顏歜，逸氣陵齊宣。',48,'全唐诗/poet.tang.47000.json','["高哉彼顏歜，逸氣陵齊宣。", "道尊義不屈，士重王來前。", "榮祿安可誘，保和從自然。", "放情任所尚，長揖歸山泉。"]'),
('cc5e87bc-fc60-492b-b211-d27267be0eb2','高士詠 周豐','吳筠','唐','唐诗','tang','','[]','周豐貴隱耀，靜默尊無名。',48,'全唐诗/poet.tang.47000.json','["周豐貴隱耀，靜默尊無名。", "魯侯詢政體，喻以治道精。", "莅人在忠慤，疑叛由會盟。", "一言達至義，千載良爲程。"]'),
('b9fd06f9-04d9-4eec-b3f1-150997ac1f07','高士詠 師金','吳筠','唐','唐诗','tang','','[]','聖人貴素朴，禮義非玄同。',48,'全唐诗/poet.tang.47000.json','["聖人貴素朴，禮義非玄同。", "師金告顏生，可謂達化宗。", "夫子飾芻狗，自然道斯窮。", "應物方矯行，俯仰靡不通。"]'),
('3d5d5c5d-8485-4bc1-a27b-716d9f0e2d19','高士詠 南郭子綦','吳筠','唐','唐诗','tang','','[]','子綦方隱几，冥寂久灰心。',48,'全唐诗/poet.tang.47000.json','["子綦方隱几，冥寂久灰心。", "悟來應顏游，清義杳何深。", "含響盡天籟，有言同鷇音。", "是非不足辯，安用勞神襟。"]'),
('2fa77330-21b3-4ee6-910c-9b43b7cd7aa1','高士詠 黔婁先生','吳筠','唐','唐诗','tang','','[]','黔婁蘊雅操，守約遺代華。',48,'全唐诗/poet.tang.47000.json','["黔婁蘊雅操，守約遺代華。", "淡然常有怡，與物固無瑕。", "哲妻配明德，既沒辯正邪。", "辭祿乃餘貴，表謚良可嘉。"]'),
('a9302550-3c6c-4bc5-954e-d8aeb6bbe6e3','高士詠 原憲','吳筠','唐','唐诗','tang','','[]','原生何淡漠，觀妙自怡性。',48,'全唐诗/poet.tang.47000.json','["原生何淡漠，觀妙自怡性。", "蓬戶常晏如，弦歌樂天命。", "無財方是貧，有道固非病。", "木賜欽高風，退慙車馬盛。"]'),
('25a375e3-64d6-4bdd-8b7d-a6b9daad709d','高士詠 商山四皓','吳筠','唐','唐诗','tang','','[]','萬方厭秦德，戰伐何紛紛。',48,'全唐诗/poet.tang.47000.json','["萬方厭秦德，戰伐何紛紛。", "四皓同無爲，丘中臥白雲。", "自漢成帝業，一來翼儲君。", "知幾道可尚，隱括成元勳。"]'),
('ae3e7581-87eb-4ee5-9042-382ceb341ca2','高士詠 河上公','吳筠','唐','唐诗','tang','','[]','邈邈河上叟，無名契虛沖。',48,'全唐诗/poet.tang.47000.json','["邈邈河上叟，無名契虛沖。", "靈關暢玄旨，萬乘趨道風。", "寵辱不可累，飄然在雲空。", "獨與造化友，誰能測無窮。"]'),
('1199e635-03be-4fe4-9bfc-a241552cbf5c','高士詠 東方曼倩','吳筠','唐','唐诗','tang','','[]','東方稟易象，翫世隱廊廟。',48,'全唐诗/poet.tang.47000.json','["東方稟易象，翫世隱廊廟。", "棲心抱清微，混跡秘光耀。", "玄覽寄數術，納規在談笑。", "賣藥五湖中，還從九仙妙。"]'),
('41a73dbc-3957-4f99-bda4-94a6628d14d8','高士詠 嚴君平','吳筠','唐','唐诗','tang','','[]','漢皇舉遺逸，多士咸已寧。',48,'全唐诗/poet.tang.47000.json','["漢皇舉遺逸，多士咸已寧。", "至德不可拔，嚴君獨湛冥。", "卜筮訓流俗，指歸暢玄經。", "閉關動元象，何必遊紫庭。"]'),
('d6c65602-4f55-4cce-a31d-b9381e8ca603','高士詠 司馬季主','吳筠','唐','唐诗','tang','','[]','季主超常倫，沈跡寄卜筮。',48,'全唐诗/poet.tang.47000.json','["季主超常倫，沈跡寄卜筮。", "宋賈二大夫，停車試觀藝。", "高談哂朝列，洪辯不可際。", "終秉鸞鳳心，翛然已遐逝。"]'),
('00afd22a-dab6-4e8d-bae1-7af498965c73','高士詠 鄭子真張仲蔚','吳筠','唐','唐诗','tang','','[]','子真巖石下，仲蔚蓬蒿居。',48,'全唐诗/poet.tang.47000.json','["子真巖石下，仲蔚蓬蒿居。", "禮聘終不屈，清貧長晏如。", "心情在耕藝，養壽資玄虛。", "至樂非外物，道冥歡有餘。"]'),
('d25cf602-6344-43ed-a417-7cd56e69de4e','高士詠 嚴子陵','吳筠','唐','唐诗','tang','','[]','漢皇敦故友，物色訪嚴生。',48,'全唐诗/poet.tang.47000.json','["漢皇敦故友，物色訪嚴生。", "三聘迨深澤，一來遇帝庭。", "紫宸同御寢，玄象驗客星。", "祿位終不屈，雲山樂躬耕。"]'),
('452b7ad7-0a78-4a0a-aba7-67cf6056acf2','高士詠 向子平','吳筠','唐','唐诗','tang','','[]','子平好真隱，清淨翫老易。',48,'全唐诗/poet.tang.47000.json','["子平好真隱，清淨翫老易。", "探玄樂無爲，觀象驗損益。", "常抱方外心，且紆人間跡。", "一朝畢婚娶，五嶽遂長適。"]'),
('6f3c1351-ddef-4689-abb4-b08b46b54028','高士詠 韓康','吳筠','唐','唐诗','tang','','[]','伯休抱遐心，隱括自爲美。',48,'全唐诗/poet.tang.47000.json','["伯休抱遐心，隱括自爲美。", "賣藥不二價，有名反深耻。", "安能受玄纁，秉願終素履。", "逃遁從所尚，蕭蕭絕塵軌。"]'),
('9640bced-7420-4493-9fc6-4d3f2b52c419','高士詠 臺佟管寧','吳筠','唐','唐诗','tang','','[]','吾嘉臺孝威，樂道隱巖穴。',48,'全唐诗/poet.tang.47000.json','["吾嘉臺孝威，樂道隱巖穴。", "吾尚管幼安，棲真養高節。", "採藥聊自給，觀書任所悅。", "風塵不可混，真素比松雪。"]'),
('466f6f7f-be93-433f-88c6-9d8d224330e0','高士詠 高鳳','吳筠','唐','唐诗','tang','','[]','吾觀時人趣，矯跡務馳聲。',48,'全唐诗/poet.tang.47000.json','["吾觀時人趣，矯跡務馳聲。", "獨有高文通，訟田求翳名。", "公車徒見累，爵祿非所榮。", "隱身樂魚釣，世網不可攖。"]'),
('bf009b06-d79c-4f5e-96cc-0d619c29690d','高士詠 龐德公','吳筠','唐','唐诗','tang','','[]','龐公棲鹿門，絕跡遠城市。',48,'全唐诗/poet.tang.47000.json','["龐公棲鹿門，絕跡遠城市。", "超然風塵外，自得丘壑美。", "耕鑿勤厥躬，耘鋤課妻子。", "保茲永無患，軒冕何足紀。"]'),
('bae6886a-e9ed-4ddf-9879-fedf9d73d30b','高士詠 玄晏先生','吳筠','唐','唐诗','tang','','[]','士安逾弱冠，落魄未修餙。',48,'全唐诗/poet.tang.47000.json','["士安逾弱冠，落魄未修餙。", "一朝因感激，志學忘寢食。", "著書窮天人，辭聘守玄默。", "薄葬信昭儉，可爲將來則。"]'),
('57d584d5-bc12-4271-a66d-bc7a1abc28ac','高士詠 孫公和','吳筠','唐','唐诗','tang','','[]','孫登好淳古，卉服從穴居。',48,'全唐诗/poet.tang.47000.json','["孫登好淳古，卉服從穴居。", "彈琴合天和，讀易見象初。", "終日無慍色，恬然在玄虛。", "貽言誡叔夜，超跡安所如。"]'),
('1c28e3b7-93ca-46ce-8c4b-2945c5d2c80f','高士詠 董威輦','吳筠','唐','唐诗','tang','','[]','董京依白社，散髮詠玄風。',48,'全唐诗/poet.tang.47000.json','["董京依白社，散髮詠玄風。", "心出區宇外，跡參城市中。", "囂塵不能雜，名位安可籠。", "匿影留雅什，精微信難窮。"]'),
('37a8e77d-f591-4b65-8867-e89bbb7b8476','高士詠 郭文舉','吳筠','唐','唐诗','tang','','[]','郭生在童稚，已得方外心。',48,'全唐诗/poet.tang.47000.json','["郭生在童稚，已得方外心。", "絕跡遺世務，棲真入長林。", "元和感異類，猛獸懷德音。", "不憶固無情，斯言微且深。"]'),
('ecc618c5-28de-4bbc-b78d-779afdd6bdb6','高士詠 陶徵君','吳筠','唐','唐诗','tang','','[]','吾重陶淵明，達生知止足。',48,'全唐诗/poet.tang.47000.json','["吾重陶淵明，達生知止足。", "怡情在樽酒，此外無所欲。", "彭澤非我榮，折腰信爲辱。", "歸來北窗下，復採東籬菊。"]'),
('11269717-6d9f-438a-8fc9-3cfa25deff6a','元日言懷因以自勵詒諸同志','吳筠','唐','唐诗','tang','','[]','馳光無時憩，加我五十年。',84,'全唐诗/poet.tang.47000.json','["馳光無時憩，加我五十年。", "知非慕伯玉，讀易宗文宣。", "經世匪吾事，庶幾唯道全。", "誰言帝鄉遠，自古多真仙。", "餘滓永可滌，秉心方杳然。", "孰能無相與，滅跡俱忘筌。", "安用感時變，當期升九天。"]'),
('f0758c48-84be-455c-b4cc-48aef493230b','同劉主簿承介建昌江泛舟作','吳筠','唐','唐诗','tang','','[]','吾友從吏隱，和光心杳然。',120,'全唐诗/poet.tang.47000.json','["吾友從吏隱，和光心杳然。", "鳴琴正多暇，嘯侶浮清川。", "風霽遠澄映，昭昭涵洞天。", "坐驚衆峰轉，乃覺孤舟遷。", "崖嶼非一狀，差池過目前。", "徘徊白日暮，月色江中鮮。", "真興殊未已，滔滔且泝沿。", "時歌滄浪曲，或誦逍遙篇。", "酣暢迷夜久，遲遲方告旋。", "此時無相與，其旨在忘筌。"]'),
('2dfca031-5eec-47a5-ae45-6bc4a0836f52','緱山廟','吳筠','唐','唐诗','tang','','[]','朝吾自嵩山，驅駕遵洛汭。',132,'全唐诗/poet.tang.47000.json','["朝吾自嵩山，驅駕遵洛汭。", "逶遲轘轅側，仰望緱山際。", "王子謝時人，笙歌此賓帝。", "仙材夙所稟，寶位焉足繫。", "爲迫丹霄期，闕流蒼生惠。", "高蹤邈千載，遺廟今一詣。", "肅肅生風雲，森森列松桂。", "大君弘至道，層構何壯麗。", "稽首環金壇，焚香陟瑤砌。", "伊余超浮俗，塵慮久已閉。", "況復清夙心，蕭然叶真契。"]'),
('06a1bd22-29b6-405d-92f3-18712e537cdf','胡無人行','吳筠','唐','唐诗','tang','','[]','劍頭利如芒，恆持照眼光。',48,'全唐诗/poet.tang.47000.json','["劍頭利如芒，恆持照眼光。", "鐵騎追驍虜，金羈討黠羌。", "高秋八九月，胡地早風霜。", "男兒不惜死，破膽與君嘗。"]'),
('617d4c8a-3953-4439-95f7-5bdc911bf633','別章叟','吳筠','唐','唐诗','tang','','[]','平昔同邑里，經年不相思。',24,'全唐诗/poet.tang.47000.json','["平昔同邑里，經年不相思。", "今日成遠別，相對心悽其。"]'),
('8f91e478-2809-4ccd-8a17-aa2c17c9c6c1','題縉雲嶺永望館','吳筠','唐','唐诗','tang','','[]','人驚此路險，我愛山前深。',24,'全唐诗/poet.tang.47000.json','["人驚此路險，我愛山前深。", "猶恐佳趣盡，欲行且沈吟。"]'),
('d80eeb36-8f99-4daa-8e07-fc8000834112','題華山人所居','吳筠','唐','唐诗','tang','','[]','故人住南郭，邀我對芳樽。',24,'全唐诗/poet.tang.47000.json','["故人住南郭，邀我對芳樽。", "歡暢日云暮，不知城市喧。"]'),
('e75e5437-816a-472d-84e4-356229ef297b','初月','杜光庭','唐','唐诗','tang','','[]','始看東上又西浮，圓缺何曾得自由。',64,'全唐诗/poet.tang.47000.json','["始看東上又西浮，圓缺何曾得自由。", "照物不能長似鏡，當天多是曲如鈎。", "定無列宿敢爭耀，好伴晴河相映流。", "直使奔波急於箭，祗應白盡世間頭。"]'),
('4f73583e-1c2b-4fb8-b338-c9a31441e625','題仙居觀','杜光庭','唐','唐诗','tang','','[]','往歲真人朝玉皇，四真三代住繁陽。',64,'全唐诗/poet.tang.47000.json','["往歲真人朝玉皇，四真三代住繁陽。", "初開九鼎丹華熟，繼躡五雲天路長。", "烟鎖翠嵐迷舊隱，池凝寒鏡貯秋光。", "時從白鹿岩前往，應許潛通不死鄉。"]'),
('bc847a19-8828-4118-9386-66528717906a','題鴻都觀','杜光庭','唐','唐诗','tang','','[]','亡吳霸越已功全，深隱雲林始學仙。',64,'全唐诗/poet.tang.47000.json','["亡吳霸越已功全，深隱雲林始學仙。", "鸞鶴自飄三蜀駕，波濤猶憶五湖船。", "雙溪夜月明寒玉，衆嶺秋空歛翠烟。", "也有扁舟歸去興，故鄉東望思悠然。"]'),
('a73b4b62-4807-41ed-8d0a-aec08fb669fa','題都慶觀','杜光庭','唐','唐诗','tang','','[]','三仙一一駕紅鸞，仙去雲閑遶古壇。',64,'全唐诗/poet.tang.47000.json','["三仙一一駕紅鸞，仙去雲閑遶古壇。", "煉藥舊臺空處所，掛衣喬木兩摧殘。", "清風嶺接猿聲近，白石溪涵水影寒。", "二十四峯皆古隱，振纓長往亦何難。"]'),
('55f84248-7fa2-4cd3-a6a7-af5e13d76a69','贈將軍','杜光庭','唐','唐诗','tang','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.tang.47000.json','["□□□□□□□，□□□□□□□。", "八表順風驚雨露，四溟隨劒息波濤。", "手扶北極鴻圖永，雲卷長天聖日高。", "未會漢家青史上，韓彭何處有功勞。"]'),
('666be20b-a036-40ef-93aa-4ca280c13b9b','題鶴鳴山','杜光庭','唐','唐诗','tang','','[]','五氣雲龍下泰清，三天真客已功成。',64,'全唐诗/poet.tang.47000.json','["五氣雲龍下泰清，三天真客已功成。", "人間回首山川小，天上凌雲劒佩輕。", "花擁石壇何寂寞，草平轍跡自分明。", "鹿裘高士如相遇，不待岩前鶴有聲。"]'),
('bb838d44-9336-4290-94d5-65024eeb035d','題空明洞','杜光庭','唐','唐诗','tang','','[]','窅然靈岫五雲深，落翮標名振古今。',64,'全唐诗/poet.tang.47000.json','["窅然靈岫五雲深，落翮標名振古今。", "芝朮迎風香馥馥，松檉蔽日影森森。", "從師祗擬尋司馬，訪道終期謁奉林。", "欲問空明奇勝處，地藏方石恰如金。"]'),
('b31f3a9d-c131-4e76-be4d-44b50ba7e24f','題北平沼','杜光庭','唐','唐诗','tang','','[]','桐柏真人曾此居，焚香厓下誦靈書。',64,'全唐诗/poet.tang.47000.json','["桐柏真人曾此居，焚香厓下誦靈書。", "朝回時宴三山客，澗盡閑飛五色魚。", "天柱一峰凝碧玉，神燈千點散紅蕖。", "寶芝常在知誰得，好駕金蟾入太虛。"]'),
('e924b201-2702-4a6f-8a27-d82fc870b9e9','題平蓋沼','杜光庭','唐','唐诗','tang','','["\u957f\u6c5f"]','勢壓長江空八陣，吳都仙客此脩真。',64,'全唐诗/poet.tang.47000.json','["勢壓長江空八陣，吳都仙客此脩真。", "寒江向晚波濤急，深洞無風草木春。", "江上玉人應可見，洞中仙鹿已來馴。", "龍車鳳輦非難遇，只要塵心早出塵。"]'),
('dd48ff0b-d3cb-464b-9d3f-5451354d2563','題本竹觀','杜光庭','唐','唐诗','tang','','[]','樓閣層層冠此山，雕軒朱檻一躋攀。',64,'全唐诗/poet.tang.47000.json','["樓閣層層冠此山，雕軒朱檻一躋攀。", "碑刊古篆龍蛇動，洞接諸天日月閑。", "帝子影堂香漠漠，真人丹澗水潺潺。", "掃空雙竹今何在，只恐投波去不還。"]'),
('5b7c7be0-77e0-4d17-9cfb-1bb2322ae99d','題福唐觀二首 一','杜光庭','唐','唐诗','tang','','[]','盤空躡翠到山巔，竹殿雲樓勢逼天。',64,'全唐诗/poet.tang.47000.json','["盤空躡翠到山巔，竹殿雲樓勢逼天。", "古洞草深微有路，舊碑文滅不知年。", "八州物象通簷外，萬里烟霞在目前。", "自是人間輕舉地，何須蓬島訪真仙。"]'),
('c6c3712c-ea71-49ad-a7fd-fdbf076f0042','題福唐觀二首 二','杜光庭','唐','唐诗','tang','','[]','曾隨雲水此山遊，行盡層峯更上樓。',64,'全唐诗/poet.tang.47000.json','["曾隨雲水此山遊，行盡層峯更上樓。", "九月登臨須有意，七年岐路亦堪愁。", "樹紅樹碧高低影，烟淡烟濃遠近秋。", "暫熟爐香不須去，佇陪天仗入神州。"]'),
('e15ff0e5-b4b8-4223-b75b-6887a23d3c68','題莫公臺','杜光庭','唐','唐诗','tang','','[]','奇絕巍臺峙濁流，古來人號小瀛州。',64,'全唐诗/poet.tang.47000.json','["奇絕巍臺峙濁流，古來人號小瀛州。", "路通霄漢雲迷晚，洞隱魚龍月浸秋。", "舉手摘星河有浪，自天圖畫筆無鈎。", "將軍悟却希夷訣，贏得清名萬古流。"]'),
('fb5b4903-45a3-41ff-bd56-bb2e02cea39b','讀書臺','杜光庭','唐','唐诗','tang','','[]','山中猶有讀書臺，風掃晴嵐畫障開。',32,'全唐诗/poet.tang.47000.json','["山中猶有讀書臺，風掃晴嵐畫障開。", "華月冰壺依舊在，青蓮居士幾時來。"]'),
('bbe65fd6-bc84-4231-9d64-24245ed11c0a','贈人','杜光庭','唐','唐诗','tang','','[]','靜神凝思仰青冥，此夕長天降瑞星。',32,'全唐诗/poet.tang.47000.json','["靜神凝思仰青冥，此夕長天降瑞星。", "海上昨聞鵬羽翼，人間初見鶴儀形。"]'),
('03bb035b-1565-448a-811a-c13530e0d5d2','贈蜀州刺史','杜光庭','唐','唐诗','tang','','[]','再扶日月歸行殿，却領山河鎮夢刀。',32,'全唐诗/poet.tang.47000.json','["再扶日月歸行殿，却領山河鎮夢刀。", "從此雄名壓寰海，八溟爭敢起波濤。"]'),
('deeac160-0839-483a-b67c-266f5c2b75a0','題劒門','杜光庭','唐','唐诗','tang','','[]','誰運乾坤陶冶功，鑄爲雙劒倚蒼穹。',32,'全唐诗/poet.tang.47000.json','["誰運乾坤陶冶功，鑄爲雙劒倚蒼穹。", "題詩曾駐三天駕，礙日長含八海風。"]'),
('e61094a4-4e8c-45f1-8862-c6fec73a266a','題龍鵠山','杜光庭','唐','唐诗','tang','','[]','抽得閑身伴瘦筇，亂敲青碧喚蛟龍。',32,'全唐诗/poet.tang.47000.json','["抽得閑身伴瘦筇，亂敲青碧喚蛟龍。", "道人掃徑收松子，缺月初圓天柱峰。"]'),
('e898fe0d-8cf2-46ae-a21d-59816355e1b7','富貴曲','杜光庭','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5973\u5b50", "\u8bbd\u523a"]','美人梳洗時，滿頭間珠翠。',24,'全唐诗/poet.tang.47000.json','["美人梳洗時，滿頭間珠翠。", "豈知兩片雲，戴却數鄉稅。"]'),
('f24a9b64-eb29-4a3f-8dc1-de86415f6ea0','詠西施','杜光庭','唐','唐诗','tang','','[]','素面已云妖，更著花鈿飾。',24,'全唐诗/poet.tang.47000.json','["素面已云妖，更著花鈿飾。", "臉橫一寸波，浸破吳王國。"]'),
('6504b29e-b122-4ea8-8f7f-bd12b30f1bbb','傷時','杜光庭','唐','唐诗','tang','','[]','帆力劈開滄海浪，馬蹄踏破亂山青。',32,'全唐诗/poet.tang.47000.json','["帆力劈開滄海浪，馬蹄踏破亂山青。", "浮名浮利過於酒，醉得人心死不醒。"]'),
('92bc7ed1-45c0-49fc-947a-af5771ff4c0d','題霍山秦尊師','杜光庭','唐','唐诗','tang','','[]','老鶴玄猿伴採芝，有時長嘆獨移時。',32,'全唐诗/poet.tang.47000.json','["老鶴玄猿伴採芝，有時長嘆獨移時。", "翠娥紅粉嬋娟劒，殺盡世人人不知。"]');
